def _company_profile_autofill_values(step2: Optional[dict]) -> dict[str, str]:
    """基本情報で入力済みの値を、会社概要/沿革の初期値として使う。"""
    src = step2 if isinstance(step2, dict) else {}
    company_name = str(src.get("company_name") or "").strip()
    address = str(src.get("address") or "").strip()
    phone = str(src.get("phone") or "").strip()
    email = str(src.get("email") or "").strip()
    site_url = str(src.get("site_url") or src.get("website_url") or src.get("main_site_url") or "").strip()

    contact_parts: list[str] = []
    if phone:
        contact_parts.append(f"TEL {phone}")
    if email:
        contact_parts.append(f"Mail {email}")

    out: dict[str, str] = {}
    if company_name:
        out["trade_name"] = company_name
    if address:
        out["address"] = address
    if site_url:
        out["site_url"] = site_url
    if contact_parts:
        out["contact"] = " / ".join(contact_parts)
    return out


def _company_profile_effective_value(step2: Optional[dict], profile: Optional[dict], key: str) -> str:
    """表示に使う会社概要値。空やサンプル値なら基本情報の値を優先する。"""
    prof = profile if isinstance(profile, dict) else {}
    raw = str(prof.get(key) or "").strip()
    sample = str(COMPANY_PROFILE_SAMPLE_MAP.get(key) or "").strip()
    auto_val = str(_company_profile_autofill_values(step2).get(key) or "").strip()
    if raw and raw != sample:
        return raw
    if auto_val:
        return auto_val
    return "" if raw == sample else raw


def _company_profile_editor_value(step2: Optional[dict], profile: Optional[dict], key: str, sample: str) -> str:
    """編集欄に出す値。未入力欄は空欄のままにし、手入力値だけを返す。"""
    prof = profile if isinstance(profile, dict) else {}
    raw = str(prof.get(key) or "").strip()
    sample = str(sample or "").strip()
    if raw and raw != sample:
        return raw
    return ""


def _company_profile_cell_html(key: str, value: str) -> str:
    """会社概要/沿革セルの表示HTML。改行を保ちつつ、URL欄は安全にリンク化する。"""
    raw = str(value or "").strip()
    if not raw:
        return ""
    if key == "site_url":
        lines = [line.strip() for line in raw.splitlines() if line.strip()]
        href = lines[0] if lines else raw
        label_html = "<br>".join(html.escape(line) for line in lines) if lines else html.escape(raw)
        safe_href = html.escape(href, quote=True)
        return f'<a class="pv-inline-link" href="{safe_href}" target="_blank" rel="noreferrer noopener">{label_html}</a>'
    return html.escape(raw).replace(chr(10), "<br>")


def _normalize_company_profile_extra_rows(profile: Optional[dict]) -> list[dict]:
    prof = profile if isinstance(profile, dict) else {}
    rows_raw = prof.get("extra_rows")
    if not isinstance(rows_raw, list):
        rows_raw = []
    rows: list[dict] = []
    for item in rows_raw[:COMPANY_PROFILE_EXTRA_ROW_COUNT]:
        if isinstance(item, dict):
            rows.append({
                "label": str(item.get("label") or "").strip(),
                "value": str(item.get("value") or "").strip(),
            })
        else:
            rows.append({"label": "", "value": ""})
    while len(rows) < COMPANY_PROFILE_EXTRA_ROW_COUNT:
        rows.append({"label": "", "value": ""})
    return rows


def _company_profile_visible_extra_rows(profile: Optional[dict]) -> list[dict[str, str]]:
    rows = _normalize_company_profile_extra_rows(profile)
    visible: list[dict[str, str]] = []
    for row in rows:
        label = str(row.get("label") or "").strip()
        value = str(row.get("value") or "").strip()
        if not value:
            continue
        visible.append({
            "label": label or "補足",
            "value": value,
        })
    return visible

