def _normalize_recruitment_block(block: Optional[dict]) -> dict:
    rec = block if isinstance(block, dict) else {}
    rec.setdefault("enabled", False)
    rec.setdefault("title", "求人情報")
    rec.setdefault("lead", "現在、一緒に働く仲間を募集しています。ご興味のある方はお気軽にご連絡ください。")
    # 1.8.0: ヘッダー募集CTAは builder / preview / publish / pack で固定にする
    # 旧案件の保存値があっても、読み込み時に必ず標準ラベルへ正規化する
    rec["header_badge_text"] = RECRUITMENT_BADGE_DEFAULT
    rec.setdefault("image_url", "")
    rec.setdefault("image_upload_name", "")
    rec.setdefault("apply_url", "")
    rec.setdefault("indeed_url", "")
    rec.setdefault("valid_through", "")
    for _key, _label, _sample in RECRUITMENT_DETAIL_DEFS:
        rec.setdefault(_key, "")
    faq_items = rec.get("faq_items")
    normalized_faqs: list[dict[str, str]] = []
    if isinstance(faq_items, list):
        for item in faq_items:
            if isinstance(item, dict):
                normalized_faqs.append({
                    "q": str(item.get("q") or "").strip(),
                    "a": str(item.get("a") or "").strip(),
                })
    for idx in range(RECRUITMENT_FAQ_COUNT):
        q = str(rec.get(f"faq_{idx + 1}_q") or "").strip()
        a = str(rec.get(f"faq_{idx + 1}_a") or "").strip()
        if q or a:
            normalized_faqs.append({"q": q, "a": a})
    normalized_faqs = normalized_faqs[:RECRUITMENT_FAQ_COUNT]
    while len(normalized_faqs) < RECRUITMENT_FAQ_COUNT:
        normalized_faqs.append({"q": "", "a": ""})
    rec["faq_items"] = normalized_faqs
    return rec


def _recruitment_rows(block: Optional[dict]) -> list[tuple[str, str]]:
    rec = _normalize_recruitment_block(block)
    rows: list[tuple[str, str]] = []
    for key, label, _sample in RECRUITMENT_DETAIL_DEFS:
        value = str(rec.get(key) or "").strip()
        if value:
            rows.append((label, value))
    return rows


def _recruitment_has_content(block: Optional[dict]) -> bool:
    rec = _normalize_recruitment_block(block)
    if str(rec.get("lead") or "").strip():
        return True
    if str(rec.get("image_url") or "").strip():
        return True
    return bool(_recruitment_rows(rec))


def _recruitment_faq_pairs(block: Optional[dict]) -> list[tuple[str, str]]:
    rec = _normalize_recruitment_block(block)
    pairs: list[tuple[str, str]] = []
    for item in rec.get("faq_items") or []:
        if not isinstance(item, dict):
            continue
        q = str(item.get("q") or "").strip()
        a = str(item.get("a") or "").strip()
        if q and a:
            pairs.append((q, a))
    return pairs[:RECRUITMENT_FAQ_COUNT]


def _recruitment_is_visible(block: Optional[dict]) -> bool:
    rec = _normalize_recruitment_block(block)
    try:
        enabled = bool(rec.get("enabled", False))
    except Exception:
        enabled = False
    return enabled and _recruitment_has_content(rec)


def _recruitment_badge_text(block: Optional[dict]) -> str:
    _normalize_recruitment_block(block)
    return RECRUITMENT_BADGE_DEFAULT


