def pf2_is_placeholder_company_name(value: object, project_name: object = "") -> bool:
    name = pf2_text(value)
    project_label = pf2_text(project_name)
    if not name:
        return False
    generic_names = {"新しい求人", "新規求人", "名称未設定", "未設定"}
    return name in generic_names or (bool(project_label) and name == project_label and project_label in generic_names)


def pf2_clean_company_name(value: object, project_name: object = "", *, fallback: str = "") -> str:
    name = pf2_text(value)
    if pf2_is_placeholder_company_name(name, project_name):
        return pf2_text(fallback)
    return name or pf2_text(fallback)


def pf2_local_save_project(project: dict, *, active: bool = True) -> dict:
    p = normalize_project(project if isinstance(project, dict) else {})
    p = pf2_prune_ai_drafts(p)
    p["updated_at"] = now_jst_iso()
    store = pf2_local_load_store()
    projects = store.get("projects") if isinstance(store.get("projects"), dict) else {}
    projects[pf2_text(p.get("project_id"))] = p
    store["projects"] = projects
    if active:
        store["active_project_id"] = pf2_text(p.get("project_id"))
    pf2_local_save_store(store)
    return p


def pf2_local_create_project(project_name: str = "") -> dict:
    p = pf2_local_blank_project(project_name)
    return pf2_local_save_project(p, active=True)


def pf2_local_list_projects() -> list[dict]:
    store = pf2_local_load_store()
    projects = store.get("projects") if isinstance(store.get("projects"), dict) else {}
    items = [normalize_project(p) for p in projects.values() if isinstance(p, dict)]
    items.sort(key=lambda item: pf2_text(item.get("updated_at")), reverse=True)
    return items


def pf2_local_get_project(project_id: str = "") -> Optional[dict]:
    store = pf2_local_load_store()
    projects = store.get("projects") if isinstance(store.get("projects"), dict) else {}
    pid = pf2_text(project_id) or pf2_text(store.get("active_project_id"))
    if pid and isinstance(projects.get(pid), dict):
        return normalize_project(projects[pid])
    for item in projects.values():
        if isinstance(item, dict):
            return normalize_project(item)
    return None


def pf2_local_set_active_project(project_id: str) -> Optional[dict]:
    store = pf2_local_load_store()
    projects = store.get("projects") if isinstance(store.get("projects"), dict) else {}
    pid = pf2_text(project_id)
    if not pid or pid not in projects:
        return None
    store["active_project_id"] = pid
    pf2_local_save_store(store)
    return normalize_project(projects[pid])


def pf2_local_ensure_active_project() -> dict:
    project = pf2_local_get_project()
    if project:
        return project
    return pf2_local_create_project("新しい求人")


def pf2_safe_export_member_path(relative_path: str) -> Optional[Path]:
    raw = pf2_text(relative_path).replace("\\", "/").lstrip("/")
    if not raw or raw.startswith("../") or "/../" in raw or raw == "..":
        return None
    path = Path(raw)
    if path.is_absolute() or any(part in ("", ".", "..") for part in path.parts):
        return None
    return path


def pf2_local_export_project(project: dict, job_id: str = "") -> dict:
    p = normalize_project(project if isinstance(project, dict) else {})
    jid = pf2_text(job_id) or pf2_job_id_for_project(p)
    job = pf2_job_from_project(p, jid)
    job["public_check"] = pf2_public_check_job(job)
    blocks_ = job["public_check"].get("blocks") if isinstance(job["public_check"].get("blocks"), list) else []
    if blocks_:
        return {"ok": False, "message": "公開前チェックで確認が必要な項目があります", "blocks": blocks_}
    if not pf2_text(job.get("mobile_preview_checked_at")):
        return {"ok": False, "message": "スマホ表示確認が必要です", "blocks": [{"field": "mobile_preview_checked_at", "label": "スマホ表示確認"}]}
    if bool(job.get("ai_draft_used")) and not pf2_text(job.get("ai_draft_human_confirmed_at")):
        return {"ok": False, "message": "入力補助文の確認が必要です", "blocks": [{"field": "ai_draft_human_confirmed_at", "label": "入力補助文の確認"}]}
    if not pf2_text(job.get("last_public_check_at")):
        job["last_public_check_at"] = now_jst_iso()
        p = pf2_apply_job_to_project(p, job)
    settings = pf2_ensure_extension(p).get("settings")
    settings = settings if isinstance(settings, dict) else {}
    google_enabled = settings.get("google_jobposting_enabled", True) is not False
    indeed_enabled = settings.get("indeed_xml_enabled", True) is not False
    sitemap_robots_enabled = settings.get("sitemap_robots_enabled", True) is not False
    files = build_pageflowai2_site_files(p)
    if not google_enabled:
        files.pop(RECRUITMENT_JOBPOSTING_JSON_PATH, None)
    if not indeed_enabled:
        files.pop(RECRUITMENT_INDEED_FEED_PATH, None)
    if not sitemap_robots_enabled:
        files.pop(SITE_SITEMAP_PATH, None)
        files.pop(SITE_ROBOTS_PATH, None)
    if google_enabled:
        try:
            jobposting = json.loads(files.get(RECRUITMENT_JOBPOSTING_JSON_PATH, b"{}").decode("utf-8", errors="replace"))
        except Exception:
            jobposting = {}
    else:
        jobposting = ""
    indeed_xml = files.get(RECRUITMENT_INDEED_FEED_PATH, b"").decode("utf-8", errors="replace") if indeed_enabled else ""
    media_check = pf2_check_media_alignment(job, jobposting=jobposting, indeed_xml=indeed_xml)
    if media_check.get("blocks"):
        return {"ok": False, "message": "公開用ファイルと求人内容に差があります", "blocks": media_check.get("blocks", [])}

    timestamp = datetime.now(JST).strftime("%Y%m%d_%H%M%S")
    safe_pid = re.sub(r"[^a-zA-Z0-9_-]", "_", pf2_text(p.get("project_id")) or "project")
    export_root = pf2_local_export_dir() / safe_pid / timestamp
    site_root = export_root / "site"
    site_root.mkdir(parents=True, exist_ok=True)
    for rel, raw in files.items():
        member = pf2_safe_export_member_path(rel)
        if member is None:
            continue
        out_path = site_root / member
        out_path.parent.mkdir(parents=True, exist_ok=True)
        out_path.write_bytes(raw if isinstance(raw, bytes) else bytes(raw or b""))

    filename = f"PageFlowAI2_{safe_pid}_{timestamp}.zip"
    zip_path = export_root / filename
    buffer = BytesIO()
    with zipfile.ZipFile(buffer, "w", zipfile.ZIP_DEFLATED) as zf:
        for rel, raw in files.items():
            member = pf2_safe_export_member_path(rel)
            if member is None:
                continue
            zf.writestr(str(Path("site") / member).replace("\\", "/"), raw if isinstance(raw, bytes) else bytes(raw or b""))
    zip_bytes = buffer.getvalue()
    zip_path.write_bytes(zip_bytes)

    job["export_pack_generated_at"] = now_jst_iso()
    p = pf2_apply_job_to_project(p, job)
    p = pf2_append_public_check_run(p, jid, job["public_check"])
    artifact_files = {
        "job_lp_html": [RECRUITMENT_PAGE_PATH] if RECRUITMENT_PAGE_PATH in files else [],
        "google_jobposting_jsonld": [RECRUITMENT_JOBPOSTING_JSON_PATH] if RECRUITMENT_JOBPOSTING_JSON_PATH in files else [],
        "indeed_xml": [RECRUITMENT_INDEED_FEED_PATH] if RECRUITMENT_INDEED_FEED_PATH in files else [],
        "sitemap": [SITE_SITEMAP_PATH] if SITE_SITEMAP_PATH in files else [],
        "robots": [SITE_ROBOTS_PATH] if SITE_ROBOTS_PATH in files else [],
    }
    for artifact_type, names in artifact_files.items():
        if names:
            p = pf2_append_media_artifact(p, jid, artifact_type, file_names=names, metadata={"source": "local_export"})
    p = pf2_append_media_artifact(p, jid, "zip_pack", file_names=[filename], metadata={"file_count": len(files)})
    p = pf2_append_export_history(p, {
        "job_id": jid,
        "export_type": "zip_pack",
        "file_names": [filename],
        "generated_at": now_jst_iso(),
        "local_zip_path": str(zip_path),
        "local_site_dir": str(site_root),
        "warning_snapshot": job["public_check"].get("warnings", []),
        "block_snapshot": [],
        "note_for_user": "公開用ファイルを作成しました。媒体側の掲載・審査は別途確認が必要です。",
    })
    p = pf2_append_audit_log(p, "pf2_local_export_generated", target_type="job", target_id=jid, metadata={
        "zip_path": str(zip_path),
        "file_count": len(files),
    })
    p = pf2_local_save_project(p, active=True)
    return {
        "ok": True,
        "message": "公開用ファイルを作成しました",
        "project": p,
        "zip_path": str(zip_path),
        "site_dir": str(site_root),
        "filename": filename,
        "zip_bytes": zip_bytes,
        "file_count": len(files),
    }


def pf2_local_export_homepage_project(project: dict) -> dict:
    p = normalize_project(project if isinstance(project, dict) else {})
    settings = pf2_ensure_extension(p).get("settings")
    settings = settings if isinstance(settings, dict) else {}
    google_enabled = settings.get("google_jobposting_enabled", True) is not False
    indeed_enabled = settings.get("indeed_xml_enabled", True) is not False
    sitemap_robots_enabled = settings.get("sitemap_robots_enabled", True) is not False
    files = build_pageflowai2_site_files(p)
    if not google_enabled:
        files.pop(RECRUITMENT_JOBPOSTING_JSON_PATH, None)
    if not indeed_enabled:
        files.pop(RECRUITMENT_INDEED_FEED_PATH, None)
    if not sitemap_robots_enabled:
        files.pop(SITE_SITEMAP_PATH, None)
        files.pop(SITE_ROBOTS_PATH, None)

    timestamp = datetime.now(JST).strftime("%Y%m%d_%H%M%S")
    safe_pid = re.sub(r"[^a-zA-Z0-9_-]", "_", pf2_text(p.get("project_id")) or "project")
    export_root = pf2_local_export_dir() / safe_pid / f"homepage_{timestamp}"
    site_root = export_root / "site"
    site_root.mkdir(parents=True, exist_ok=True)
    for rel, raw in files.items():
        member = pf2_safe_export_member_path(rel)
        if member is None:
            continue
        out_path = site_root / member
        out_path.parent.mkdir(parents=True, exist_ok=True)
        out_path.write_bytes(raw if isinstance(raw, bytes) else bytes(raw or b""))

    filename = f"PageFlowAI2_CompanyPage_{safe_pid}_{timestamp}.zip"
    zip_path = export_root / filename
    buffer = BytesIO()
    with zipfile.ZipFile(buffer, "w", zipfile.ZIP_DEFLATED) as zf:
        for rel, raw in files.items():
            member = pf2_safe_export_member_path(rel)
            if member is None:
                continue
            zf.writestr(str(Path("site") / member).replace("\\", "/"), raw if isinstance(raw, bytes) else bytes(raw or b""))
    zip_bytes = buffer.getvalue()
    zip_path.write_bytes(zip_bytes)
    jid = pf2_job_id_for_project(p)
    artifact_files = {
        "company_page_html": ["index.html"] if "index.html" in files else [],
        "job_lp_html": [RECRUITMENT_PAGE_PATH] if RECRUITMENT_PAGE_PATH in files else [],
        "google_jobposting_jsonld": [RECRUITMENT_JOBPOSTING_JSON_PATH] if RECRUITMENT_JOBPOSTING_JSON_PATH in files else [],
        "indeed_xml": [RECRUITMENT_INDEED_FEED_PATH] if RECRUITMENT_INDEED_FEED_PATH in files else [],
        "sitemap": [SITE_SITEMAP_PATH] if SITE_SITEMAP_PATH in files else [],
        "robots": [SITE_ROBOTS_PATH] if SITE_ROBOTS_PATH in files else [],
    }
    for artifact_type, names in artifact_files.items():
        if names:
            p = pf2_append_media_artifact(p, jid, artifact_type, file_names=names, metadata={"source": "homepage_export"})
    p = pf2_append_media_artifact(p, jid, "homepage_zip_pack", file_names=[filename], metadata={"file_count": len(files)})

    p = pf2_append_export_history(p, {
        "export_type": "homepage_zip_pack",
        "file_names": [filename],
        "generated_at": now_jst_iso(),
        "local_zip_path": str(zip_path),
        "local_site_dir": str(site_root),
        "warning_snapshot": [],
        "block_snapshot": [],
        "note_for_user": "会社ページ用ファイルを作成しました。実際の公開はお客様のWebサーバで行ってください。",
    })
    p = pf2_append_audit_log(p, "pf2_local_homepage_export_generated", target_type="homepage", target_id=safe_pid, metadata={
        "zip_path": str(zip_path),
        "file_count": len(files),
    })
    p = pf2_local_save_project(p, active=True)
    return {
        "ok": True,
        "message": "会社ページ用ファイルを作成しました",
        "project": p,
        "zip_path": str(zip_path),
        "site_dir": str(site_root),
        "filename": filename,
        "zip_bytes": zip_bytes,
        "file_count": len(files),
    }


def pf2_job_id_for_project(p: Optional[dict]) -> str:
    raw = pf2_text(p.get("project_id")) if isinstance(p, dict) else ""
    return (raw or "project") + "-recruitment"


def pf2_active_job_id_for_project(p: Optional[dict]) -> str:
    if not isinstance(p, dict):
        return pf2_job_id_for_project(p)
    ext = pf2_ensure_extension(p)
    jobs = ext.get("jobs") if isinstance(ext.get("jobs"), dict) else {}
    active = pf2_text(ext.get("active_job_id"))
    if active and active in jobs:
        return active
    default = pf2_job_id_for_project(p)
    if default in jobs:
        return default
    if len(jobs) == 1:
        return next(iter(jobs.keys()))
    return default


def pf2_ensure_extension(p: dict) -> dict:
    """Create the PageFlowAI2 extension area without disturbing legacy fields."""
    if not isinstance(p, dict):
        p = {}
    data = p.get("data") if isinstance(p.get("data"), dict) else {}
    p["data"] = data
    ext = data.get("pageflowai2") if isinstance(data.get("pageflowai2"), dict) else {}
    data["pageflowai2"] = ext
    ext.setdefault("schema_version", PAGEFLOWAI2_SCHEMA_VERSION)
    ext.setdefault("jobs", {})
    ext.setdefault("wizard_answers", {})
    ext.setdefault("ai_drafts", {})
    ext.setdefault("public_check_runs", [])
    ext.setdefault("media_artifacts", [])
    ext.setdefault("export_history", [])
    ext.setdefault("audit_logs", [])
    ext.setdefault("homepage", {})
    ext.setdefault("settings", {})
    if not isinstance(ext.get("jobs"), dict):
        ext["jobs"] = {}
    if not isinstance(ext.get("wizard_answers"), dict):
        ext["wizard_answers"] = {}
    if not isinstance(ext.get("ai_drafts"), dict):
        ext["ai_drafts"] = {}
    if not isinstance(ext.get("public_check_runs"), list):
        ext["public_check_runs"] = []
    if not isinstance(ext.get("media_artifacts"), list):
        ext["media_artifacts"] = []
    if not isinstance(ext.get("export_history"), list):
        ext["export_history"] = []
    if not isinstance(ext.get("audit_logs"), list):
        ext["audit_logs"] = []
    if not isinstance(ext.get("homepage"), dict):
        ext["homepage"] = {}
    if not isinstance(ext.get("settings"), dict):
        ext["settings"] = {}
    settings = ext["settings"]
    settings.setdefault("local_role", "admin")
    settings["local_role"] = pf2_normalize_role(settings.get("local_role"))
    return ext


def pf2_job_extra_for_project(p: dict, job_id: str = "") -> dict:
    ext = pf2_ensure_extension(p)
    jobs = ext.get("jobs") if isinstance(ext.get("jobs"), dict) else {}
    jid = pf2_text(job_id) or pf2_job_id_for_project(p)
    item = jobs.get(jid) if isinstance(jobs.get(jid), dict) else {}
    jobs[jid] = item
    ext["jobs"] = jobs
    return item


def pf2_job_from_project(p: dict, job_id: str = "") -> dict:
    """Project -> PageFlowAI2 Job adapter.

    Legacy recruitment fields remain the source for current output paths, while
    v0.4-only fields live under data.pageflowai2.jobs[job_id].
    """
    project = normalize_project(p if isinstance(p, dict) else {})
    data = project.get("data") if isinstance(project.get("data"), dict) else {}
    step1 = data.get("step1") if isinstance(data.get("step1"), dict) else {}
    step2 = data.get("step2") if isinstance(data.get("step2"), dict) else {}
    blocks = data.get("blocks") if isinstance(data.get("blocks"), dict) else {}
    recruitment = _normalize_recruitment_block(blocks.get("recruitment") if isinstance(blocks.get("recruitment"), dict) else {})
    jid = pf2_text(job_id) or pf2_job_id_for_project(project)
    extra = pf2_job_extra_for_project(project, jid)
    faq_items = []
    for item in recruitment.get("faq_items") or []:
        if isinstance(item, dict):
            faq_items.append({"question": pf2_text(item.get("q")), "answer": pf2_text(item.get("a"))})
    job = {
        "tenant_id": pf2_text(project.get("owner_company_id")),
        "company_id": pf2_text(project.get("owner_company_id")),
        "job_id": jid,
        "project_id": pf2_text(project.get("project_id")),
        "company_name": pf2_clean_company_name(step2.get("company_name"), project.get("project_name")),
        "title": pf2_text(recruitment.get("title")),
        "employment_type": pf2_text(recruitment.get("employment_types")),
        "service_type": pf2_text(extra.get("service_type")) or pf2_text(step1.get("welfare_domain")) or pf2_text(step1.get("industry")),
        "workplace": pf2_text(recruitment.get("work_location")) or pf2_text(step2.get("address")),
        "workplace_change_scope": pf2_text(extra.get("workplace_change_scope")),
        "job_description": pf2_text(recruitment.get("work_details")) or pf2_text(recruitment.get("work_summary")),
        "job_summary": pf2_text(recruitment.get("work_summary")),
        "job_change_scope": pf2_text(extra.get("job_change_scope")),
        "contract_period_type": pf2_text(extra.get("contract_period_type")) or "unknown",
        "contract_period": pf2_text(extra.get("contract_period")),
        "contract_renewal": pf2_text(extra.get("contract_renewal")),
        "contract_renewal_criteria": pf2_text(extra.get("contract_renewal_criteria")),
        "contract_renewal_limit": pf2_text(extra.get("contract_renewal_limit")),
        "salary_type": pf2_text(extra.get("salary_type")),
        "salary_min": extra.get("salary_min"),
        "salary_max": extra.get("salary_max"),
        "salary_note": pf2_text(recruitment.get("salary_note")),
        "salary_breakdown": pf2_text(extra.get("salary_breakdown")),
        "fixed_overtime_enabled": bool(extra.get("fixed_overtime_enabled", False)),
        "fixed_overtime_hours": extra.get("fixed_overtime_hours"),
        "fixed_overtime_amount": extra.get("fixed_overtime_amount"),
        "fixed_overtime_extra_pay_note": pf2_text(extra.get("fixed_overtime_extra_pay_note")),
        "working_hours": pf2_text(recruitment.get("work_hours")),
        "break_time": pf2_text(extra.get("break_time")),
        "holidays": pf2_text(recruitment.get("holidays")),
        "trial_period": pf2_text(extra.get("trial_period")),
        "social_insurance": pf2_text(extra.get("social_insurance")),
        "passive_smoking_policy": pf2_text(extra.get("passive_smoking_policy")),
        "appeal_text": pf2_text(recruitment.get("lead")),
        "day_flow": pf2_text(recruitment.get("daily_flow")),
        "benefits": pf2_text(recruitment.get("benefits")),
        "qualification_note": pf2_text(recruitment.get("qualification_note")),
        "ideal_candidate": pf2_text(recruitment.get("target_person")),
        "faq_items": faq_items,
        "application_method": pf2_text(recruitment.get("application_flow")),
        "apply_url": pf2_text(recruitment.get("apply_url")),
        "contact_name": pf2_text(extra.get("contact_name")),
        "contact_email": pf2_text(step2.get("email")),
        "contact_phone": pf2_text(step2.get("phone")),
        "ai_draft_used": bool(extra.get("ai_draft_used", False)),
        "ai_draft_human_confirmed_at": pf2_text(extra.get("ai_draft_human_confirmed_at")),
        "mobile_preview_checked_at": pf2_text(extra.get("mobile_preview_checked_at")),
        "last_public_check_at": pf2_text(extra.get("last_public_check_at")),
        "export_pack_generated_at": pf2_text(extra.get("export_pack_generated_at")),
        "created_by": pf2_text(project.get("created_by")),
        "updated_by": pf2_text(project.get("updated_by")),
        "created_at": pf2_text(project.get("created_at")),
        "updated_at": pf2_text(project.get("updated_at")),
    }
    job["public_check"] = pf2_public_check_job(job)
    job["main_state"] = pf2_compute_job_state(job)
    extra["main_state"] = job["main_state"]
    return job


def pf2_apply_job_to_project(p: dict, job: dict) -> dict:
    project = normalize_project(p if isinstance(p, dict) else {})
    data = project.get("data") if isinstance(project.get("data"), dict) else {}
    step2 = data.get("step2") if isinstance(data.get("step2"), dict) else {}
    blocks = data.get("blocks") if isinstance(data.get("blocks"), dict) else {}
    recruitment = _normalize_recruitment_block(blocks.get("recruitment") if isinstance(blocks.get("recruitment"), dict) else {})
    blocks["recruitment"] = recruitment
    jid = pf2_text(job.get("job_id")) or pf2_job_id_for_project(project)
    recruitment["enabled"] = bool(job.get("enabled", recruitment.get("enabled", True)))
    recruitment["title"] = pf2_text(job.get("title")) or recruitment.get("title") or "求人情報"
    recruitment["lead"] = pf2_text(job.get("appeal_text")) or recruitment.get("lead") or ""
    recruitment["employment_types"] = pf2_text(job.get("employment_type"))
    recruitment["work_location"] = pf2_text(job.get("workplace"))
    recruitment["work_hours"] = pf2_text(job.get("working_hours"))
    recruitment["salary_note"] = pf2_text(job.get("salary_note"))
    recruitment["holidays"] = pf2_text(job.get("holidays"))
    recruitment["benefits"] = pf2_text(job.get("benefits"))
    recruitment["work_summary"] = pf2_text(job.get("job_summary"))
    recruitment["work_details"] = pf2_text(job.get("job_description"))
    recruitment["daily_flow"] = pf2_text(job.get("day_flow"))
    recruitment["qualification_note"] = pf2_text(job.get("qualification_note"))
    recruitment["target_person"] = pf2_text(job.get("ideal_candidate"))
    recruitment["application_flow"] = pf2_text(job.get("application_method"))
    recruitment["apply_url"] = pf2_text(job.get("apply_url"))
    if pf2_text(job.get("company_name")):
        step2["company_name"] = pf2_text(job.get("company_name"))
    if pf2_text(job.get("contact_email")):
        step2["email"] = pf2_text(job.get("contact_email"))
    if pf2_text(job.get("contact_phone")):
        step2["phone"] = pf2_text(job.get("contact_phone"))
    faq_items = []
    for item in job.get("faq_items") or []:
        if isinstance(item, dict):
            q = pf2_text(item.get("question") or item.get("q"))
            a = pf2_text(item.get("answer") or item.get("a"))
            if q or a:
                faq_items.append({"q": q, "a": a})
    recruitment["faq_items"] = faq_items[:RECRUITMENT_FAQ_COUNT]

    extra = pf2_job_extra_for_project(project, jid)
    pf2_ensure_extension(project)["active_job_id"] = jid
    for key in [
        "service_type", "workplace_change_scope", "job_change_scope", "contract_period_type",
        "contract_period", "contract_renewal", "contract_renewal_criteria",
        "contract_renewal_limit", "salary_type", "salary_min", "salary_max",
        "salary_breakdown", "fixed_overtime_enabled", "fixed_overtime_hours",
        "fixed_overtime_amount", "fixed_overtime_extra_pay_note", "break_time",
        "trial_period", "social_insurance", "passive_smoking_policy",
        "contact_name", "ai_draft_used", "ai_draft_human_confirmed_at",
        "mobile_preview_checked_at", "last_public_check_at", "export_pack_generated_at",
    ]:
        if key in job:
            extra[key] = job.get(key)
    extra["main_state"] = pf2_compute_job_state(job)
    return normalize_project(project)


def pf2_public_check_job(job: dict) -> dict:
    blocks_: list[dict[str, str]] = []
    warnings: list[dict[str, str]] = []
    for key, label in PF2_REQUIRED_JOB_FIELDS:
        if not pf2_text(job.get(key)):
            blocks_.append({"field": key, "label": label, "message": f"{label}が未入力です"})
    if pf2_text(job.get("contract_period_type")) == "fixed_term":
        for key, label in PF2_CONTRACT_REQUIRED_FIELDS:
            if not pf2_text(job.get(key)):
                blocks_.append({"field": key, "label": label, "message": f"有期契約の場合、{label}が必要です"})
    if bool(job.get("fixed_overtime_enabled")):
        for key, label in [
            ("salary_breakdown", "基本給または給与内訳"),
            ("fixed_overtime_hours", "固定残業時間"),
            ("fixed_overtime_amount", "固定残業代の金額"),
            ("fixed_overtime_extra_pay_note", "固定残業代を超える時間外労働の扱い"),
        ]:
            if not pf2_text(job.get(key)):
                blocks_.append({"field": key, "label": label, "message": f"固定残業代を含む場合、{label}が必要です"})
    if bool(job.get("ai_draft_used")) and not pf2_text(job.get("ai_draft_human_confirmed_at")):
        blocks_.append({"field": "ai_draft_human_confirmed_at", "label": "入力補助文の確認", "message": "入力補助で作った文章の確認が未完了です"})
    for field, label, value in pf2_public_text_safety_entries(job):
        if not value:
            continue
        pii_scan = pf2_scan_pii_text(value)
        if not pii_scan["passed"]:
            blocks_.append({
                "field": f"{field}.pii",
                "label": label,
                "message": "個人情報につながる可能性がある表現を削除してください",
            })
        claim_scan = pf2_scan_media_claim_text(value)
        if not claim_scan["passed"]:
            blocks_.append({
                "field": f"{field}.media_claim",
                "label": label,
                "message": "採用成功、上位表示、媒体掲載を保証するように読める表現を削除してください",
            })
    if not pf2_text(job.get("mobile_preview_checked_at")):
        warnings.append({"field": "mobile_preview_checked_at", "label": "スマホ表示確認", "message": "スマホ表示の確認が未完了です"})
    return {"blocks": blocks_, "warnings": warnings}


def pf2_compute_job_state(job: dict) -> str:
    meaningful = ["title", "employment_type", "workplace", "job_description", "salary_note", "working_hours", "appeal_text"]
    filled_count = sum(1 for key in meaningful if pf2_text(job.get(key)))
    if filled_count == 0:
        return PF2_JOB_STATE_NOT_STARTED
    public_check = job.get("public_check") if isinstance(job.get("public_check"), dict) else pf2_public_check_job(job)
    blocks_ = public_check.get("blocks") if isinstance(public_check.get("blocks"), list) else []
    warnings = public_check.get("warnings") if isinstance(public_check.get("warnings"), list) else []
    if blocks_:
        return PF2_JOB_STATE_EDITING
    if warnings or not pf2_text(job.get("last_public_check_at")):
        return PF2_JOB_STATE_REVIEW_REQUIRED
    if pf2_text(job.get("export_pack_generated_at")):
        return PF2_JOB_STATE_PREPARED
    return PF2_JOB_STATE_EXPORT_READY


def pf2_append_export_history(p: dict, export_item: dict) -> dict:
    project = p if isinstance(p, dict) else {}
    ext = pf2_ensure_extension(project)
    history = ext.get("export_history") if isinstance(ext.get("export_history"), list) else []
    item = dict(export_item or {})
    item.setdefault("created_at", now_jst_iso())
    item.setdefault("export_id", f"export-{len(history) + 1}")
    history.append(item)
    ext["export_history"] = history[-100:]
    return project


def pf2_append_public_check_run(p: dict, job_id: str, result: dict) -> dict:
    project = p if isinstance(p, dict) else {}
    ext = pf2_ensure_extension(project)
    runs = ext.get("public_check_runs") if isinstance(ext.get("public_check_runs"), list) else []
    check = result if isinstance(result, dict) else {}
    blocks_ = check.get("blocks") if isinstance(check.get("blocks"), list) else []
    warnings = check.get("warnings") if isinstance(check.get("warnings"), list) else []
    runs.append({
        "run_id": f"public-check-{len(runs) + 1}",
        "job_id": pf2_text(job_id),
        "block_count": len(blocks_),
        "warning_count": len(warnings),
        "blocks": blocks_,
        "warnings": warnings,
        "created_at": now_jst_iso(),
    })
    ext["public_check_runs"] = runs[-100:]
    return project


def pf2_append_media_artifact(
    p: dict,
    job_id: str,
    artifact_type: str,
    *,
    status: str = "generated",
    file_names: Optional[list[str]] = None,
    metadata: Optional[dict] = None,
) -> dict:
    project = p if isinstance(p, dict) else {}
    ext = pf2_ensure_extension(project)
    artifacts = ext.get("media_artifacts") if isinstance(ext.get("media_artifacts"), list) else []
    artifacts.append({
        "artifact_id": f"media-artifact-{len(artifacts) + 1}",
        "job_id": pf2_text(job_id),
        "artifact_type": pf2_text(artifact_type),
        "status": pf2_text(status) or "generated",
        "file_names": [pf2_text(name) for name in (file_names or []) if pf2_text(name)],
        "metadata": metadata if isinstance(metadata, dict) else {},
        "created_at": now_jst_iso(),
    })
    ext["media_artifacts"] = artifacts[-100:]
    return project


def pf2_append_audit_log(p: dict, action: str, *, target_type: str = "", target_id: str = "", metadata: Optional[dict] = None) -> dict:
    project = p if isinstance(p, dict) else {}
    ext = pf2_ensure_extension(project)
    logs = ext.get("audit_logs") if isinstance(ext.get("audit_logs"), list) else []
    logs.append({
        "audit_id": f"audit-{len(logs) + 1}",
        "action": pf2_text(action),
        "target_type": pf2_text(target_type),
        "target_id": pf2_text(target_id),
        "metadata": metadata if isinstance(metadata, dict) else {},
        "created_at": now_jst_iso(),
    })
    ext["audit_logs"] = logs[-500:]
    return project


def pf2_ai_log_timestamp(draft: dict) -> Optional[datetime]:
    if not isinstance(draft, dict):
        return None
    for key in ["created_at", "human_confirmed_at", "generated_at"]:
        dt = parse_iso_datetime(pf2_text(draft.get(key)))
        if dt:
            return dt
    return None


def pf2_prune_ai_drafts(p: dict, *, now: Optional[datetime] = None) -> dict:
    project = p if isinstance(p, dict) else {}
    ext = pf2_ensure_extension(project)
    drafts = ext.get("ai_drafts") if isinstance(ext.get("ai_drafts"), dict) else {}
    current = now or datetime.now(JST)
    kept: dict[str, dict] = {}
    removed = 0
    for draft_id, draft in drafts.items():
        if not isinstance(draft, dict):
            removed += 1
            continue
        created = pf2_ai_log_timestamp(draft)
        if not created:
            kept[str(draft_id)] = draft
            continue
        try:
            retention_days = int(draft.get("retention_days") or PF2_AI_LOG_RETENTION_DAYS)
        except Exception:
            retention_days = PF2_AI_LOG_RETENTION_DAYS
        retention_days = max(1, min(retention_days, PF2_AI_PUBLIC_LOG_RETENTION_DAYS))
        if created.astimezone(JST) < current.astimezone(JST) - timedelta(days=retention_days):
            removed += 1
            continue
        kept[str(draft_id)] = draft
    if removed:
        ext["ai_drafts"] = kept
        ext["last_ai_log_pruned_at"] = now_jst_iso()
        ext["last_ai_log_pruned_count"] = removed
    return project


def pf2_record_ai_draft_log(
    p: dict,
    *,
    job_id: str = "",
    purpose: str,
    provider: str,
    input_snapshot: Optional[dict] = None,
    generated_text: str = "",
    edited_text: str = "",
    scan: Optional[dict] = None,
    retention_days: int = PF2_AI_LOG_RETENTION_DAYS,
) -> dict:
    project = p if isinstance(p, dict) else {}
    ext = pf2_ensure_extension(project)
    draft_id = "draft-" + datetime.now(JST).strftime("%Y%m%d%H%M%S") + "-" + secrets.token_hex(2)
    ext.setdefault("ai_drafts", {})[draft_id] = {
        "draft_id": draft_id,
        "job_id": pf2_text(job_id),
        "purpose": pf2_text(purpose),
        "provider": pf2_text(provider) or "input_assist",
        "input_context_snapshot": input_snapshot if isinstance(input_snapshot, dict) else {},
        "generated_text": pf2_text(generated_text),
        "edited_text": pf2_text(edited_text),
        "scan": scan if isinstance(scan, dict) else {},
        "human_confirmed": False,
        "created_at": now_jst_iso(),
        "retention_days": max(1, min(int(retention_days or PF2_AI_LOG_RETENTION_DAYS), PF2_AI_PUBLIC_LOG_RETENTION_DAYS)),
    }
    return pf2_prune_ai_drafts(project)


def _public_site_base_url(site_url: str) -> str:
    raw = str(site_url or "").strip()
    if not raw:
        return ""
    try:
        parsed = urlparse(raw)
        if parsed.scheme not in {"http", "https"} or not parsed.netloc:
            return ""
        path = parsed.path or "/"
        if path.endswith("/index.html"):
            path = path[:-11] or "/"
        if not path.endswith("/"):
            path += "/"
        return urlunparse((parsed.scheme, parsed.netloc, path, "", "", ""))
    except Exception:
        return ""


def _public_url(base_url: str, relative_path: str) -> str:
    base = _public_site_base_url(base_url)
    rel = str(relative_path or "").lstrip("/")
    if not base or not rel:
        return ""
    try:
        return urljoin(base, rel)
    except Exception:
        return ""


def _public_page_url(base_url: str, relative_path: str) -> str:
    raw = _public_url(base_url, relative_path)
    if not raw:
        return ""
    try:
        parsed = urlparse(raw)
        path = parsed.path or "/"
        if path.endswith("/index.html"):
            path = path[:-10] or "/"
        return urlunparse(parsed._replace(path=path))
    except Exception:
        return raw


def _get_project_publish_settings(p: Optional[dict]) -> dict:
    data = p.get("data") if isinstance(p, dict) else {}
    if not isinstance(data, dict):
        return {}
    publish = data.get("publish")
    return publish if isinstance(publish, dict) else {}


def _project_public_site_url(p: Optional[dict], step2: Optional[dict] = None, profile: Optional[dict] = None) -> str:
    publish = _get_project_publish_settings(p)
    configured = str(publish.get("public_site_url") or "").strip()
    if configured:
        return configured
    return _company_profile_effective_value(step2, profile, "site_url")


def _append_query_param(url: str, key: str, value: str) -> str:
    raw = str(url or "").strip()
    if not raw:
        return ""
    try:
        parsed = urlparse(raw)
        query_items = [(k, v) for k, v in parse_qsl(parsed.query, keep_blank_values=True) if k != key]
        query_items.append((key, value))
        return urlunparse(parsed._replace(query=urlencode(query_items)))
    except Exception:
        sep = "&" if "?" in raw else "?"
        return f"{raw}{sep}{key}={quote_plus(value)}"


def _build_sitemap_xml(urls: list[str], *, lastmod: str = "") -> str:
    items: list[str] = []
    for raw in urls:
        loc = str(raw or "").strip()
        if not loc:
            continue
        loc_xml = html.escape(loc, quote=False)
        if lastmod:
            items.append(f"  <url><loc>{loc_xml}</loc><lastmod>{html.escape(lastmod)}</lastmod></url>")
        else:
            items.append(f"  <url><loc>{loc_xml}</loc></url>")
    return "\n".join([
        '<?xml version="1.0" encoding="UTF-8"?>',
        '<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">',
        *items,
        '</urlset>',
        "",
    ])


def _build_robots_txt(*, sitemap_url: str = "") -> str:
    lines = [
        "User-agent: *",
        "Allow: /",
    ]
    if sitemap_url:
        lines.extend(["", f"Sitemap: {sitemap_url.strip()}"])
    lines.append("")
    return "\n".join(lines)


def _json_loads_bytes(raw, default=None):
    fallback = {} if default is None else default
    if raw is None:
        return fallback
    try:
        text = raw.decode("utf-8", errors="replace") if isinstance(raw, (bytes, bytearray)) else str(raw or "")
        text = text.strip()
        return json.loads(text) if text else fallback
    except Exception:
        return fallback


def _extract_postal_code(text: str) -> str:
    raw = str(text or "").strip()
    if not raw:
        return ""
    m = re.search(r"〒?\s*(\d{3})[-ー−‐－ ]?(\d{4})", raw)
    if not m:
        return ""
    return f"{m.group(1)}-{m.group(2)}"


def _split_japanese_address(address: str) -> dict[str, str]:
    raw = str(address or "").strip()
    postal = _extract_postal_code(raw)
    body = re.sub(r"〒?\s*\d{3}[-ー−‐－ ]?\d{4}\s*", "", raw).strip()
    state = ""
    for pref in JP_PREFECTURES:
        if body.startswith(pref):
            state = pref
            body = body[len(pref):].strip()
            break

    city = ""
    street = body
    if body:
        m = re.match(r"^(.+?(?:市.+?区|郡.+?(?:町|村)|市|区|町|村))(.*)$", body)
        if m:
            city = m.group(1).strip()
            street = m.group(2).strip()
        else:
            digit_match = re.search(r"[0-9０-９]", body)
            if digit_match:
                idx = digit_match.start()
                city = body[:idx].strip()
                street = body[idx:].strip()
    if not city and body:
        city = body
        street = ""
    return {
        "postalcode": postal,
        "state": state,
        "city": city,
        "streetaddress": street,
    }


def _iso_datetime_utc(value: str, fallback: str = "") -> str:
    dt = parse_iso_datetime(str(value or "")) or parse_iso_datetime(str(fallback or ""))
    if not dt:
        dt = datetime.now(timezone.utc)
    try:
        dt = dt.astimezone(timezone.utc)
    except Exception:
        dt = dt.replace(tzinfo=timezone.utc)
    return dt.replace(microsecond=0).isoformat().replace("+00:00", "Z")


def _extract_salary_text(text: str) -> str:
    raw = str(text or "").replace("\r\n", "\n").replace("\r", "\n").strip()
    if not raw:
        return ""
    patterns = [
        r"(月給[^\n。]+)",
        r"(年収[^\n。]+)",
        r"(時給[^\n。]+)",
        r"(日給[^\n。]+)",
        r"(給与[^\n。]+)",
        r"((?:\d[\d,]*)\s*円[^\n。]*)",
    ]
    for pat in patterns:
        m = re.search(pat, raw)
        if m:
            return m.group(1).strip()
    return ""


def _indeed_jobtype_values(employment_text: str) -> str:
    raw = str(employment_text or "").strip()
    if not raw:
        return ""
    values: list[str] = []
    mapping = [
        (("正社員", "フルタイム", "fulltime", "常勤"), "fulltime"),
        (("パート", "アルバイト", "parttime", "短時間"), "parttime"),
        (("契約社員", "contract"), "contract"),
        (("派遣", "temporary", "temp"), "temporary"),
        (("業務委託", "委託"), "contract"),
        (("インターン", "intern"), "internship"),
    ]
    lowered = raw.lower()
    for keywords, normalized in mapping:
        if any(keyword.lower() in lowered for keyword in keywords) and normalized not in values:
            values.append(normalized)
    return ", ".join(values) if values else raw


def _xml_cdata(value: str) -> str:
    raw = str(value or "")
    return "<![CDATA[" + raw.replace("]]>", "]]]]><![CDATA[>") + "]]>"


def _build_recruitment_description_html(sections: list[tuple[str, str]]) -> str:
    blocks: list[str] = []
    for title, text in sections:
        raw = str(text or "").replace("\r\n", "\n").replace("\r", "\n").strip()
        if not raw:
            continue
        paragraphs = []
        for line in [seg.strip() for seg in raw.split("\n") if seg.strip()]:
            paragraphs.append(f"<p>{html.escape(line)}</p>")
        body = "".join(paragraphs) if paragraphs else f"<p>{html.escape(raw)}</p>"
        blocks.append(f"<h2>{html.escape(title)}</h2>{body}")
    return "".join(blocks)


def _google_service_account_candidate_paths(publish: Optional[dict] = None) -> list[str]:
    publish_cfg = publish if isinstance(publish, dict) else {}
    local_appdata_raw = str(os.getenv("LOCALAPPDATA") or "").strip()
    secret_dir = (Path(local_appdata_raw) / "Temp" / "codex-secrets") if local_appdata_raw else None
    raw_candidates = [
        str(publish_cfg.get("google_service_account_file") or "").strip(),
        str(os.getenv(CVHB_GOOGLE_SERVICE_ACCOUNT_FILE_ENV) or "").strip(),
        str(os.getenv("GOOGLE_APPLICATION_CREDENTIALS") or "").strip(),
    ]
    if secret_dir is not None:
        for name in [
            "google-indexing-service-account.json",
            "google_service_account.json",
            "service-account.json",
            "service_account.json",
        ]:
            raw_candidates.append(str(secret_dir / name))

    seen: set[str] = set()
    out: list[str] = []
    for raw in raw_candidates:
        path = str(raw or "").strip()
        if not path or path in seen:
            continue
        seen.add(path)
        out.append(path)
    return out


def _load_google_service_account_info(publish: Optional[dict] = None) -> tuple[Optional[dict], str, str]:
    env_json = str(os.getenv(CVHB_GOOGLE_SERVICE_ACCOUNT_JSON_ENV) or "").strip()
    if env_json:
        try:
            info = json.loads(env_json)
            missing = [k for k in ["client_email", "private_key", "token_uri"] if not str(info.get(k) or "").strip()]
            if missing:
                return None, "", f"{CVHB_GOOGLE_SERVICE_ACCOUNT_JSON_ENV} に必須キー不足: {', '.join(missing)}"
            return info, f"env:{CVHB_GOOGLE_SERVICE_ACCOUNT_JSON_ENV}", ""
        except Exception as e:
            return None, "", f"{CVHB_GOOGLE_SERVICE_ACCOUNT_JSON_ENV} の読込に失敗しました: {sanitize_error_text(e)}"

    last_error = ""
    for candidate in _google_service_account_candidate_paths(publish):
        path = Path(candidate)
        if not path.is_file():
            continue
        try:
            info = json.loads(path.read_text(encoding="utf-8"))
            missing = [k for k in ["client_email", "private_key", "token_uri"] if not str(info.get(k) or "").strip()]
            if missing:
                last_error = f"service account JSON に必須キー不足: {', '.join(missing)}"
                continue
            return info, str(path), ""
        except Exception as e:
            last_error = f"service account JSON の読込に失敗しました: {sanitize_error_text(e)}"
    return None, "", last_error or "Google service account JSON が未設定です"


def _google_indexing_enabled(publish: Optional[dict] = None) -> bool:
    publish_cfg = publish if isinstance(publish, dict) else {}
    if "google_indexing_enabled" in publish_cfg:
        return _as_bool(publish_cfg.get("google_indexing_enabled"), default=True)
    return _env_flag("CVHB_GOOGLE_INDEXING_ENABLED")


def submit_google_indexing_notification(url: str, *, notification_type: str = "URL_UPDATED", publish: Optional[dict] = None) -> dict:
    result = {
        "at": now_jst_iso(),
        "attempted": False,
        "ok": False,
        "state": "failed",
        "message": "",
        "url": str(url or "").strip(),
        "notification_type": str(notification_type or "URL_UPDATED").strip() or "URL_UPDATED",
        "status_code": 0,
        "credential_source": "",
        "response": {},
    }
    if not result["url"]:
        result["state"] = "skipped"
        result["message"] = "採用ページの公開URLが未設定です"
        return result
    if AuthorizedSession is None or google_service_account is None:
        result["state"] = "skipped"
        result["message"] = "google-auth が未インストールのため Google Indexing API を実行できません"
        return result

    info, source, load_error = _load_google_service_account_info(publish)
    if not info:
        result["state"] = "skipped"
        result["message"] = load_error or "Google service account JSON が見つかりません"
        return result

    session = None
    try:
        credentials = google_service_account.Credentials.from_service_account_info(info, scopes=[GOOGLE_INDEXING_SCOPE])
        session = AuthorizedSession(credentials)
        payload = {"url": result["url"], "type": result["notification_type"]}
        response = session.post(GOOGLE_INDEXING_PUBLISH_ENDPOINT, json=payload, timeout=20)
        result["attempted"] = True
        result["credential_source"] = source
        result["status_code"] = int(getattr(response, "status_code", 0) or 0)
        body_text = str(getattr(response, "text", "") or "").strip()
        body_json = _json_loads_bytes(body_text, default={}) if body_text else {}
        result["response"] = body_json if isinstance(body_json, dict) and body_json else {"raw": body_text[:800]} if body_text else {}
        if 200 <= result["status_code"] < 300:
            result["ok"] = True
            result["state"] = "success"
            result["message"] = "Google Indexing API に URL_UPDATED を送信しました" if result["notification_type"] == "URL_UPDATED" else "Google Indexing API に通知しました"
            return result

        error_message = ""
        if isinstance(body_json, dict):
            err = body_json.get("error")
            if isinstance(err, dict):
                error_message = str(err.get("message") or "").strip()
        result["message"] = error_message or body_text[:200] or "Google Indexing API がエラーを返しました"
        return result
    except Exception as e:
        result["message"] = sanitize_error_text(e)
        return result
    finally:
        try:
            if session is not None:
                session.close()
        except Exception:
            pass


def sync_google_indexing_for_project(
    p: dict,
    *,
    actor: Optional["User"] = None,
    notification_type: str = "URL_UPDATED",
    distribution_payload: Optional[dict] = None,
    force: bool = False,
) -> dict:
    publish = _get_project_publish_settings(p)
    data = p.get("data") if isinstance(p, dict) else {}
    blocks = data.get("blocks") if isinstance(data, dict) and isinstance(data.get("blocks"), dict) else {}
    recruitment = blocks.get("recruitment") if isinstance(blocks.get("recruitment"), dict) else {}
    if not _recruitment_is_visible(recruitment):
        return {
            "at": now_jst_iso(),
            "attempted": False,
            "ok": False,
            "state": "skipped",
            "message": "採用ページが未公開のため Google 通知をスキップしました",
            "url": "",
            "notification_type": notification_type,
            "status_code": 0,
            "credential_source": "",
            "response": {},
        }
    if not force and not _google_indexing_enabled(publish):
        return {
            "at": now_jst_iso(),
            "attempted": False,
            "ok": False,
            "state": "skipped",
            "message": "Google Indexing API の自動通知がOFFです",
            "url": "",
            "notification_type": notification_type,
            "status_code": 0,
            "credential_source": "",
            "response": {},
        }

    step2 = data.get("step2") if isinstance(data, dict) and isinstance(data.get("step2"), dict) else {}
    philosophy = blocks.get("philosophy") if isinstance(blocks.get("philosophy"), dict) else {}
    profile = philosophy.get("company_profile") if isinstance(philosophy.get("company_profile"), dict) else {}
    dist = distribution_payload if isinstance(distribution_payload, dict) else {}
    public_urls = dist.get("public_urls") if isinstance(dist.get("public_urls"), dict) else {}
    google_dist = dist.get("google") if isinstance(dist.get("google"), dict) else {}
    target_url = str(public_urls.get("recruitment_page") or "").strip()
    if not target_url and isinstance(google_dist.get("url_updated_payload"), dict):
        target_url = str(google_dist.get("url_updated_payload", {}).get("url") or "").strip()
    if not target_url:
        target_url = _public_page_url(_project_public_site_url(p, step2, profile), RECRUITMENT_PAGE_PATH)

    result = submit_google_indexing_notification(
        target_url,
        notification_type=notification_type,
        publish=publish,
    )
    try:
        if actor:
            action = "project_google_indexing"
            if result.get("state") == "skipped":
                action = "project_google_indexing_skipped"
            elif not result.get("ok"):
                action = "project_google_indexing_failed"
            safe_log_action(
                actor,
                action,
                details=json.dumps(
                    {
                        "project_id": str(p.get("project_id") or ""),
                        "state": result.get("state"),
                        "url": result.get("url"),
                        "status_code": result.get("status_code"),
                        "message": result.get("message"),
                    },
                    ensure_ascii=False,
                ),
            )
    except Exception:
        pass
    return result


def apply_recruitment_distribution_to_workflow(wf: dict, distribution_payload: Optional[dict]) -> None:
    if not isinstance(wf, dict) or not isinstance(distribution_payload, dict):
        return
    public_urls = distribution_payload.get("public_urls") if isinstance(distribution_payload.get("public_urls"), dict) else {}
    google = distribution_payload.get("google") if isinstance(distribution_payload.get("google"), dict) else {}
    indeed = distribution_payload.get("indeed") if isinstance(distribution_payload.get("indeed"), dict) else {}
    wf["last_distribution_generated_at"] = str(distribution_payload.get("generated_at") or "")
    wf["last_distribution_public_site_url"] = str(distribution_payload.get("public_site_url") or "")
    wf["last_recruitment_public_url"] = str(public_urls.get("recruitment_page") or "")
    wf["last_jobposting_json_url"] = str(public_urls.get("jobposting_json") or "")
    wf["last_indeed_feed_url"] = str(public_urls.get("indeed_feed_xml") or "")
    wf["last_sitemap_url"] = str(public_urls.get("sitemap_xml") or "")
    wf["last_robots_url"] = str(public_urls.get("robots_txt") or "")
    wf["last_distribution_google_ready"] = bool(google.get("indexing_api_ready"))
    wf["last_distribution_indeed_ready"] = bool(indeed.get("feed_ready"))


def apply_google_indexing_result_to_workflow(wf: dict, result: Optional[dict], actor: Optional["User"] = None) -> None:
    if not isinstance(wf, dict) or not isinstance(result, dict):
        return
    wf["last_google_indexing_at"] = str(result.get("at") or now_jst_iso())
    wf["last_google_indexing_by"] = actor.username if actor else str(result.get("by") or "")
    wf["last_google_indexing_state"] = str(result.get("state") or ("success" if result.get("ok") else "failed"))
    wf["last_google_indexing_ok"] = bool(result.get("ok"))
    wf["last_google_indexing_message"] = str(result.get("message") or "")
    wf["last_google_indexing_url"] = str(result.get("url") or "")
    wf["last_google_indexing_type"] = str(result.get("notification_type") or "")
    wf["last_google_indexing_credential_source"] = str(result.get("credential_source") or "")
    try:
        wf["last_google_indexing_status_code"] = int(result.get("status_code") or 0)
    except Exception:
        wf["last_google_indexing_status_code"] = 0


def extract_recruitment_distribution_payload(files: Optional[dict[str, bytes]]) -> dict:
    if not isinstance(files, dict):
        return {}
    return _json_loads_bytes(files.get(RECRUITMENT_DISTRIBUTION_JSON_PATH), default={})

# 事故防止：極端に大きいファイルは弾く（Heroku/ブラウザの負荷対策）
MAX_UPLOAD_BYTES = 10_000_000  # 10MB


def _maybe_resize_image_bytes(data: bytes, mime: str, *, max_w: int, max_h: int, force_png: bool = False, fit_mode: str = "cover", trim_transparent: bool = False, allow_upscale: bool = True, prefer_lossy_if_opaque: bool = False) -> tuple[bytes, str]:
    """画像を target(max_w×max_h) に整えて返す。

    fit_mode:
    - cover  : 比率を合わせてセンタークロップ + リサイズ
    - contain: 画像全体を残して target 内に収める（ロゴ向け）

    trim_transparent:
    - True のとき、透明PNGなどで周囲の透明余白を先にトリムする
      （会社ロゴをヘッダーで自然な大きさに見せたい時用）

    仕様:
    - Pillow(PIL) が無い環境では元データを返す（安全優先）
    - EXIF の回転を補正してから処理する
    - 出力は基本: 透過あり -> PNG / 透過なし -> WebP(quality=80)
      WebP に失敗した場合は JPEG(quality=82) へ安全にフォールバックする
      ただし force_png=True の場合は常に PNG を返す

    1.5.1:
    - builder preview 用に、ほぼ不透明なRGBA画像は lossy(WebP/JPEG)へ落とせるようにした
      → PNG のまま巨大化しやすい画像を軽くし、/pv_img の転送量を減らす
    """
    try:
        if not data:
            return data, mime
        if max_w <= 0 or max_h <= 0:
            return data, mime
        if not str(mime or "").startswith("image/"):
            return data, mime

        try:
            from PIL import Image, ImageOps  # type: ignore
            from io import BytesIO
        except Exception:
            return data, mime

        fit_mode = str(fit_mode or "cover").strip().lower()
        if fit_mode not in ("cover", "contain"):
            fit_mode = "cover"

        im = Image.open(BytesIO(data))
        try:
            im.load()
        except Exception:
            pass

        try:
            im = ImageOps.exif_transpose(im)
        except Exception:
            pass

        w, h = getattr(im, "size", (0, 0))
        if not w or not h:
            return data, mime

        target_w = int(max_w)
        target_h = int(max_h)
        if target_w <= 0 or target_h <= 0:
            return data, mime
        if not allow_upscale:
            try:
                if w <= target_w and h <= target_h:
                    return data, mime
            except Exception:
                pass

        target_ratio = target_w / float(target_h)
        src_ratio = w / float(h)

        if fit_mode == "cover":
            try:
                if src_ratio > target_ratio:
                    new_w = max(1, int(round(h * target_ratio)))
                    left = int(round((w - new_w) / 2.0))
                    im = im.crop((left, 0, left + new_w, h))
                elif src_ratio < target_ratio:
                    new_h = max(1, int(round(w / target_ratio)))
                    top = int(round((h - new_h) / 2.0))
                    im = im.crop((0, top, w, top + new_h))
            except Exception:
                pass
            try:
                im = im.resize((target_w, target_h), Image.LANCZOS)
            except Exception:
                try:
                    im = im.resize((target_w, target_h))
                except Exception:
                    pass
        else:
            try:
                use_alpha = force_png or im.mode in ("RGBA", "LA") or (im.mode == "P" and ("transparency" in getattr(im, "info", {})))

                if trim_transparent and use_alpha:
                    try:
                        probe = im.convert("RGBA") if im.mode != "RGBA" else im
                        alpha = probe.getchannel("A")
                        bbox = alpha.getbbox()
                        if bbox:
                            left, top, right, bottom = bbox
                            if (right - left) > 0 and (bottom - top) > 0:
                                im = probe.crop(bbox)
                                w, h = getattr(im, "size", (w, h))
                    except Exception:
                        pass

                scale = min(target_w / float(w), target_h / float(h))
                new_w = max(1, int(round(w * scale)))
                new_h = max(1, int(round(h * scale)))
                try:
                    fit_im = im.resize((new_w, new_h), Image.LANCZOS)
                except Exception:
                    fit_im = im.resize((new_w, new_h))

                canvas_mode = "RGBA" if use_alpha else "RGB"
                canvas_bg = (255, 255, 255, 0) if use_alpha else (255, 255, 255)
                canvas = Image.new(canvas_mode, (target_w, target_h), canvas_bg)
                paste_x = int(round((target_w - new_w) / 2.0))
                paste_y = int(round((target_h - new_h) / 2.0))
                if fit_im.mode in ("RGBA", "LA") or (fit_im.mode == "P" and ("transparency" in getattr(fit_im, "info", {}))):
                    try:
                        fit_rgba = fit_im.convert("RGBA")
                    except Exception:
                        fit_rgba = fit_im
                    canvas.paste(fit_rgba, (paste_x, paste_y), fit_rgba if canvas_mode == "RGBA" else None)
                else:
                    if canvas_mode == "RGBA" and fit_im.mode != "RGBA":
                        try:
                            fit_im = fit_im.convert("RGBA")
                        except Exception:
                            pass
                    canvas.paste(fit_im, (paste_x, paste_y))
                im = canvas
            except Exception:
                pass

        from io import BytesIO
        out = BytesIO()

        if force_png:
            out_mime = "image/png"
            try:
                if im.mode != "RGBA":
                    im = im.convert("RGBA")
            except Exception:
                pass
            try:
                im.save(out, format="PNG", optimize=True)
            except Exception:
                return data, mime
            out_bytes = out.getvalue()
            return (out_bytes, out_mime) if out_bytes else (data, mime)

        has_alpha = (
            im.mode in ("RGBA", "LA")
            or (im.mode == "P" and ("transparency" in getattr(im, "info", {})))
        )

        if has_alpha and prefer_lossy_if_opaque:
            try:
                probe = im.convert("RGBA") if im.mode != "RGBA" else im
                alpha = probe.getchannel("A")
                extrema = alpha.getextrema() or (255, 255)
                flatten_to_lossy = False

                if int(extrema[0] or 0) >= 250:
                    flatten_to_lossy = True
                else:
                    hist = alpha.histogram() or []
                    total = int(sum(hist)) if hist else 0
                    if total > 0 and len(hist) >= 256:
                        mostly_opaque_ratio = sum(hist[250:]) / float(total)
                        low_alpha_ratio = sum(hist[:245]) / float(total)
                        if mostly_opaque_ratio >= 0.995 and low_alpha_ratio <= 0.001:
                            flatten_to_lossy = True

                if flatten_to_lossy:
                    bg = Image.new("RGB", probe.size, (255, 255, 255))
                    bg.paste(probe, mask=alpha)
                    im = bg
                    has_alpha = False
            except Exception:
                pass

        webp_quality = 74 if prefer_lossy_if_opaque else 80
        jpeg_quality = 78 if prefer_lossy_if_opaque else 82

        if has_alpha:
            out_mime = "image/png"
            try:
                if im.mode != "RGBA":
                    im = im.convert("RGBA")
            except Exception:
                pass
            try:
                im.save(out, format="PNG", optimize=True)
            except Exception:
                return data, mime
        else:
            if im.mode != "RGB":
                try:
                    im = im.convert("RGB")
                except Exception:
                    pass

            out_mime = "image/webp"
            try:
                im.save(out, format="WEBP", quality=webp_quality, method=6)
            except Exception:
                out = BytesIO()
                out_mime = "image/jpeg"
                try:
                    im.save(out, format="JPEG", quality=jpeg_quality, optimize=True, progressive=True)
                except Exception:
                    return data, mime

        out_bytes = out.getvalue()
        return (out_bytes, out_mime) if out_bytes else (data, mime)
    except Exception:
        return data, mime

def _upload_debug_summary(obj) -> str:
    """Heroku logs 向けの安全な要約（生bytes/base64は絶対に出さない）"""
    try:
        if obj is None:
            return "None"
        if isinstance(obj, (bytes, bytearray, memoryview)):
            return f"{type(obj).__name__}(len={len(obj)})"
        if isinstance(obj, str):
            s = obj.strip()
            if s.startswith("data:") and "base64," in s:
                return f"str(data_url,len={len(s)})"
            return f"str(len={len(s)})"
        if isinstance(obj, dict):
            keys = list(obj.keys())
            if len(keys) > 12:
                keys = keys[:12] + ["..."]
            return f"dict(keys={keys})"
        if isinstance(obj, (list, tuple)):
            return f"{type(obj).__name__}(len={len(obj)})"
        return type(obj).__name__
    except Exception:
        return "unknown"


def _extract_upload_event_payload(e) -> dict:
    """NiceGUI upload のイベント引数の揺れ（object / dict / list）を吸収して payload を返す。

    返り値の形:
      {"name": str, "type": str, "content": Any}

    ねらい:
    - NiceGUI側のバージョン差・イベント型の差をここで吸収する
    - 後段は「content から bytes を取れるか」だけに集中できる
    """
    # list/tuple: 先頭から「それっぽい」ものを拾う
    if isinstance(e, (list, tuple)):
        for it in e:
            p = _extract_upload_event_payload(it)
            if p.get("content") is not None or p.get("name") or p.get("type"):
                return p
        return {"name": "", "type": "", "content": None}

    # dict: キー名ゆれを吸収
    if isinstance(e, dict):
        name = str(
            e.get("name")
            or e.get("filename")
            or e.get("fileName")
            or e.get("file_name")
            or ""
        ).strip()
        mime = str(
            e.get("type")
            or e.get("mime")
            or e.get("mimetype")
            or e.get("content_type")
            or ""
        ).strip()

        content = e.get("content")
        if content is None:
            content = e.get("file")
        if content is None:
            content = e.get("data")
        if content is None:
            content = e.get("bytes")

        # 入れ子（files/args/payload/value）にも対応
        if content is None:
            for k in ("files", "args", "payload", "value"):
                if k in e:
                    nested = e.get(k)
                    p = _extract_upload_event_payload(nested)
                    # 上書きできる情報があれば反映
                    if not name:
                        name = p.get("name", "") or name
                    if not mime:
                        mime = p.get("type", "") or mime
                    if p.get("content") is not None:
                        content = p.get("content")
                        break

        return {"name": name, "type": mime, "content": content}

    # object: attribute 名ゆれを吸収
    try:
        name = str(getattr(e, "name", "") or getattr(e, "filename", "") or "").strip()
        mime = str(getattr(e, "type", "") or getattr(e, "mime", "") or "").strip()

        content = getattr(e, "content", None)
        if content is None:
            content = getattr(e, "file", None)
        if content is None:
            content = getattr(e, "data", None)
        if content is None:
            # some wrappers use .files/.args/.payload/.value
            for attr in ("files", "args", "payload", "value"):
                nested = getattr(e, attr, None)
                if nested is not None:
                    p = _extract_upload_event_payload(nested)
                    if not name:
                        name = p.get("name", "") or name
                    if not mime:
                        mime = p.get("type", "") or mime
                    if p.get("content") is not None:
                        content = p.get("content")
                        break

        # それでも取れない場合は「e 自体」を content として渡す（後段で深掘り）
        if content is None:
            content = e

        return {"name": name, "type": mime, "content": content}
    except Exception:
        return {"name": "", "type": "", "content": e}


async def _read_upload_bytes(content, *, _depth: int = 0, _seen: Optional[set[int]] = None) -> bytes:
    """Upload content から bytes を確実に取り出す（同期/非同期・dict/list の揺れを吸収）。

    重要:
    - NiceGUI/Starlette の UploadFile は read() が async のことがある（= await 必須）
    - 逆に file.read() は sync のこともある
    - ここで「両方」吸収して、必ず bytes を確保する
    """
    if content is None:
        return b""
    # 再帰ループ防止
    if _seen is None:
        _seen = set()
    try:
        obj_id = id(content)
        if obj_id in _seen:
            return b""
        _seen.add(obj_id)
    except Exception:
        pass

    if _depth > 8:
        return b""
    # bytes 直
    if isinstance(content, (bytes, bytearray, memoryview)):
        return bytes(content)

    # dict
    if isinstance(content, dict):
        # よくあるキーから優先して掘る
        for k in ("content", "data", "bytes", "file", "raw", "body", "buffer"):
            if k in content:
                b = await _read_upload_bytes(content.get(k), _depth=_depth + 1, _seen=_seen)
                if b:
                    return b

        # 入れ子（files/args/payload/value）
        for k in ("files", "args", "payload", "value"):
            if k in content:
                b = await _read_upload_bytes(content.get(k), _depth=_depth + 1, _seen=_seen)
                if b:
                    return b

        return b""
    # list/tuple: 先頭から読めるものを探す
    if isinstance(content, (list, tuple)):
        for it in content:
            b = await _read_upload_bytes(it, _depth=_depth + 1, _seen=_seen)
            if b:
                return b
        return b""
    # data URL（念のため）
    try:
        if isinstance(content, str) and content.startswith("data:") and "base64," in content:
            b64 = content.split("base64,", 1)[1]
            return base64.b64decode(b64)
    except Exception:
        pass

    # 1) Prefer underlying file object (UploadFile.file 等) (sync)
    try:
        fobj = getattr(content, "file", None)
    except Exception:
        fobj = None

    if fobj is not None and hasattr(fobj, "read"):
        try:
            # seek(0) できるなら戻す（同じイベントの再読みでも事故らない）
            if hasattr(fobj, "seek"):
                try:
                    fobj.seek(0)
                except Exception:
                    pass
            data = fobj.read()
            if inspect.isawaitable(data):
                data = await data
            if isinstance(data, str):
                data = data.encode("utf-8", errors="ignore")
            if isinstance(data, (bytes, bytearray, memoryview)) and len(data) > 0:
                return bytes(data)
        except Exception:
            pass

    # 2) Try seek/read on the content itself (sync/async)
    try:
        seek_fn = getattr(content, "seek", None)
        if callable(seek_fn):
            try:
                r = seek_fn(0)
                if inspect.isawaitable(r):
                    await r
            except Exception:
                pass
    except Exception:
        pass

    try:
        read_fn = getattr(content, "read", None)
        if callable(read_fn):
            data = read_fn()
            if inspect.isawaitable(data):
                data = await data
            if isinstance(data, str):
                data = data.encode("utf-8", errors="ignore")
            if isinstance(data, (bytes, bytearray, memoryview)) and len(data) > 0:
                return bytes(data)
    except Exception:
        pass

    # 3) Known wrappers: content.value / content.body / content.buffer など
    try:
        for attr in ("value", "body", "buffer", "raw", "data"):
            v = getattr(content, attr, None)
            if v is not None and v is not content:
                b = await _read_upload_bytes(v, _depth=_depth + 1, _seen=_seen)
                if b:
                    return b
    except Exception:
        pass

    # 4) Last resort
    try:
        b = bytes(content)
        return b if b else b""
    except Exception:
        return b""


async def _upload_event_to_data_url(
    e, *, max_w: int = 0, max_h: int = 0, force_png: bool = False, fit_mode: str = "cover", trim_transparent: bool = False
) -> tuple[str, str]:
    """Upload event -> data URL（v0.6.9995 と同じ流れに戻す）.

    - event の型ゆれ（object/dict/list）を吸収
    - content から bytes を確保（sync/async 両対応）
    - bytes を max_w×max_h に中心トリミング＋リサイズ（cover方式）
    - data URL 化して返す

    NOTE:
    - 成功通知は呼び出し側で行う（場所ごとに文言を変えたい）
    """
    payload = _extract_upload_event_payload(e)
    # UI表示は短い方が安心。保存用も短縮で統一。
    fname = _short_name(payload.get("name", "") or "uploaded")
    mime = (payload.get("type") or "").strip()
    content = payload.get("content")

    # まず payload.content から読む。ダメなら e 自体も読む（古いイベント形状対策）
    data = await _read_upload_bytes(content)
    if not data:
        data = await _read_upload_bytes(e)

    if not data:
        try:
            print(
                "[UPLOAD] empty bytes",
                json.dumps(
                    {
                        "event": _upload_debug_summary(e),
                        "payload": _upload_debug_summary(payload),
                        "content": _upload_debug_summary(content),
                        "name": fname,
                        "mime": mime,
                    },
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
        try:
            ui.notify("画像の読み込みに失敗しました（JPG/PNG をお試しください）", type="warning")
        except Exception:
            pass
        return "", fname

    if len(data) > MAX_UPLOAD_BYTES:
        try:
            ui.notify("画像が大きすぎます（10MB以下にしてください）", type="warning")
        except Exception:
            pass
        return "", fname

    mime = mime or _guess_mime(fname, default="image/png")

    # Resize/crop (cover)
    if max_w and max_h:
        try:
            # PIL が重い時でも UI 全体が固まらないようにスレッドへ退避
            data, mime = await asyncio.to_thread(
                _maybe_resize_image_bytes, data, mime, max_w=max_w, max_h=max_h, force_png=force_png, fit_mode=fit_mode, trim_transparent=trim_transparent
            )
        except Exception:
            traceback.print_exc()

    try:
        b64 = base64.b64encode(data).decode("ascii")
        # 成功ログ（バイナリは出さない）
        try:
            print(
                "[UPLOAD] ok",
                json.dumps(
                    {"name": fname, "mime": mime, "bytes": len(data), "resized": bool(max_w and max_h)},
                    ensure_ascii=False,
                ),
                flush=True,
            )
        except Exception:
            pass
        return f"data:{mime};base64,{b64}", fname
    except Exception:
        traceback.print_exc()
        try:
            ui.notify("画像の読み込みに失敗しました（JPG/PNG をお試しください）", type="warning")
        except Exception:
            pass
        return "", fname
# ---------------------------
# Preview image serving (data URL -> /pv_img/<hash>)
# 目的: data URL をHTML/WS payloadに毎回乗せない（案件読込・操作を軽くする）
# ---------------------------

_PV_IMG_CACHE: "OrderedDict[str, tuple[str, bytes]]" = OrderedDict()
_PV_IMG_CACHE_MAX = 256  # safety cap

def pv_img_src(url: Optional[str], *, max_w: int = 0, max_h: int = 0, fit_mode: str = "cover", force_png: bool = False, trim_transparent: bool = False) -> str:
    """Preview用: data URL を短いURLに置き換える（巨大payload削減）。

    - builderでは、必要に応じて軽量な派生画像を返す（初回だけ生成し、その後はキャッシュ）
    - max_w/max_h を 0 にすると従来どおり元画像を使う
    """
    if not url or not isinstance(url, str):
        return url or ''
    s = url.strip()
    if not s.startswith('data:') or 'base64,' not in s:
        return s
    key_seed = f"{s}|{int(max_w or 0)}|{int(max_h or 0)}|{fit_mode}|{int(bool(force_png))}|{int(bool(trim_transparent))}"
    key = hashlib.sha1(key_seed.encode('utf-8')).hexdigest()[:24]
    if key in _PV_IMG_CACHE:
        try:
            _PV_IMG_CACHE.move_to_end(key)
        except Exception:
            pass
        return f'/pv_img/{key}'
    try:
        head, b64part = s.split('base64,', 1)
        mime = head[5:].split(';', 1)[0].strip() or 'application/octet-stream'
        data = base64.b64decode(b64part)
        if data and max_w and max_h:
            try:
                data, mime = _maybe_resize_image_bytes(
                    data,
                    mime,
                    max_w=int(max_w),
                    max_h=int(max_h),
                    force_png=force_png,
                    fit_mode=fit_mode,
                    trim_transparent=trim_transparent,
                    allow_upscale=False,
                    prefer_lossy_if_opaque=not bool(force_png),
                )
            except Exception:
                pass
        if len(_PV_IMG_CACHE) >= _PV_IMG_CACHE_MAX:
            try:
                _PV_IMG_CACHE.popitem(last=False)
            except Exception:
                _PV_IMG_CACHE.clear()
        _PV_IMG_CACHE[key] = (mime, data)
    except Exception:
        return s
    return f'/pv_img/{key}'


try:
    _pv_route_added = getattr(app, "_cvhb_pv_img_route_added", False)
except Exception:
    _pv_route_added = False

if not _pv_route_added:

    @app.get('/pv_img/{key}')
    def _pv_img_endpoint(key: str):
        item = _PV_IMG_CACHE.get(key)
        if not item:
            return Response(status_code=404)
        try:
            _PV_IMG_CACHE.move_to_end(key)
        except Exception:
            pass
        mime, data = item
        return Response(
            content=data,
            media_type=mime,
            headers={'Cache-Control': 'public, max-age=31536000, immutable'},
        )

    try:
        app._cvhb_pv_img_route_added = True
    except Exception:
        pass



# =========================
# Export ZIP download cache (v0.7.0)
# =========================

_EXPORT_ZIP_CACHE: dict[str, dict] = {}
_EXPORT_ZIP_CACHE_MAX = 10

def _build_content_disposition_attachment(filename: str) -> str:
    """Content-Disposition を安全に作る（日本語ファイル名で500にならないようにする）.
    - header は基本 ASCII が安全。非ASCIIは filename* (RFC5987) で渡す。
    - filename はフォールバック（英数字化）を入れる。
    """
    name = str(filename or "export.zip")
    # header injection / encoding trouble guard
    try:
        name = name.replace("\r", "").replace("\n", "")
    except Exception:
        pass
    try:
        name = name.replace('"', "")
    except Exception:
        pass

    # length guard (very long names can cause trouble)
    try:
        root, ext = os.path.splitext(name)
        if len(name) > 180:
            keep = max(1, 180 - len(ext))
            name = root[:keep] + ext
    except Exception:
        pass

    # ASCII fallback (safe for HTTP headers)
    try:
        fallback = re.sub(r"[^A-Za-z0-9._-]+", "_", name).strip("._")
    except Exception:
        fallback = "export"
    if not fallback:
        fallback = "export"
    # keep extension if original has it
    try:
        if name.lower().endswith(".zip") and not fallback.lower().endswith(".zip"):
            fallback = fallback + ".zip"
    except Exception:
        pass
    if not fallback.lower().endswith(".zip"):
        # safety: exported zip should end with .zip
        fallback = fallback + ".zip"

    # RFC5987 (UTF-8 percent-encoding)
    try:
        from urllib.parse import quote
        encoded = quote(name, safe="")
    except Exception:
        try:
            encoded = quote_plus(name)
        except Exception:
            encoded = ""

    if encoded:
        return f'attachment; filename="{fallback}"; filename*=UTF-8\'\'{encoded}'
    return f'attachment; filename="{fallback}"'


def _export_cache_put(user_id: int, filename: str, data: bytes) -> str:
    """生成したZIPを一時キャッシュし、ダウンロード用キーを返す。"""
    key = secrets.token_urlsafe(16)
    if len(_EXPORT_ZIP_CACHE) >= _EXPORT_ZIP_CACHE_MAX:
        # drop oldest
        try:
            oldest = sorted(_EXPORT_ZIP_CACHE.items(), key=lambda kv: kv[1].get("created_at", ""))[0][0]
            _EXPORT_ZIP_CACHE.pop(oldest, None)
        except Exception:
            _EXPORT_ZIP_CACHE.clear()
    _EXPORT_ZIP_CACHE[key] = {
        "user_id": int(user_id),
        "filename": str(filename),
        "data": data,
        "created_at": now_jst_iso(),
    }
    return key


def _register_export_zip(data: bytes, filename: str) -> str:
    """UIから生成したZIPを現在ユーザーのダウンロードキャッシュへ登録する。"""
    user_id = 0
    try:
        user = current_user()
        user_id = int(getattr(user, "id", 0) or 0) if user else 0
    except Exception:
        user_id = 0
    try:
        if isinstance(data, memoryview):
            payload = data.tobytes()
        elif isinstance(data, bytearray):
            payload = bytes(data)
        elif isinstance(data, bytes):
            payload = data
        else:
            payload = bytes(data or b"")
    except Exception:
        payload = b""
    return _export_cache_put(user_id, filename or "pageflowai2.zip", payload)


try:
    _export_route_added = getattr(app, "_cvhb_export_route_added", False)
except Exception:
    _export_route_added = False

if not _export_route_added:

    @app.get("/export_zip/{key}")
    def _export_zip_endpoint(key: str):
        user = current_user()
        item = _EXPORT_ZIP_CACHE.get(key)
        if not user or not item:
            return Response(status_code=404)
        try:
            if int(item.get("user_id") or 0) != int(user.id):
                return Response(status_code=404)
        except Exception:
            return Response(status_code=404)

        filename = str(item.get("filename") or "export.zip")
        data = item.get("data") or b""
        # Response は bytes/str 前提なので、念のため bytes に寄せる
        try:
            if isinstance(data, memoryview):
                data = data.tobytes()
            elif isinstance(data, bytearray):
                data = bytes(data)
            elif isinstance(data, str):
                data = data.encode("utf-8", errors="ignore")
            elif not isinstance(data, (bytes,)):
                data = b""
        except Exception:
            data = b""


        # Content-Disposition はASCIIのみが安全（日本語ファイル名で500になる事故を防ぐ）
        headers = {
            "Content-Disposition": _build_content_disposition_attachment(filename),
            "Cache-Control": "no-store",
        }

        try:
            resp = Response(content=data, media_type="application/zip", headers=headers)
        except Exception as ex:
            # ここで落ちると「Internal Server Error」になるため、ログだけ残して 500 を返す
            try:
                print(f"[EXPORT] response build failed: {type(ex).__name__}: {ex}")
            except Exception:
                pass
            # 失敗した場合はキャッシュを残す（リトライできるように）
            return Response(status_code=500)

        # One-time download: delete after building response (safety)
        try:
            _EXPORT_ZIP_CACHE.pop(key, None)
        except Exception:
            pass
        return resp


    try:
        app._cvhb_export_route_added = True
    except Exception:
        pass

def _preview_preflight_error() -> Optional[str]:
    """プレビュー描画前に、必要な定義が揃っているかチェックして事故を減らす。"""
    try:
        import inspect

        required = {
            "_preview_glass_style": "callable",
            "_safe_list": "callable",
            "HERO_IMAGE_PRESETS": "dict",
            "HERO_IMAGE_DEFAULT": "str",
            "HERO_IMAGE_OPTIONS": "list",
        }
        g = globals()
        for name, kind in required.items():
            if name not in g:
                return f"内部定義が見つかりません: {name}"
            v = g[name]
            if kind == "callable" and not callable(v):
                return f"内部定義が不正です: {name}（callableではありません）"
            if kind == "dict" and not isinstance(v, dict):
                return f"内部定義が不正です: {name}（dictではありません）"
            if kind == "str" and not isinstance(v, str):
                return f"内部定義が不正です: {name}（strではありません）"
            if kind == "list" and not isinstance(v, list):
                return f"内部定義が不正です: {name}（listではありません）"

        # 引数ズレ事故（unexpected keyword argument 等）を早期に検知する
        sig = inspect.signature(g["_preview_glass_style"])
        if "dark" not in sig.parameters:
            return "_preview_glass_style に dark 引数がありません"
        if not any(p.kind == inspect.Parameter.VAR_KEYWORD for p in sig.parameters.values()):
            return "_preview_glass_style は **kwargs を受け取る必要があります（互換維持のため）"

        return None
    except Exception:
        # preflight 自体が原因で落ちないようにする
        return None

