# =========================
# [BLK-03] Config
# =========================

def read_text_file(path: str, default: str = "") -> str:
    try:
        return Path(path).read_text(encoding="utf-8").strip()
    except Exception:
        return default


VERSION = read_text_file("VERSION", "1.9.17")


def detect_file_version(path: str) -> str:
    try:
        name = Path(str(path or "")).name
        m = re.search(r"main_v(\d+\.\d+\.\d+)\.py$", name)
        if m:
            return str(m.group(1) or "").strip()
        m = re.search(r"main_(\d+\.\d+\.\d+)_mirror\.py$", name)
        if m:
            return str(m.group(1) or "").strip()
    except Exception:
        pass
    return ""


CURRENT_APP_VERSION = detect_file_version(globals().get("__file__", "")) or VERSION or "1.9.17"
APP_RELEASE_VERSION = CURRENT_APP_VERSION
DESIGN_PROFILE_SCHEMA_VERSION = "1.9.schema.1"


PRODUCT_NAME = "PageFlowAI2"
BUILDER_NAME = "求人・会社ページ作成"
BUILDER_NAME_JA = "ページ作成ビルダー"
BUILDER_LABEL = f"{BUILDER_NAME}（{BUILDER_NAME_JA}）"
ASSIST_LABEL = "PageFlow Assist（AI作成補助）"
CONNECT_LABEL = "PageFlow Connect（API・外部連携）"
PUBLISH_LABEL = "PageFlow Publish（公開・書き出し）"


def _svg_data_url(svg_text: str) -> str:
    payload = base64.b64encode((svg_text or "").encode("utf-8")).decode("ascii")
    return f"data:image/svg+xml;base64,{payload}"


