def cleanup_user_storage() -> None:
    """旧バージョンで入れていた大きいデータが残ると、表示がおかしくなったり500になることがあるため掃除。"""
    try:
        # 旧キー（大きい辞書を入れていた場合）
        app.storage.user.pop("project", None)
    except Exception:
        pass


def navigate_to(path: str) -> None:
    safe_path = (path or "/").replace("'", "\'")
    try:
        ui.navigate.to(path)
        return
    except Exception:
        pass
    try:
        ui.open(path)
        return
    except Exception:
        pass
    try:
        ui.run_javascript(f"window.location.href='{safe_path}'")
    except Exception:
        pass


def clear_client_sensitive_storage_script(redirect_path: str = "/") -> str:
    safe_redirect = json.dumps(str(redirect_path or "/"))
    return f"""
(async () => {{
  try {{ localStorage.clear(); }} catch (e) {{}}
  try {{ sessionStorage.clear(); }} catch (e) {{}}
  try {{
    if (window.indexedDB && indexedDB.databases) {{
      const dbs = await indexedDB.databases();
      await Promise.all((dbs || []).map(db => db && db.name ? new Promise(resolve => {{
        const req = indexedDB.deleteDatabase(db.name);
        req.onsuccess = req.onerror = req.onblocked = () => resolve();
      }}) : Promise.resolve()));
    }}
  }} catch (e) {{}}
  try {{
    if (window.caches) {{
      const keys = await caches.keys();
      await Promise.all(keys.map(key => caches.delete(key)));
    }}
  }} catch (e) {{}}
  window.location.href = {safe_redirect};
}})();
"""


def replace_browser_url(path: str) -> None:
    try:
        safe_path = json.dumps(str(path or "/") or "/")
    except Exception:
        safe_path = '"/"'
    try:
        ui.run_javascript(
            f"""
try {{
  window.history.replaceState(window.history.state || {{}}, '', {safe_path});
}} catch (e) {{}}
"""
        )
    except Exception:
        pass


def _current_project_storage_snapshot() -> tuple[str, str]:
    try:
        project_id = str(app.storage.user.get("current_project_id") or "").strip()
    except Exception:
        project_id = ""
    try:
        project_name = str(app.storage.user.get("current_project_name") or "").strip()
    except Exception:
        project_name = ""
    return project_id, project_name


def navigate_to_builder_home(user: Optional[User] = None, *, source: str = "secondary_page_back") -> None:
    project_id, project_name = _current_project_storage_snapshot()
    viewer = user
    if viewer is None:
        try:
            viewer = current_user()
        except Exception:
            viewer = None
    cache_ready = False
    if project_id and viewer:
        try:
            cache_ready = project_cache_hit(viewer, project_id)
        except Exception:
            cache_ready = False
    if project_id and not cache_ready:
        try:
            set_pending_open_project(project_id, project_name, source=source)
        except Exception:
            pass
    navigate_to("/")


def render_secondary_page_error_state(page_name: str, user: Optional[User], lead: str, *, detail: str = "") -> None:
    with ui.element("div").classes("cvhb-container"):
        with ui.card().classes("q-pa-md rounded-borders cvhb-surface-card").props("bordered"):
            ui.label(f"{page_name}の読み込みで問題が起きました").classes("text-subtitle1")
            ui.label(str(lead or "ページの表示に失敗しました。")).classes("cvhb-muted q-mt-sm")
            if detail:
                ui.label(f"詳細: {sanitize_error_text(detail)}").classes("text-caption text-grey q-mt-sm")
            ui.label("画面全体を500にせず、この画面だけを安全に戻せる状態へ切り替えています。").classes("cvhb-muted text-caption q-mt-sm")
            with ui.row().classes("q-gutter-sm q-mt-md"):
                ui.button(f"{BUILDER_NAME}へ戻る", on_click=lambda: navigate_to_builder_home(user, source=f"{page_name}_error_back")).props("color=primary flat no-caps")
                ui.button("案件へ戻る", on_click=lambda: navigate_to("/projects")).props("flat no-caps")
                ui.button("トップへ戻る", on_click=lambda: navigate_to("/")).props("flat no-caps")


PENDING_OPEN_PROJECT_ID_KEY = "pending_open_project_id"
PENDING_OPEN_PROJECT_NAME_KEY = "pending_open_project_name"
PENDING_OPEN_STARTED_AT_KEY = "pending_open_started_at"
PENDING_OPEN_SOURCE_KEY = "pending_open_source"


def set_pending_open_project(project_id: str, project_name: str = "", *, source: str = "projects") -> None:
    try:
        app.storage.user[PENDING_OPEN_PROJECT_ID_KEY] = str(project_id or "")
        app.storage.user[PENDING_OPEN_PROJECT_NAME_KEY] = str(project_name or "")
        app.storage.user[PENDING_OPEN_STARTED_AT_KEY] = float(time.perf_counter())
        app.storage.user[PENDING_OPEN_SOURCE_KEY] = str(source or "projects")
    except Exception:
        pass


def pop_pending_open_project() -> tuple[str, str, float, str]:
    project_id = ""
    project_name = ""
    started_at = 0.0
    source = ""
    try:
        project_id = str(app.storage.user.pop(PENDING_OPEN_PROJECT_ID_KEY, "") or "")
    except Exception:
        project_id = ""
    try:
        project_name = str(app.storage.user.pop(PENDING_OPEN_PROJECT_NAME_KEY, "") or "")
    except Exception:
        project_name = ""
    try:
        started_at = float(app.storage.user.pop(PENDING_OPEN_STARTED_AT_KEY, 0.0) or 0.0)
    except Exception:
        started_at = 0.0
    try:
        source = str(app.storage.user.pop(PENDING_OPEN_SOURCE_KEY, "") or "")
    except Exception:
        source = ""
    return project_id, project_name, started_at, source


def clear_pending_open_project() -> None:
    try:
        app.storage.user.pop(PENDING_OPEN_PROJECT_ID_KEY, None)
        app.storage.user.pop(PENDING_OPEN_PROJECT_NAME_KEY, None)
        app.storage.user.pop(PENDING_OPEN_STARTED_AT_KEY, None)
        app.storage.user.pop(PENDING_OPEN_SOURCE_KEY, None)
    except Exception:
        pass


def _pending_open_elapsed_ms(started_at: float) -> int:
    try:
        if float(started_at or 0.0) <= 0:
            return 0
        return max(0, int(round((time.perf_counter() - float(started_at)) * 1000)))
    except Exception:
        return 0


def log_project_open_timing(
    user: Optional["User"],
    *,
    project_id: str,
    project_name: str = "",
    source: str = "",
    phase: str = "",
    started_at: float = 0.0,
    ok: bool = True,
    error_text: str = "",
) -> None:
    payload = {
        "project_id": str(project_id or ""),
        "project_name": str(project_name or ""),
        "source": str(source or ""),
        "phase": str(phase or ""),
        "elapsed_ms": _pending_open_elapsed_ms(started_at),
        "ok": bool(ok),
        "error": str(error_text or ""),
    }
    try:
        safe_log_action(user, "project_open_timing", json.dumps(payload, ensure_ascii=False))
    except Exception:
        pass
    try:
        print("[project_open_timing]", json.dumps(payload, ensure_ascii=False), flush=True)
    except Exception:
        pass


