def _normalize_bg_strength(value: str) -> str:
    aliases = {
        "弱": "weak",
        "中": "medium",
        "中（おすすめ）": "medium",
        "中（初期設定）": "medium",
        "中（標準・おすすめ）": "medium",
        "中（初期設定・おすすめ）": "medium",
        "強": "strong",
        "weak": "weak",
        "medium": "medium",
        "strong": "strong",
    }
    v = str(value or "").strip().lower()
    v = aliases.get(v, aliases.get(str(value or "").strip(), v))
    return v if v in BG_STRENGTH_OPTIONS else "medium"


