def build_completed_hp_design_profile(step1: Optional[dict]) -> dict:
    src = step1 if isinstance(step1, dict) else {}
    primary = str(src.get("primary_color") or "blue").strip() or "blue"
    primary = COLOR_MIGRATION.get(primary, primary)
    if primary not in COLOR_OPTIONS:
        primary = "blue"
    bg_strength = _normalize_bg_strength(src.get("bg_strength") or "medium")
    bg_motion = _normalize_bg_motion(src.get("bg_motion") or "medium")
    ui_strength = _normalize_ui_strength(src.get("ui_strength") or bg_strength or "medium")
    ui_motion = _normalize_ui_motion(src.get("ui_motion") or bg_motion or "medium")
    profile_id = f"completed_hp_uiux_v1-{primary}-{bg_strength}-{bg_motion}-{ui_strength}-{ui_motion}"
    return {
        "schema_version": DESIGN_PROFILE_SCHEMA_VERSION,
        "app_version": APP_RELEASE_VERSION,
        "profile_namespace": "completed_hp_uiux_v1",
        "profile_id": profile_id,
        "layout_profile": "pv_layout_260218",
        "safe_change_scope": "uiux_only",
        "primary_color": primary,
        "background_strength": bg_strength,
        "background_motion": bg_motion,
        "ui_strength": ui_strength,
        "ui_motion": ui_motion,
        "supports_future_bulk_design_switch": True,
    }


