def audit_static_site_release_integrity(files: dict[str, bytes], *, expected_version: str = APP_RELEASE_VERSION, raise_on_error: bool = False) -> dict:
    expected_version = str(expected_version or APP_RELEASE_VERSION).strip() or APP_RELEASE_VERSION

    def _decode(path: str) -> str:
        raw = files.get(path) or b""
        try:
            if isinstance(raw, bytes):
                return raw.decode("utf-8", errors="replace")
            return str(raw or "")
        except Exception:
            return ""

    index_html = _decode("index.html")
    privacy_html = _decode("privacy.html")
    news_index_html = _decode("news/index.html")
    recruitment_html = _decode(RECRUITMENT_PAGE_PATH)
    recruitment_jobposting_json = _decode(RECRUITMENT_JOBPOSTING_JSON_PATH)
    recruitment_distribution_json = _decode(RECRUITMENT_DISTRIBUTION_JSON_PATH)
    recruitment_indeed_xml = _decode(RECRUITMENT_INDEED_FEED_PATH)
    sitemap_xml = _decode(SITE_SITEMAP_PATH)
    robots_txt = _decode(SITE_ROBOTS_PATH)
    site_css = _decode("assets/site.css")
    site_js = _decode("assets/site.js")
    version_json = _decode("assets/site.version.json")
    design_json = _decode("assets/site.design.json")

    manifest = {}
    try:
        manifest = json.loads(version_json) if version_json else {}
    except Exception:
        manifest = {}
    distribution_manifest = _json_loads_bytes(recruitment_distribution_json, default={})

    flags = manifest.get("flags") if isinstance(manifest, dict) else {}
    if not isinstance(flags, dict):
        flags = {}
    public_urls = distribution_manifest.get("public_urls") if isinstance(distribution_manifest.get("public_urls"), dict) else {}
    public_url_configured = bool(
        flags.get("public_site_url_configured")
        or distribution_manifest.get("public_site_base_url")
        or public_urls.get("recruitment_page")
    )

    lazy_map_required = bool(
        flags.get("has_lazy_map_target")
        or ('pv-mapframe-live' in index_html)
        or ('data-pv-map-src=' in index_html)
    )
    recruitment_required = bool(
        flags.get("recruitment_visible")
        or ('id="pv-recruitment"' in index_html)
        or ('href="#pv-recruitment"' in index_html)
        or ('href="index.html#pv-recruitment"' in index_html)
        or (RECRUITMENT_PAGE_PATH in index_html)
        or bool(recruitment_html)
    )

    hero_slide_count = index_html.count('class="pv-hero-slide"')
    checks = {
        "has_index_html": bool(index_html),
        "has_site_css": "assets/site.css" in files,
        "has_site_js": "assets/site.js" in files,
        "has_split_js": all(name in files for name in ["assets/site.hero.js", "assets/site.contact.js", "assets/site.reveal.js", "assets/site.map.js"]),
        "has_design_json": bool(design_json),
        "has_version_json": bool(version_json),
        "css_version_match": f"assets/site.css?v={expected_version}" in index_html,
        "js_version_match": f"assets/site.js?v={expected_version}" in index_html,
        "footer_version_match": f"{PRODUCT_NAME} {expected_version}" in index_html,
        "root_app_version_attr": f'data-pv-app-version="{expected_version}"' in index_html,
        "hero_full_bleed_marker": ('data-pv-hero-fullbleed="1"' in index_html and 'pv-hero-fullbleed' in index_html),
        "hero_slide_count_ok": (1 <= hero_slide_count <= 2),
        "hero_cover_css": ('object-fit: cover !important;' in site_css and 'pv-hero-img' in site_css),
        "hero_width_match_css": ('pv-hero-slider-wide' in site_css and 'aspect-ratio: 16 / 9;' in site_css and 'height: auto;' in site_css and 'width: 100vw;' in site_css and 'width="1280" height="720"' in index_html),
        "lazy_map_marker": ('data-pv-map-src=' in index_html) if lazy_map_required else True,
        "translate_lock_html": ('translate="no"' in index_html and 'notranslate' in index_html and 'Content-Language' in index_html and 'google" content="notranslate"' in index_html),
        "translate_lock_subpages": ((not privacy_html or 'translate="no"' in privacy_html) and (not news_index_html or 'translate="no"' in news_index_html)),
        "translate_lock_css": '.goog-te-banner-frame.skiptranslate' in site_css,
        "recruitment_badge_fixed": (RECRUITMENT_BADGE_DEFAULT in index_html) if recruitment_required else True,
        "recruitment_page_exists": bool(recruitment_html) if recruitment_required else True,
        "recruitment_page_version_match": (f"site.css?v={expected_version}" in recruitment_html and f"site.js?v={expected_version}" in recruitment_html) if recruitment_html else True,
        "recruitment_page_footer_version": (f"{PRODUCT_NAME} {expected_version}" in recruitment_html) if recruitment_html else True,
        "recruitment_page_translate_lock": ((not recruitment_html) or ('translate="no"' in recruitment_html and 'notranslate' in recruitment_html and 'Content-Language' in recruitment_html and 'google" content="notranslate"' in recruitment_html)),
        "recruitment_jobposting_json_exists": bool(recruitment_jobposting_json) if recruitment_required else True,
        "recruitment_distribution_json_exists": bool(recruitment_distribution_json) if recruitment_required else True,
        "recruitment_indeed_feed_exists": bool(recruitment_indeed_xml) if recruitment_required else True,
        "sitemap_exists": bool(sitemap_xml) if public_url_configured else True,
        "robots_exists": bool(robots_txt) if public_url_configured else True,
        "manifest_version_match": str(manifest.get("app_version") or "") == expected_version,
        "design_manifest_profile": bool(manifest.get("design_profile_id")),
        "bootstrap_mentions_modules": all(name in site_js for name in ["site.hero.js", "site.contact.js", "site.reveal.js", "site.map.js"]),
        "lazy_map_required": lazy_map_required,
        "recruitment_required": recruitment_required,
        "public_url_configured": public_url_configured,
    }
    critical = [
        "has_index_html",
        "has_site_css",
        "has_site_js",
        "has_split_js",
        "has_design_json",
        "has_version_json",
        "css_version_match",
        "js_version_match",
        "footer_version_match",
        "root_app_version_attr",
        "hero_full_bleed_marker",
        "hero_slide_count_ok",
        "hero_cover_css",
        "hero_width_match_css",
        "translate_lock_html",
        "translate_lock_subpages",
        "translate_lock_css",
        "manifest_version_match",
    ]
    if lazy_map_required:
        critical.append("lazy_map_marker")
    if recruitment_required:
        critical.extend([
            "recruitment_badge_fixed",
            "recruitment_page_exists",
            "recruitment_page_version_match",
            "recruitment_page_footer_version",
            "recruitment_page_translate_lock",
            "recruitment_jobposting_json_exists",
            "recruitment_distribution_json_exists",
            "recruitment_indeed_feed_exists",
        ])
    if public_url_configured:
        critical.extend([
            "sitemap_exists",
            "robots_exists",
        ])
    audit = {
        "expected_version": expected_version,
        "checks": checks,
        "critical_failed": [k for k in critical if not checks.get(k)],
    }
    if raise_on_error and audit["critical_failed"]:
        raise RuntimeError("static site release integrity failed: " + ", ".join(audit["critical_failed"]))
    return audit


def audit_recruitment_page_quality(files: dict[str, bytes], *, expected_version: str = APP_RELEASE_VERSION, raise_on_error: bool = False) -> dict:
    expected_version = str(expected_version or APP_RELEASE_VERSION).strip() or APP_RELEASE_VERSION

    def _decode(path: str) -> str:
        raw = files.get(path) or b""
        try:
            if isinstance(raw, bytes):
                return raw.decode("utf-8", errors="replace")
            return str(raw or "")
        except Exception:
            return ""

    index_html = _decode("index.html")
    recruit_html = _decode(RECRUITMENT_PAGE_PATH)
    recruitment_jobposting_json = _decode(RECRUITMENT_JOBPOSTING_JSON_PATH)
    recruitment_distribution_json = _decode(RECRUITMENT_DISTRIBUTION_JSON_PATH)
    recruitment_indeed_xml = _decode(RECRUITMENT_INDEED_FEED_PATH)
    sitemap_xml = _decode(SITE_SITEMAP_PATH)
    robots_txt = _decode(SITE_ROBOTS_PATH)
    if not recruit_html:
        audit = {
            "expected_version": expected_version,
            "page_path": RECRUITMENT_PAGE_PATH,
            "section_scores": {sid: 0 for sid, _title, _en in RECRUITMENT_PAGE_SECTION_DEFS},
            "checks": {"page_exists": False},
            "critical_failed": ["page_exists"],
            "all_sections_ge_95": False,
        }
        if raise_on_error:
            raise RuntimeError("recruitment page audit failed: page_exists")
        return audit

    def _has(text: str) -> bool:
        return text in recruit_html

    distribution_manifest = _json_loads_bytes(recruitment_distribution_json, default={})
    public_urls = distribution_manifest.get("public_urls") if isinstance(distribution_manifest.get("public_urls"), dict) else {}
    public_url_configured = bool(distribution_manifest.get("public_site_base_url") or public_urls.get("recruitment_page"))

    section_scores: dict[str, int] = {}
    section_checks: dict[str, dict] = {}
    accordion_count = recruit_html.count('class="pv-job-accordion"')
    nav_button_count = recruit_html.count('class="pv-job-nav-btn"')
    highlight_count = recruit_html.count('class="pv-job-highlight"')
    apply_button_count = recruit_html.count('pv-job-apply')
    footer_cta_count = index_html.count('pv-footer-cta-row')

    for sid, title, _en in RECRUITMENT_PAGE_SECTION_DEFS:
        has_id = _has(f'id="{sid}"')
        has_title = _has(title)
        has_nav = _has(f'href="#{sid}"')
        requires_details = sid not in {"job-overview", "job-highlights", "job-contact"}
        has_details = (not requires_details) or _has(f'data-job-section="{sid}"') or _has(f'data-job-accordion="{sid}"') or _has(f'data-job-detail-for="{sid}"') or (sid == "job-faq" and 'class="pv-job-faq-item"' in recruit_html)
        score = 0
        if has_id:
            score += 55
        if has_title:
            score += 20
        if has_nav:
            score += 10
        if has_details:
            score += 15
        section_scores[sid] = score
        section_checks[sid] = {
            "has_id": has_id,
            "has_title": has_title,
            "has_nav": has_nav,
            "has_details": has_details,
        }

    checks = {
        "page_exists": True,
        "index_header_cta_to_recruitment": (RECRUITMENT_PAGE_PATH in index_html and RECRUITMENT_BADGE_DEFAULT in index_html),
        "index_footer_cta_to_recruitment": ('pv-footer-cta-row' in index_html and RECRUITMENT_PAGE_PATH in index_html),
        "page_version_match": (f"site.css?v={expected_version}" in recruit_html and f"site.js?v={expected_version}" in recruit_html),
        "translate_lock": ('translate="no"' in recruit_html and 'notranslate' in recruit_html and 'Content-Language' in recruit_html and 'google" content="notranslate"' in recruit_html),
        "section_nav_count_ok": nav_button_count >= len(RECRUITMENT_PAGE_SECTION_DEFS),
        "accordion_count_ok": accordion_count >= 6,
        "highlight_count_ok": highlight_count >= 4,
        "apply_button_count_ok": apply_button_count >= 3,
        "footer_cta_count_ok": footer_cta_count >= 1,
        "contact_panel_present": ('job-contact' in recruit_html and ('mailto:' in recruit_html or 'index.html#pv-access-contact' in recruit_html or 'data-job-apply-href' in recruit_html or 'https://' in recruit_html)),
        "jobposting_json_present": bool(recruitment_jobposting_json),
        "distribution_json_present": bool(recruitment_distribution_json),
        "indeed_feed_present": bool(recruitment_indeed_xml),
        "sitemap_present": bool(sitemap_xml) if public_url_configured else True,
        "robots_present": bool(robots_txt) if public_url_configured else True,
    }
    critical_failed = [k for k, v in checks.items() if not v]
    for sid, score in section_scores.items():
        if score < RECRUITMENT_SECTION_MIN_SCORE:
            critical_failed.append(f"section_score:{sid}")
    audit = {
        "expected_version": expected_version,
        "page_path": RECRUITMENT_PAGE_PATH,
        "checks": checks,
        "section_checks": section_checks,
        "section_scores": section_scores,
        "all_sections_ge_95": all(score >= RECRUITMENT_SECTION_MIN_SCORE for score in section_scores.values()),
        "critical_failed": critical_failed,
    }
    if raise_on_error and critical_failed:
        raise RuntimeError("recruitment page audit failed: " + ", ".join(critical_failed))
    return audit

ROOT_PAGE_AUDIT_MIN_SCORE = 95
ROOT_PAGE_AUDIT_ITEMS = [
    ("hero", "ヒーロー"),
    ("header_nav_primary_cta", "ヘッダー/主CTA"),
    ("background_depth", "背景/奥行き"),
    ("philosophy_about", "理念/概要"),
    ("recruitment", "求人"),
    ("news", "お知らせ"),
    ("faq", "FAQ"),
    ("access_contact", "アクセス/問い合わせ"),
    ("footer_trust", "フッター/信頼感"),
    ("image_typography_layout_coherence", "画像/文字/余白一貫性"),
]


def audit_root_page_quality(files: dict[str, bytes], *, expected_version: str = APP_RELEASE_VERSION, raise_on_error: bool = False) -> dict:
    expected_version = str(expected_version or APP_RELEASE_VERSION).strip() or APP_RELEASE_VERSION

    def _decode(path: str) -> str:
        raw = files.get(path) or b""
        try:
            if isinstance(raw, bytes):
                return raw.decode("utf-8", errors="replace")
            return str(raw or "")
        except Exception:
            return ""

    index_html = _decode("index.html")
    site_css = _decode("assets/site.css")
    site_js = _decode("assets/site.js")
    site_hero_js = _decode("assets/site.hero.js")
    js_all = site_js + "\n" + site_hero_js
    scores: dict[str, int] = {}
    checks: dict[str, dict] = {}
    slide_count = index_html.count('class="pv-hero-slide"')

    item_checks = {
        "hero": {
            "full_bleed": ('data-pv-hero-fullbleed="1"' in index_html and 'calc(50% - 50vw)' in site_css),
            "width_matched": ('pv-hero-slider-wide' in site_css and 'aspect-ratio: 16 / 9;' in site_css and 'height: auto;' in site_css and 'width: 100vw;' in site_css and 'width="1280" height="720"' in index_html),
            "slide_budget": (1 <= slide_count <= 2),
            "left_caption": ('left: clamp(24px, 6vw, 84px);' in site_css and 'pv-hero-caption-title' in index_html),
        },
        "header_nav_primary_cta": {
            "badge_cta": (RECRUITMENT_BADGE_DEFAULT in index_html and RECRUITMENT_PAGE_PATH in index_html),
            "desktop_nav": ('class="row pv-desktop-nav items-center no-wrap"' in index_html),
            "topbar_polish": ('pv-topbar-260218.is-compact' in site_css and 'syncTopbarCompact' in js_all),
        },
        "background_depth": {
            "surface_gradients": ('radial-gradient(' in site_css and '--pv-panel-guard' in site_css),
            "hero_overlay": ('pv-hero-caption' in site_css and 'linear-gradient(180deg, rgba(255,255,255,0.34)' in site_css),
        },
        "philosophy_about": {
            "about_grid": ('class="pv-about-grid"' in index_html and 'grid-template-columns: minmax(0, 1.02fr) minmax(320px, 0.98fr);' in site_css),
            "points": ('class="pv-points"' in index_html),
            "services": ('class="pv-services-grid"' in index_html and 'grid-template-columns: minmax(0, 0.96fr) minmax(320px, 1.04fr);' in site_css),
        },
        "recruitment": {
            "dedicated_page": (RECRUITMENT_PAGE_PATH in files),
            "header_cta": (RECRUITMENT_PAGE_PATH in index_html and RECRUITMENT_BADGE_DEFAULT in index_html),
            "footer_cta": ('pv-footer-cta-row' in index_html and RECRUITMENT_PAGE_PATH in index_html),
        },
        "news": {
            "news_section": ('id="pv-news"' in index_html),
            "paired_layout": ('pv-home-pair-newsfaq' in index_html and 'pv-home-pair-newsfaq' in site_css),
        },
        "faq": {
            "faq_section": ('id="pv-faq"' in index_html),
            "paired_layout": ('pv-home-pair-newsfaq' in index_html and 'pv-faq-list' in index_html),
        },
        "access_contact": {
            "section": ('id="pv-access-contact"' in index_html),
            "grid": ('class="pv-access-grid pv-access-contact-grid"' in index_html or 'class="pv-access-grid"' in index_html),
            "contact_card": ('pv-contact-card' in index_html),
        },
        "footer_trust": {
            "company_name": ('pv-footer-company-name' in index_html),
            "company_meta": ('pv-footer-company-meta' in index_html and 'pv-footer-company-meta' in site_css),
            "cta_row": ('pv-footer-cta-row' in index_html),
        },
        "image_typography_layout_coherence": {
            "brand": ('pv-brand-logo' in index_html or 'pv-brand-name' in index_html),
            "hero_fit_js": ('fitHeroCaption' in js_all),
            "footer_fit_js": ('fitFooterLinks' in js_all),
        },
    }

    critical_failed: list[str] = []
    for key, _label in ROOT_PAGE_AUDIT_ITEMS:
        subset = item_checks.get(key, {})
        hit = sum(1 for v in subset.values() if v)
        total = max(1, len(subset))
        score = int(round((hit / total) * 100))
        scores[key] = score
        checks[key] = subset
        if score < ROOT_PAGE_AUDIT_MIN_SCORE:
            critical_failed.append(f"root_score:{key}")

    audit = {
        "expected_version": expected_version,
        "page_path": "index.html",
        "scores": scores,
        "section_checks": checks,
        "all_scores_ge_95": all(score >= ROOT_PAGE_AUDIT_MIN_SCORE for score in scores.values()),
        "critical_failed": critical_failed,
    }
    if raise_on_error and critical_failed:
        raise RuntimeError("root page audit failed: " + ", ".join(critical_failed))
    return audit


def audit_static_perf_budget(files: dict[str, bytes], *, expected_version: str = APP_RELEASE_VERSION, raise_on_error: bool = False) -> dict:
    expected_version = str(expected_version or APP_RELEASE_VERSION).strip() or APP_RELEASE_VERSION

    def _size(path: str) -> int:
        raw = files.get(path) or b""
        try:
            if isinstance(raw, bytes):
                return len(raw)
            return len(str(raw or "").encode("utf-8", errors="ignore"))
        except Exception:
            return 0

    def _decode(path: str) -> str:
        raw = files.get(path) or b""
        try:
            if isinstance(raw, bytes):
                return raw.decode("utf-8", errors="replace")
            return str(raw or "")
        except Exception:
            return ""

    index_html = _decode("index.html")
    recruit_html = _decode(RECRUITMENT_PAGE_PATH)
    site_js = _size("assets/site.js")
    site_css = _size("assets/site.css")
    split_total = sum(_size(p) for p in ["assets/site.hero.js", "assets/site.contact.js", "assets/site.reveal.js", "assets/site.map.js"])
    hero_slide_count = index_html.count('class="pv-hero-slide"')
    checks = {
        "bootstrap_js_bytes_ok": site_js <= 24000,
        "site_css_bytes_ok": site_css <= 150000,
        "split_modules_total_bytes_ok": split_total <= 42000,
        "index_html_bytes_ok": _size("index.html") <= 90000,
        "recruitment_html_bytes_ok": (_size(RECRUITMENT_PAGE_PATH) <= 95000) if recruit_html else True,
        "hero_slide_budget_ok": (1 <= hero_slide_count <= 2),
        "no_eager_map_iframe": ('class="pv-map-iframe"' not in index_html),
        "split_js_present": all(name in files for name in ["assets/site.hero.js", "assets/site.contact.js", "assets/site.reveal.js", "assets/site.map.js"]),
    }
    audit = {
        "expected_version": expected_version,
        "budgets": {
            "site_js_bytes": site_js,
            "site_css_bytes": site_css,
            "split_modules_total_bytes": split_total,
            "index_html_bytes": _size("index.html"),
            "recruitment_html_bytes": _size(RECRUITMENT_PAGE_PATH),
            "hero_slide_count": hero_slide_count,
        },
        "checks": checks,
        "critical_failed": [k for k, v in checks.items() if not v],
    }
    if raise_on_error and audit["critical_failed"]:
        raise RuntimeError("static perf budget failed: " + ", ".join(audit["critical_failed"]))
    return audit


def audit_builder_runtime_contract(source_text: Optional[str] = None, *, expected_version: str = APP_RELEASE_VERSION, raise_on_error: bool = False) -> dict:
    expected_version = str(expected_version or APP_RELEASE_VERSION).strip() or APP_RELEASE_VERSION
    src = str(source_text or "")
    checks = {
        "source_available": bool(src),
        "preview_theme_delta": ('window.cvhbPreviewApplyThemeDelta' in src),
        "preview_mode_delta": ('window.cvhbPreviewSetMode' in src),
        "preview_follow_scroll": ('window.cvhbPreviewScrollTo' in src),
        "project_open_timing": ('project_open_timing' in src),
        "projects_help_safe": ('if HELP_MODE or not _tenant_admin_db_ready()' in src),
        "company_list_cache": ('_COMPANY_LIST_CACHE' in src and '_company_list_cache_get' in src),
        "tenant_scope_company_options_cache": ('_TENANT_SCOPE_COMPANY_OPTIONS_CACHE' in src and '_tenant_scope_company_options_cache_get' in src),
        "tenant_hierarchy_permissions": ('is_tenant_subadmin' in src and 'can_issue_tenant_role' in src and 'can_manage_target_user' in src),
        "recruitment_badge_fixed": (f'RECRUITMENT_BADGE_DEFAULT = "{RECRUITMENT_BADGE_DEFAULT}"' in src),
    }
    score_weights = {
        "preview_theme_delta": 14,
        "preview_mode_delta": 14,
        "preview_follow_scroll": 12,
        "project_open_timing": 12,
        "projects_help_safe": 12,
        "company_list_cache": 12,
        "tenant_scope_company_options_cache": 10,
        "tenant_hierarchy_permissions": 14,
        "recruitment_badge_fixed": 12,
    }
    score = sum(weight for key, weight in score_weights.items() if checks.get(key))
    audit = {
        "expected_version": expected_version,
        "checks": checks,
        "score": score,
        "critical_failed": [key for key in score_weights if not checks.get(key)],
    }
    if raise_on_error and audit["critical_failed"]:
        raise RuntimeError("builder runtime contract failed: " + ", ".join(audit["critical_failed"]))
    return audit


def audit_product_release_readiness(files: dict[str, bytes], *, source_text: Optional[str] = None, expected_version: str = APP_RELEASE_VERSION, raise_on_error: bool = False) -> dict:
    expected_version = str(expected_version or APP_RELEASE_VERSION).strip() or APP_RELEASE_VERSION
    site_audit = audit_static_site_release_integrity(files, expected_version=expected_version, raise_on_error=False)
    root_audit = audit_root_page_quality(files, expected_version=expected_version, raise_on_error=False)
    recruit_audit = audit_recruitment_page_quality(files, expected_version=expected_version, raise_on_error=False) if RECRUITMENT_PAGE_PATH in files else {}
    perf_audit = audit_static_perf_budget(files, expected_version=expected_version, raise_on_error=False)
    builder_audit = audit_builder_runtime_contract(source_text=source_text, expected_version=expected_version, raise_on_error=False)
    critical_failed: list[str] = []
    critical_failed.extend([f"site:{k}" for k in site_audit.get("critical_failed", [])])
    critical_failed.extend([f"root:{k}" for k in root_audit.get("critical_failed", [])])
    critical_failed.extend([f"recruitment:{k}" for k in recruit_audit.get("critical_failed", [])])
    critical_failed.extend([f"perf:{k}" for k in perf_audit.get("critical_failed", [])])
    critical_failed.extend([f"builder:{k}" for k in builder_audit.get("critical_failed", [])])
    audit = {
        "expected_version": expected_version,
        "site": site_audit,
        "root": root_audit,
        "recruitment": recruit_audit,
        "perf": perf_audit,
        "builder": builder_audit,
        "product_ready": not bool(critical_failed),
        "critical_failed": critical_failed,
    }
    if raise_on_error and critical_failed:
        raise RuntimeError("product release gate failed: " + ", ".join(critical_failed))
    return audit


def _normalize_preview_light_images(value) -> bool:
    try:
        if isinstance(value, bool):
            return value
        s = str(value).strip().lower()
        if s in {"0", "false", "off", "no", "n", "heavy", "full", "75", "75%"}:
            return False
        if s in {"1", "true", "on", "yes", "y", "light", "10", "10%", "25", "25%", ""}:
            return True
    except Exception:
        return True
    return True


