    def _plain_text(*parts: str) -> str:
        buf = []
        for part in parts:
            s = str(part or "").strip()
            if s:
                buf.append(re.sub(r"\s+", " ", s))
        return "\n\n".join(buf)

    def _iso_date_only(value: str) -> str:
        dt = parse_iso_datetime(str(value or ""))
        if dt:
            return to_jst(dt).date().isoformat()
        m = re.match(r"^(\d{4}-\d{2}-\d{2})", str(value or "").strip())
        return m.group(1) if m else ""

