if not getattr(app, "_pf2_live_preview_route_added", False):
    @app.get("/pf2/live-preview/{project_id}/{file_path:path}")
    def _pf2_live_preview_endpoint(project_id: str, file_path: str, preview: str = "", light: str = "", focus: str = ""):
        headers = _pf2_live_preview_headers()
        pid = pf2_text(project_id)
        safe_path = _pf2_safe_preview_file_path(file_path)
        if not pid or not safe_path:
            return Response(
                content=_pf2_live_preview_message_html("表示できません", "プレビューの指定が正しくありません。"),
                status_code=404,
                media_type="text/html",
                headers=headers,
            )
        p = pf2_local_get_project(pid)
        if not p:
            return Response(
                content=_pf2_live_preview_message_html("案件が見つかりません", "保存済みの案件を開くと、ここに実際のページが表示されます。"),
                status_code=404,
                media_type="text/html",
                headers=headers,
            )
        try:
            active_preview_job_id = pf2_active_job_id_for_project(p)
            preview_project = pf2_apply_job_to_project(p, pf2_job_from_project(p, active_preview_job_id))
            files = build_pageflowai2_site_files(preview_project)
        except Exception:
            return Response(
                content=_pf2_live_preview_message_html("プレビューを作成できません", "入力内容に確認が必要な項目があります。保存内容を確認してからもう一度開いてください。"),
                status_code=200,
                media_type="text/html",
                headers=headers,
            )
        target_path = safe_path
        if target_path.endswith("/"):
            target_path = f"{target_path}index.html"
        if target_path not in files and not target_path.endswith("/index.html"):
            alt_path = f"{target_path.rstrip('/')}/index.html"
            if alt_path in files:
                target_path = alt_path
        if target_path not in files:
            if target_path.endswith(".html"):
                return Response(
                    content=_pf2_live_preview_message_html("まだページがありません", "職種名や会社紹介を入力して保存すると、ここに実際のページが表示されます。"),
                    status_code=200,
                    media_type="text/html",
                    headers=headers,
                )
            return Response(content=b"", status_code=404, media_type="text/plain", headers=headers)
        media_type = mimetypes.guess_type(target_path)[0] or "application/octet-stream"
        content = _pf2_apply_live_preview_mode(files[target_path], media_type=media_type, preview=preview, light=light, focus=focus)
        return Response(content=content, media_type=media_type, headers=headers)

    app._pf2_live_preview_route_added = True


def build_site_zip_filename(p: dict, *, dt: Optional[datetime] = None) -> str:
    """書き出しZIPのファイル名を生成する。

    形式: YYMMDD_案件名_site.zip
    例: 260223_テスト4_site.zip

    ※ 同日に同名バックアップが既にある場合は、保存側で _2, _3 ... を付けて上書きを避ける。
    """
    try:
        p = normalize_project(p)
    except Exception:
        p = p if isinstance(p, dict) else {}

    if dt is None:
        dt = datetime.now(JST)

    date_prefix = dt.strftime("%y%m%d")

    try:
        name = str(p.get("project_name") or "").strip()
    except Exception:
        name = ""

    if not name or name == "(no name)":
        try:
            name = str(p.get("project_id") or "project").strip()
        except Exception:
            name = "project"

    safe_name = _safe_filename(name)
    # 長すぎると扱いにくいので、ほどほどに制限
    try:
        safe_name = safe_name[:40]
    except Exception:
        pass
    safe_name = safe_name or "project"

    return f"{date_prefix}_{safe_name}_site.zip"



def _normalize_static_site_files(files: dict) -> dict[str, bytes]:
    """静的サイト生成の戻り値を ZIP へ安全に入れられる形（bytes）に正規化する。"""
    out: dict[str, bytes] = {}
    if not isinstance(files, dict):
        return out

    for k, v in files.items():
        if k is None:
            continue
        path = str(k)
        if v is None:
            out[path] = b""
            continue
        try:
            if isinstance(v, bytes):
                out[path] = v
            elif isinstance(v, bytearray):
                out[path] = bytes(v)
            elif isinstance(v, memoryview):
                out[path] = v.tobytes()
            elif isinstance(v, str):
                out[path] = v.encode("utf-8")
            else:
                # 最後の手段（壊れた型が混ざっても落とさない）
                out[path] = str(v).encode("utf-8", errors="ignore")
        except Exception:
            out[path] = b""
    return out


def _static_site_selfcheck(p: dict, files: dict[str, bytes]) -> None:
    """書き出しZIPが「納品物として成立するか」を最低限チェックする。

    ここで落ちる場合は、利用者の入力ミスではなく「内部の組み立てバグ」を想定。
    """
    required = [
        "index.html",
        "privacy.html",
        "assets/site.css",
        "assets/site.js",
        "news/index.html",
    ]
    missing = [k for k in required if k not in files]
    if missing:
        raise RuntimeError("内部エラー: 書き出しに必要なファイルが不足しています: " + ", ".join(missing))

    # index.html が「pv-layout-260218」を使っているか（プレビュー基準になっているか）
    try:
        idx = files.get("index.html", b"").decode("utf-8", errors="ignore")
        if "pv-layout-260218" not in idx:
            raise RuntimeError("内部エラー: index.html がプレビュー基準のテンプレになっていません（pv-layout-260218 が未検出）")
    except RuntimeError:
        raise
    except Exception:
        # decode に失敗しても、ここでは落とさない
        pass

    # contact.php 同梱（PHPフォーム方式のときだけ必須）
    try:
        contact_mode = ""
        data = p.get("data") if isinstance(p, dict) else {}
        blocks = data.get("blocks") if isinstance(data, dict) else {}
        contact = blocks.get("contact") if isinstance(blocks, dict) else {}
        contact_mode = _normalize_contact_form_mode(str(contact.get("form_mode") or contact.get("mode") or ""))
    except Exception:
        contact_mode = ""

    if contact_mode == "php":
        required_php = [
            "contact.php",
            "thanks.html",
            "config/config.php",
        ]
        missing_php = [k for k in required_php if k not in files]
        if missing_php:
            raise RuntimeError("内部エラー: PHPフォーム同梱ファイルが不足しています: " + ", ".join(missing_php))


def build_site_zip_bytes(p: dict) -> tuple[bytes, str]:
    """静的サイト一式をZIP化して返す。

    - 書き出しは「納品物」なので、途中で失敗したら黙って欠けたZIPを出さず、必ず失敗として扱う。
    - ただしアプリ全体は落とさない（呼び出し側で try/except して notify する）。
    """
    p = normalize_project(p)

    # 1) 静的ファイル生成
    files_raw = build_static_site_files(p)
    files = _normalize_static_site_files(files_raw)

    # 2) 最低限の自己診断（壊れたZIPを出さない）
    _static_site_selfcheck(p, files)

    # 3) ZIP作成
    mem = BytesIO()
    write_errors: list[str] = []
    with zipfile.ZipFile(mem, "w", compression=zipfile.ZIP_DEFLATED) as z:
        for path, content in files.items():
            try:
                z.writestr(path, content)
            except Exception as ex:
                # ここで握りつぶすと「欠けた納品物」になるので、エラーとして保持する
                write_errors.append(f"{path} ({type(ex).__name__})")

    if write_errors:
        # 先頭だけ表示（長すぎるとUIに収まらない）
        head = ", ".join(write_errors[:8])
        tail = " ..." if len(write_errors) > 8 else ""
        raise RuntimeError("ZIPに含めるファイルの書き込みに失敗しました: " + head + tail)

    filename = build_site_zip_filename(p)
    return mem.getvalue(), filename




def _save_site_zip_backup_to_project__base_13784(p: dict, actor: User, zip_bytes: bytes, filename: str) -> str:
    """書き出しZIPを案件内（SFTP To Go）へバックアップ保存する。

    - デフォルト名: YYMMDD_案件名_site.zip
    - 既に同名がある場合は _2, _3 ... を付けて上書き事故を避ける
    """
    p = normalize_project(p)
    pid = str(p.get("project_id") or "project")

    desired = str(filename or "").strip() or build_site_zip_filename(p)

    # ファイル名を安全にする（日本語OKだが、念のため危険文字だけ置換）
    base = _safe_filename(Path(desired).stem) or "backup"
    try:
        base = base[:80]
    except Exception:
        pass

    remote_dir = f"{project_dir(pid)}/backups"

    with sftp_client() as sftp:
        # 同名があるなら _2, _3... を付与（同日に複数保存しても上書きしない）
        cand = f"{base}.zip"
        for i in range(2, 100):
            try:
                sftp.stat(f"{remote_dir}/{cand}")
                cand = f"{base}_{i}.zip"
                continue
            except Exception:
                break

        remote_path = f"{remote_dir}/{cand}"
        sftp_write_bytes(sftp, remote_path, zip_bytes or b"")

    # ログ（SFTPのURL/パスワード等は出さない）
    try:
        safe_log_action(actor, "project_export_backup_zip", details=json.dumps({"project_id": pid, "file": cand}, ensure_ascii=False))
    except Exception:
        pass

    return remote_path
