def parse_cleanup_exclude_list(raw) -> list[str]:
    """不要ファイル削除で残したいファイルの除外リストを正規化する。

    - 1行1つ（例: robots.txt）
    - ワイルドカード（* / ?）OK（例: *.xml）
    - 先頭/末尾の空白は削除
    - 先頭の / は無視（相対パス扱い）
    - # で始まる行はコメント扱いで無視
    """
    try:
        lines: list[str] = []
        if isinstance(raw, list):
            lines = [str(x) for x in raw]
        else:
            lines = str(raw or "").splitlines()

        out: list[str] = []
        for ln in lines:
            s = str(ln or "").strip()
            if not s:
                continue
            if s.startswith("#"):
                continue
            s = s.lstrip("/").strip()
            if not s:
                continue
            # 事故防止（明らかに危険な指定は無視）
            if ".." in s.replace("\\", "/").split("/"):
                continue
            out.append(s)

        # uniq (keep order)
        seen = set()
        uniq: list[str] = []
        for s in out:
            if s in seen:
                continue
            seen.add(s)
            uniq.append(s)
        return uniq
    except Exception:
        return []


def is_excluded_path(rel_path: str, patterns: list[str]) -> bool:
    """rel_path が除外パターンに一致するか（fnmatch）。"""
    try:
        rel = str(rel_path or "").lstrip("/")
        pats = patterns or []
        for p in pats:
            pp = str(p or "").strip()
            if not pp:
                continue
            try:
                if fnmatch.fnmatch(rel, pp):
                    return True
            except Exception:
                continue
        return False
    except Exception:
        return False


def _list_project_backup_zips__base_13892(project_id: str) -> list[dict]:
    """案件ディレクトリ内の backups/*.zip を一覧する（新しい順）。"""
    pid = (project_id or "").strip()
    if not pid:
        return []
    remote_dir = f"{project_dir(pid)}/backups"
    out: list[dict] = []
    with sftp_client() as sftp:
        try:
            items = sftp.listdir_attr(remote_dir)
        except Exception:
            return []
        for it in items:
            try:
                if stat.S_ISDIR(it.st_mode):
                    continue
                fn = str(it.filename or "")
                if not fn.lower().endswith(".zip"):
                    continue
                size_kb = int(round(int(getattr(it, "st_size", 0) or 0) / 1024))
                mtime_iso = ""
                try:
                    mt = int(getattr(it, "st_mtime", 0) or 0)
                    if mt > 0:
                        mtime_iso = datetime.fromtimestamp(mt, tz=JST).replace(microsecond=0).isoformat()
                except Exception:
                    mtime_iso = ""
                out.append({"filename": fn, "size_kb": size_kb, "mtime": mtime_iso})
            except Exception:
                continue
    # mtime（更新日時）降順で並べる（名前規則が変わっても安定）
    try:
        out.sort(key=lambda x: str(x.get("mtime") or ""), reverse=True)
    except Exception:
        pass
    return out
