def _render_inapp_help_links_html(items: list[dict]) -> str:
    """上部の箇条書きリンク（ページ内リンク）をHTMLで返す"""
    try:
        lis = []
        for it in items:
            sid = html.escape(str(it.get("id") or ""))
            title = html.escape(str(it.get("title") or it.get("q") or ""))
            if not sid or not title:
                continue
            lis.append(
                f"<li><a href='javascript:void(0)' onclick=\"try{{document.getElementById('{sid}').scrollIntoView({{behavior:'smooth', block:'start'}});}}catch(e){{}}\">{title}</a></li>"
            )
        joined = "".join(lis)
        return (
            "<div class='cvhb-help-links'>"
            "<div style='font-weight:700; margin-bottom:6px;'>よくある質問（クリックで移動）</div>"
            "<ul style='margin: 0 0 0 18px; padding: 0; line-height: 1.6;'>"
            + joined
            + "</ul></div>"
        )
    except Exception:
        return ""

def create_inapp_help_dialog() -> ui.dialog:
    """ビルダー内で開くヘルプ（ポップアップ）"""
    with ui.dialog() as dialog, ui.card().classes("q-pa-md rounded-borders").style("width: 980px; max-width: 96vw;").props("bordered"):
        with ui.row().classes("items-center justify-between"):
            ui.label("ヘルプ（よくある質問）").classes("text-h6")
            ui.button("閉じる", on_click=dialog.close).props("flat")
        ui.label("困ったときは、まず上のリンクから該当項目へジャンプしてください。").classes("cvhb-muted q-mt-xs")

        ui.separator().classes("q-my-sm")

        with ui.scroll_area().style("height: 72vh; width: 100%;"):
            # 上部：箇条書き（ページ内リンク）
            ui.html(_render_inapp_help_links_html(INAPP_HELP_FAQ)).classes("q-mb-md")

            # 下：Q&A
            for it in INAPP_HELP_FAQ:
                sid = str(it.get("id") or "")
                q = str(it.get("q") or "")
                a = str(it.get("a_md") or "")
                if not sid or not q:
                    continue
                ui.html(f"<div id='{html.escape(sid)}' style='scroll-margin-top: 90px;'></div>")
                ui.label(f"Q. {q}").classes("text-subtitle2 q-mt-md")
                if a:
                    ui.markdown(a).classes("q-mt-xs")
                else:
                    ui.label("（準備中）").classes("cvhb-muted")

        ui.separator().classes("q-mt-sm")
        with ui.row().classes("items-center justify-end q-gutter-sm q-mt-sm"):
            ui.button("閉じる", on_click=dialog.close).props("color=primary outline")
    return dialog




def _header_brand_html() -> str:
    logo = html.escape(PAGEFLOW_BUILDER_LOGO_DATA_URL, quote=True)
    icon = html.escape(PAGEFLOW_BUILDER_ICON_DATA_URL, quote=True)
    alt = html.escape(PRODUCT_NAME, quote=True)
    sub = html.escape(f"{BUILDER_NAME} v{CURRENT_APP_VERSION}｜{BUILDER_NAME_JA}")
    return f"""
<div class="cvhb-brand-lockup-html">
  <span class="cvhb-brand-mark"><img src="{icon}" alt="{alt}"></span>
  <span class="cvhb-brand-copy">
    <span class="cvhb-brand-wordmark-wrap"><img class="cvhb-brand-wordmark" src="{logo}" alt="{alt}"></span>
    <span class="cvhb-brand-sub">{sub}</span>
  </span>
</div>
"""


def _auth_brand_panel_html(note: str, points: list[str]) -> str:
    icon = html.escape(PAGEFLOW_BUILDER_ICON_DATA_URL, quote=True)
    note_html = "<br>".join(html.escape(line) for line in str(note or "").splitlines() if line is not None)
    point_items = []
    for point in points or []:
        p = str(point or "").strip()
        if not p:
            continue
        point_items.append(
            f'<span class="cvhb-auth-point"><span class="cvhb-auth-point-mark"><img src="{icon}" alt=""></span><span>{html.escape(p)}</span></span>'
        )
    points_html = "".join(point_items)
    return f"""
<div class="cvhb-auth-brand">
  <div class="cvhb-auth-brand-shell">
    <div class="cvhb-auth-brand-head">
      <span class="cvhb-auth-brand-mark"><img src="{icon}" alt=""></span>
      <div class="cvhb-auth-brand-copy" style="line-height:1.15">
        <div style="font-weight:900;font-size:30px;letter-spacing:0;color:#0f172a;">PageFlowAI2</div>
        <div style="font-weight:800;font-size:13px;color:rgba(15,23,42,.58);margin-top:4px;">求人・会社ページ作成</div>
      </div>
    </div>
    <div class="cvhb-auth-brand-note">{note_html}</div>
  </div>
  <div class="cvhb-auth-point-row">{points_html}</div>
</div>
"""


def _startup_brand_panel_html(note: str) -> str:
    note_html = "<br>".join(html.escape(line) for line in str(note or "").splitlines() if line is not None)
    return f"""
<div class="cvhb-startup-brand">
  <div class="cvhb-startup-brandplate" style="font-weight:900;font-size:28px;color:#0f172a;">PageFlowAI2</div>
  <div class="cvhb-startup-note">{note_html}</div>
</div>
"""


