def render_login(root_refresh) -> None:
    with ui.element("div").classes("cvhb-auth-shell"):
        with ui.card().classes("q-pa-xl rounded-borders cvhb-auth-card").props("bordered"):
            ui.html(
                _auth_brand_panel_html(
                    """左で入力、右で確認しながら、案件ごとに整理して進められるビルダーです。
公開までの流れが見やすく、迷いにくい構成にしています。""",
                    [
                        "左で入力、右で確認",
                        "案件ごとに整理しやすい",
                        "公開まで流れが見やすい",
                    ],
                )
            )
            ui.label(PRODUCT_NAME).classes("cvhb-panel-caption")
            ui.label("ログイン").classes("text-h5 q-mt-xs")
            if APP_ENV == "stg":
                seeded, msg = ensure_stg_test_users()
                with ui.card().classes("q-pa-md q-mb-md rounded-borders cvhb-surface-card").props("flat bordered"):
                    ui.label("stg（検証環境）テストアカウント").classes("text-subtitle1")
                    if seeded:
                        ui.label("ユーザー名：admin_test / company_admin_test / subadmin_test / user01〜user05")
                        ui.label("パスワード：STG_TEST_PASSWORD").classes("text-caption text-grey")
                    else:
                        ui.label("STG_TEST_PASSWORD が未設定のため、テストアカウントは作成されていません。")
                        ui.label(f"理由: {msg}").classes("text-caption text-grey")

            username = ui.input("ユーザー名").props("outlined").classes("w-full")
            password = ui.input("パスワード", password=True, password_toggle_button=True).props("outlined").classes("w-full")

            def do_login() -> None:
                un = (username.value or "").strip()
                pw = (password.value or "")
                if not un or not pw:
                    ui.notify("ユーザー名とパスワードを入力してください", type="warning")
                    return

                login_key = _login_rate_key(un)
                remaining = _login_throttle_remaining_seconds(login_key)
                if remaining > 0:
                    safe_log_action(None, "login_throttled", details=json.dumps({"username": un, "wait_sec": remaining}, ensure_ascii=False))
                    ui.notify("ログイン試行が多すぎます。少し時間をおいて再試行してください。", type="negative")
                    return

                row = get_user_by_username(un)
                reason = login_block_reason(row)
                if not row or reason or not verify_password(pw, row["password_hash"]):
                    _record_login_failure(login_key)
                    safe_log_action(None, "login_failed", details=json.dumps({"username": un}, ensure_ascii=False))
                    ui.notify(reason or "ユーザー名またはパスワードが違います", type="negative")
                    return

                _clear_login_failures(login_key)
                set_logged_in(row)
                cleanup_user_storage()
                u = current_user()
                if u:
                    safe_log_action(u, "login_success")

                if bool((row or {}).get("must_change_password", False)):
                    ui.notify("初期パスワードです。先にアカウント設定で変更してください", type="warning")
                    navigate_to(ACCOUNT_PAGE_PATH)
                    return

                ui.notify("ログインしました", type="positive")
                root_refresh()

            ui.label(f"案件管理と {BUILDER_LABEL} を開きます。").classes("cvhb-auth-lead q-mb-md")
            ui.button("ログイン", on_click=do_login).props("color=primary unelevated no-caps").classes("q-mt-md w-full cvhb-primary-cta")


def render_first_admin_setup(root_refresh) -> None:
    with ui.element("div").classes("cvhb-auth-shell"):
        with ui.card().classes("q-pa-xl rounded-borders cvhb-auth-card").style("width: 640px; max-width: 92vw;").props("bordered"):
            ui.html(
                _auth_brand_panel_html(
                    """最初の管理者を1人だけ作れば、この画面は以後表示されません。
設定後は通常のログイン画面からそのまま使い始められます。""",
                    [
                        "初回だけ表示",
                        "あとでユーザー追加可能",
                        "設定後すぐ開始",
                    ],
                )
            )
            ui.label(PRODUCT_NAME).classes("cvhb-panel-caption")
            ui.label("初期設定：管理者アカウント作成").classes("text-h5 q-mt-xs")
            ui.label("※ この画面は、ユーザーが1人もいない時だけ表示されます。").classes("cvhb-auth-lead q-mb-md")

            username = ui.input("管理者ユーザー名").props("outlined").classes("w-full")
            password = ui.input("パスワード", password=True, password_toggle_button=True).props("outlined").classes("w-full")
            password2 = ui.input("パスワード（確認）", password=True, password_toggle_button=True).props("outlined").classes("w-full")

            def create_admin() -> None:
                un = (username.value or "").strip()
                pw = (password.value or "")
                pw2 = (password2.value or "")
                if not un or not pw:
                    ui.notify("ユーザー名とパスワードを入力してください", type="warning")
                    return
                if pw != pw2:
                    ui.notify("パスワードが一致しません", type="negative")
                    return
                if len(pw) < 10:
                    ui.notify("パスワードは10文字以上がおすすめです", type="warning")
                    return

                create_user(un, pw, "admin")
                row = get_user_by_username(un)
                if row:
                    set_logged_in(row)
                    cleanup_user_storage()
                    u = current_user()
                    if u:
                        safe_log_action(u, "first_admin_created")
                    ui.notify("管理者を作成しました。ログインしました。", type="positive")
                    root_refresh()
                else:
                    ui.notify("作成に失敗しました（同名ユーザーがいる可能性）", type="negative")

            ui.button("管理者を作成", on_click=create_admin).props("color=primary unelevated no-caps").classes("q-mt-md w-full cvhb-primary-cta")


