# [BLK-10] Preview: Glassmorphism theme (SP/PC)

def _is_light_color(color_value: str) -> bool:
    return str(color_value) in {"white", "yellow"}

def _safe_primary_text_class(primary: str) -> str:
    return "text-black" if _is_light_color(primary) else "text-white"

def _hex_to_rgb(hex_color: str) -> tuple[int, int, int]:
    h = (hex_color or "").strip().lstrip("#")
    if len(h) == 3:
        h = "".join([c * 2 for c in h])
    if len(h) != 6:
        return (25, 118, 210)  # fallback (Quasar primary blue)
    r = int(h[0:2], 16)
    g = int(h[2:4], 16)
    b = int(h[4:6], 16)
    return (r, g, b)

def _rgb_to_hex(r: int, g: int, b: int) -> str:
    r = max(0, min(255, int(r)))
    g = max(0, min(255, int(g)))
    b = max(0, min(255, int(b)))
    return f"#{r:02x}{g:02x}{b:02x}"

def _blend_hex(c1: str, c2: str, t: float) -> str:
    """c1 と c2 を t(0..1) でブレンド"""
    t = max(0.0, min(1.0, float(t)))
    r1, g1, b1 = _hex_to_rgb(c1)
    r2, g2, b2 = _hex_to_rgb(c2)
    r = r1 + (r2 - r1) * t
    g = g1 + (g2 - g1) * t
    b = b1 + (b2 - b1) * t
    return _rgb_to_hex(r, g, b)

def _is_light_hex(hex_color: str) -> bool:
    r, g, b = _hex_to_rgb(hex_color)
    # 相対輝度（ざっくり）
    y = (r * 0.299) + (g * 0.587) + (b * 0.114)
    return y >= 165

def _preview_accent_hex(primary: str) -> str:
    """プレビュー用のアクセント色（ガラステーマ用）"""
    # 「白」はアクセントが白だと見えないので、濃い色に寄せる（=白基調 + 濃いアクセント）
    if primary == "white":
        return "#0f172a"
    # 「黒」はダークモード扱いにする（ボタン等が沈まないように、見えるアクセントを採用）
    if primary == "black":
        return "#60a5fa"  # blue-400
    # それ以外は既存の COLOR_HEX を採用
    return COLOR_HEX.get(primary, "#1976d2")

def _preview_accent2_hex(primary: str, accent_hex: str) -> str:
    """プレビュー用のアクセント2（グラデーション用の2色目）

    v1.0.9:
    - 各テーマが「その色らしく」見えるように、補助色も同系色へ寄せる
    - blue → 青系、purple → 紫系、yellow → 黄〜金系 を維持する
    - 背景の幾何学模様でもテーマ色がきれいに見えるよう、線色の彩度を少しだけ上げる
    """
    presets = {
        "blue": "#60a5fa",    # blue-400
        "green": "#34d399",   # emerald-400
        "red": "#f87171",     # red-400
        "orange": "#fb923c",  # orange-400
        "purple": "#8b5cf6",  # violet-500
        "grey": "#94a3b8",    # slate-400
        "gray": "#94a3b8",    # alias
        "black": "#38bdf8",   # sky-400
        "white": "#2563eb",   # blue-600
        "yellow": "#facc15",  # yellow-400
    }
    if primary in presets:
        return presets[primary]
    # fallback: accent を少しだけ明るくして2色目にする
    try:
        return _blend_hex(accent_hex, "#ffffff", 0.35)
    except Exception:
        return accent_hex



def _preview_glass_style(step1_or_primary=None, *, dark: Optional[bool] = None, **_ignore) -> str:
    """Return inline CSS variables for the preview/export theme.

    背景ルール（固定）
    - Layer1: ベースカラー（面）
    - Layer2: radial gradient（光の中心）
    - Layer3: organic blob（有機的な塊）
    - Layer4: geometric line（線のアクセント）
    - Layer5: light orb（小さめの光球）

    重要:
    - 「柄が見える」のに「本文は読みやすい」を優先する
    - 背景の濃さは step1.bg_strength（weak / medium / strong）で制御する
    """

    primary = "blue"
    strength = "medium"
    motion_strength = "medium"
    ui_strength = "medium"
    ui_motion = "medium"
    try:
        if isinstance(step1_or_primary, dict):
            primary = str(step1_or_primary.get("primary_color") or "blue").strip() or "blue"
            strength = _normalize_bg_strength(step1_or_primary.get("bg_strength") or "medium")
            motion_strength = _normalize_bg_motion(step1_or_primary.get("bg_motion") or "medium")
            ui_strength = _normalize_ui_strength(step1_or_primary.get("ui_strength") or strength or "medium")
            ui_motion = _normalize_ui_motion(step1_or_primary.get("ui_motion") or motion_strength or "medium")
        elif isinstance(step1_or_primary, str) and step1_or_primary:
            primary = str(step1_or_primary).strip() or "blue"
    except Exception:
        primary = "blue"
        strength = "medium"
        motion_strength = "medium"
        ui_strength = "medium"
        ui_motion = "medium"

    primary = COLOR_MIGRATION.get(primary, primary)
    if primary not in COLOR_OPTIONS:
        primary = "blue"

    accent = _preview_accent_hex(primary)
    accent2 = _preview_accent2_hex(primary, accent)
    accent3 = _blend_hex(accent, accent2, 0.5)

    if dark is None:
        dark = (primary == "black")
    is_dark = bool(dark)

    def _rgba(hex_color: str, alpha: float) -> str:
        r, g, b = _hex_to_rgb(hex_color)
        a = max(0.0, min(1.0, float(alpha)))
        return f"rgba({r}, {g}, {b}, {a:.3f})"

    def _alpha(base: float) -> float:
        scale = {"weak": 0.82, "medium": 1.00, "strong": 1.28}.get(strength, 1.00)
        return max(0.0, min(0.98, float(base) * scale))

    if not is_dark:
        base1 = _blend_hex(accent, "#ffffff", 0.82)
        base2 = _blend_hex(accent2, "#fbfdff", 0.90)
        base3 = _blend_hex(accent3, "#fffdfa", 0.95)

        text = "#0f172a"
        muted = "rgba(15, 23, 42, 0.74)"
        border = "rgba(255, 255, 255, 0.34)"
        line = "rgba(15, 23, 42, 0.10)"
        card = "linear-gradient(180deg, rgba(255, 255, 255, 0.34), rgba(255, 255, 255, 0.22))"
        chip_bg = "rgba(255, 255, 255, 0.30)"
        chip_border = "rgba(255, 255, 255, 0.28)"
        shadow = "0 22px 64px rgba(15, 23, 42, 0.10)"
        primary_weak = _rgba(accent, 0.14)

        panel_guard = {
            "weak": "linear-gradient(180deg, rgba(255,255,255,0.84), rgba(255,255,255,0.72))",
            "medium": "linear-gradient(180deg, rgba(255,255,255,0.74), rgba(255,255,255,0.56))",
            "strong": "linear-gradient(180deg, rgba(255,255,255,0.60), rgba(255,255,255,0.40))",
        }.get(strength, "linear-gradient(180deg, rgba(255,255,255,0.74), rgba(255,255,255,0.56))")
        panel_border = "rgba(255,255,255,0.42)"
        topbar_bg = {
            "weak": "linear-gradient(180deg, rgba(255,255,255,0.84), rgba(255,255,255,0.68))",
            "medium": "linear-gradient(180deg, rgba(255,255,255,0.78), rgba(255,255,255,0.58))",
            "strong": "linear-gradient(180deg, rgba(255,255,255,0.70), rgba(255,255,255,0.48))",
        }.get(strength, "linear-gradient(180deg, rgba(255,255,255,0.78), rgba(255,255,255,0.58))")
        topbar_border = "rgba(255,255,255,0.34)"
        surface_bg = {
            "weak": "linear-gradient(180deg, rgba(255,255,255,0.62), rgba(255,255,255,0.46))",
            "medium": "linear-gradient(180deg, rgba(255,255,255,0.50), rgba(255,255,255,0.30))",
            "strong": "linear-gradient(180deg, rgba(255,255,255,0.36), rgba(255,255,255,0.14))",
        }.get(strength, "linear-gradient(180deg, rgba(255,255,255,0.50), rgba(255,255,255,0.30))")
        surface_border = "rgba(255,255,255,0.30)"

        radial_1 = _rgba(accent, _alpha(0.74))
        radial_2 = _rgba(accent2, _alpha(0.62))
        blob_1 = _rgba(_blend_hex(accent, "#ffffff", 0.42), _alpha(0.60))
        blob_2 = _rgba(_blend_hex(accent2, "#ffffff", 0.40), _alpha(0.48))
        line_1 = _rgba(_blend_hex(accent, "#ffffff", 0.20), _alpha(0.24))
        line_2 = _rgba(_blend_hex(accent2, "#ffffff", 0.24), _alpha(0.20))
        line_1_soft = _rgba(_blend_hex(accent3, "#ffffff", 0.56), _alpha(0.12))
        line_band_1 = _rgba(_blend_hex(accent, "#ffffff", 0.34), _alpha(0.10))
        line_band_2 = _rgba(_blend_hex(accent2, "#ffffff", 0.38), _alpha(0.08))
        orb_1 = _rgba("#ffffff", _alpha(0.76))
        orb_2 = _rgba(_blend_hex(accent2, "#ffffff", 0.54), _alpha(0.28))
        orb_ring = _rgba(_blend_hex(accent3, "#ffffff", 0.74), _alpha(0.028))

        radial_opacity = {"weak": 0.26, "medium": 0.56, "strong": 0.84}.get(strength, 0.56)
        blob_opacity = {"weak": 0.16, "medium": 0.38, "strong": 0.60}.get(strength, 0.38)
        line_opacity = {"weak": 0.18, "medium": 0.34, "strong": 0.58}.get(strength, 0.34)
        orb_opacity = {"weak": 0.26, "medium": 0.50, "strong": 0.72}.get(strength, 0.50)
        panel_show_opacity = {"weak": 0.02, "medium": 0.08, "strong": 0.16}.get(strength, 0.08)
    else:
        base1 = _blend_hex("#0b1220", accent, 0.18)
        base2 = _blend_hex("#111827", accent2, 0.16)
        base3 = _blend_hex("#04070d", accent3, 0.04)

        text = "rgba(248, 250, 252, 0.97)"
        muted = "rgba(226, 232, 240, 0.84)"
        border = "rgba(255, 255, 255, 0.16)"
        line = "rgba(255, 255, 255, 0.12)"
        card = "linear-gradient(180deg, rgba(15, 23, 42, 0.60), rgba(15, 23, 42, 0.42))"
        chip_bg = "rgba(255, 255, 255, 0.10)"
        chip_border = "rgba(255, 255, 255, 0.16)"
        shadow = "0 24px 72px rgba(0, 0, 0, 0.42)"
        primary_weak = _rgba(accent, 0.20)

        panel_guard = {
            "weak": "linear-gradient(180deg, rgba(7,12,20,0.86), rgba(7,12,20,0.72))",
            "medium": "linear-gradient(180deg, rgba(7,12,20,0.78), rgba(7,12,20,0.58))",
            "strong": "linear-gradient(180deg, rgba(7,12,20,0.70), rgba(7,12,20,0.48))",
        }.get(strength, "linear-gradient(180deg, rgba(7,12,20,0.78), rgba(7,12,20,0.58))")
        panel_border = "rgba(255,255,255,0.14)"
        topbar_bg = {
            "weak": "linear-gradient(180deg, rgba(8,12,19,0.90), rgba(8,12,19,0.74))",
            "medium": "linear-gradient(180deg, rgba(8,12,19,0.84), rgba(8,12,19,0.64))",
            "strong": "linear-gradient(180deg, rgba(8,12,19,0.76), rgba(8,12,19,0.54))",
        }.get(strength, "linear-gradient(180deg, rgba(8,12,19,0.84), rgba(8,12,19,0.64))")
        topbar_border = "rgba(255,255,255,0.14)"
        surface_bg = {
            "weak": "linear-gradient(180deg, rgba(9,13,21,0.78), rgba(9,13,21,0.60))",
            "medium": "linear-gradient(180deg, rgba(9,13,21,0.70), rgba(9,13,21,0.50))",
            "strong": "linear-gradient(180deg, rgba(9,13,21,0.58), rgba(9,13,21,0.38))",
        }.get(strength, "linear-gradient(180deg, rgba(9,13,21,0.70), rgba(9,13,21,0.50))")
        surface_border = "rgba(255,255,255,0.14)"

        radial_1 = _rgba(accent, _alpha(0.46))
        radial_2 = _rgba(accent2, _alpha(0.36))
        blob_1 = _rgba(_blend_hex(accent, "#ffffff", 0.16), _alpha(0.38))
        blob_2 = _rgba(_blend_hex(accent2, "#ffffff", 0.22), _alpha(0.30))
        line_1 = _rgba(_blend_hex(accent, "#ffffff", 0.50), _alpha(0.22))
        line_2 = _rgba(_blend_hex(accent2, "#ffffff", 0.48), _alpha(0.20))
        line_1_soft = _rgba(_blend_hex(accent3, "#ffffff", 0.68), _alpha(0.14))
        line_band_1 = _rgba(_blend_hex(accent, "#ffffff", 0.62), _alpha(0.08))
        line_band_2 = _rgba(_blend_hex(accent2, "#ffffff", 0.60), _alpha(0.07))
        orb_1 = _rgba("#ffffff", _alpha(0.42))
        orb_2 = _rgba(_blend_hex(accent2, "#ffffff", 0.50), _alpha(0.24))
        orb_ring = _rgba(_blend_hex(accent, "#ffffff", 0.66), _alpha(0.034))

        radial_opacity = {"weak": 0.24, "medium": 0.52, "strong": 0.80}.get(strength, 0.52)
        blob_opacity = {"weak": 0.16, "medium": 0.36, "strong": 0.56}.get(strength, 0.36)
        line_opacity = {"weak": 0.18, "medium": 0.36, "strong": 0.60}.get(strength, 0.36)
