def render_recruitment_page_preview(p: dict, mode: str = "pc", *, root_id: Optional[str] = None, in_builder: bool = False) -> None:
    """求人専用ページの右プレビュー。

    完成HP本体とは別ページとして、Google JobPosting / Indeed feed の前提を確認しやすくする。
    """
    if isinstance(p, dict) and isinstance(p.get("data"), dict):
        d = p.get("data") or {}
        project_obj = p
    elif isinstance(p, dict):
        d = p
        project_obj = {"data": d}
    else:
        d = {}
        project_obj = {"data": d}

    step1 = d.get("step1", {}) if isinstance(d.get("step1"), dict) else {}
    step2 = d.get("step2", {}) if isinstance(d.get("step2"), dict) else {}
    blocks = d.get("blocks", {}) if isinstance(d.get("blocks"), dict) else {}
    philosophy = blocks.get("philosophy") if isinstance(blocks.get("philosophy"), dict) else {}
    profile = philosophy.get("company_profile") if isinstance(philosophy.get("company_profile"), dict) else {}
    recruitment = _normalize_recruitment_block(blocks.get("recruitment") if isinstance(blocks.get("recruitment"), dict) else {})

    mode = str(mode or "mobile").strip()
    if mode not in {"mobile", "pc"}:
        mode = "mobile"
    root_id = str(root_id or f"pv-recruitment-root-{mode}").strip() or f"pv-recruitment-root-{mode}"

    def _esc(v) -> str:
        return html.escape(str(v or ""), quote=True)

    def _nl(v) -> str:
        return _esc(v).replace("\n", "<br>")

    company_name = str(step2.get("company_name") or "").strip() or "会社名"
    title = str(recruitment.get("title") or "").strip() or "求人情報"
    lead = str(recruitment.get("lead") or "").strip()
    enabled = bool(recruitment.get("enabled"))
    rows = _recruitment_rows(recruitment)
    image_url = str(recruitment.get("image_url") or "").strip()
    public_base = _project_public_site_url(project_obj, step2, profile)
    recruitment_public_url = _public_page_url(public_base, RECRUITMENT_PAGE_PATH) if public_base else RECRUITMENT_PAGE_PATH
    jobposting_url = _public_url(public_base, RECRUITMENT_JOBPOSTING_JSON_PATH) if public_base else RECRUITMENT_JOBPOSTING_JSON_PATH
    indeed_feed_url = _public_url(public_base, RECRUITMENT_INDEED_FEED_PATH) if public_base else RECRUITMENT_INDEED_FEED_PATH
    email = str(step2.get("email") or "").strip()
    apply_url = str(recruitment.get("apply_url") or "").strip()
    indeed_url = str(recruitment.get("indeed_url") or "").strip()
    apply_href = apply_url or (f"mailto:{email}" if email else "#")
    apply_label = "今すぐ応募する" if apply_url else ("メールで応募する" if email else "応募導線を入力")
    indeed_button_html = f'<a class="job-action job-action-light" href="{_esc(indeed_url)}" target="_blank" rel="noopener">Indeed求人ページを開く</a>' if indeed_url else ""
    work_ready = any(str(recruitment.get(k) or "").strip() for k in ("work_summary", "work_details", "daily_flow"))
    conditions_ready = any(str(recruitment.get(k) or "").strip() for k in ("employment_types", "work_location", "work_hours", "salary_note", "holidays", "benefits", "conditions"))

    required_for_google = [
        ("会社名", bool(company_name and company_name != "会社名")),
        ("仕事内容", work_ready),
        ("勤務条件", conditions_ready),
        ("応募導線", bool(str(recruitment.get("apply_url") or "").strip() or str(step2.get("email") or "").strip())),
    ]
    required_for_indeed = [
        ("公開URL", bool(public_base)),
        ("会社名", bool(company_name and company_name != "会社名")),
        ("メール", bool(str(step2.get("email") or "").strip())),
        ("住所", bool(str(step2.get("address") or "").strip())),
    ]

    def _status_badges(items: list[tuple[str, bool]]) -> str:
        return "".join(
            f'<span class="job-status {"ok" if ok else "warn"}">{"OK" if ok else "要確認"} {_esc(label)}</span>'
            for label, ok in items
        )

    rows_html = "".join(
        f'<div class="job-row"><dt>{_esc(label)}</dt><dd>{_nl(value)}</dd></div>'
        for label, value in rows
    ) or '<div class="job-empty">求人項目を入力すると、ここに仕事内容・条件・応募方法が整理されます。</div>'

    if image_url:
        dims = (880, 520) if mode == "pc" else (720, 520)
        img_html = f'<img class="job-hero-img" src="{_esc(pv_img_src(image_url, max_w=dims[0], max_h=dims[1], fit_mode="cover"))}" alt="">'
    else:
        img_html = '<div class="job-hero-placeholder">職場・スタッフ・働く様子の画像</div>'

    disabled_note = "" if enabled else '<div class="job-disabled">現在は「求人情報を表示する」がOFFです。公開時は求人ページを出さない設定になります。</div>'
    layout_class = "is-mobile" if mode == "mobile" else "is-pc"

    ui.html(
        f"""
<div id="{_esc(root_id)}" class="job-preview {layout_class} notranslate" translate="no">
  <style>
    .job-preview{{--job-primary:#2563eb;--job-ink:#0f172a;--job-muted:#64748b;font-family:"Hiragino Sans","Hiragino Kaku Gothic ProN","Noto Sans JP","Yu Gothic",Meiryo,sans-serif;background:linear-gradient(180deg,#f8fafc,#eef6ff);color:var(--job-ink);min-height:720px;border-radius:24px;overflow:hidden;position:relative;padding-bottom:86px;}}
    .job-preview *{{box-sizing:border-box;}}
    .job-top{{position:sticky;top:0;z-index:8;display:flex;align-items:center;justify-content:space-between;gap:14px;padding:14px 18px;border-bottom:1px solid rgba(15,23,42,.08);background:rgba(255,255,255,.76);backdrop-filter:blur(14px) saturate(1.08);}}
    .job-brand{{font-weight:1000;font-size:17px;line-height:1.3;letter-spacing:-.02em;}}
    .job-page-path{{font-size:11px;color:var(--job-muted);margin-top:2px;word-break:break-all;}}
    .job-badge{{background:var(--job-ink);color:#fff;border-radius:999px;padding:9px 12px;font-size:12px;font-weight:900;white-space:nowrap;box-shadow:0 12px 28px rgba(15,23,42,.14);}}
    .job-hero{{display:grid;grid-template-columns:minmax(0,1.1fr) minmax(300px,.9fr);gap:0;align-items:stretch;padding:18px;}}
    .job-hero-visual{{min-width:0;min-height:420px;border-radius:28px;overflow:hidden;box-shadow:0 22px 58px rgba(15,23,42,.14);background:#0f172a;}}
    .job-hero-img,.job-hero-placeholder{{width:100%;height:100%;min-height:420px;object-fit:cover;background:linear-gradient(135deg,#dbeafe,#f8fafc);border:0;display:block;}}
    .job-hero-placeholder{{display:grid;place-items:center;color:#64748b;font-weight:900;}}
    .job-hero-copy{{align-self:center;margin:32px 0 32px -58px;padding:24px;border-radius:28px;background:rgba(255,255,255,.90);box-shadow:0 22px 58px rgba(15,23,42,.14);}}
    .job-kicker{{font-size:11px;letter-spacing:.16em;color:var(--job-primary);font-weight:1000;margin-bottom:10px;}}
    .job-title{{font-size:clamp(32px,4.6vw,56px);line-height:1.10;font-weight:1000;letter-spacing:-.045em;margin:0 0 14px;text-wrap:balance;}}
    .job-lead{{font-size:15px;line-height:1.9;color:#334155;margin:0;}}
    .job-actions{{display:flex;flex-wrap:wrap;gap:10px;margin-top:16px;}}
    .job-action{{display:inline-flex;align-items:center;justify-content:center;min-height:46px;padding:0 16px;border-radius:999px;text-decoration:none;font-weight:1000;}}
    .job-action-main{{background:linear-gradient(135deg,var(--job-primary),#38bdf8);color:#fff;box-shadow:0 14px 32px rgba(37,99,235,.22);}}
    .job-action-light{{background:rgba(15,23,42,.06);color:var(--job-ink);border:1px solid rgba(15,23,42,.08);}}
    .job-disabled{{margin-top:14px;border:1px solid #f59e0b;background:#fffbeb;color:#92400e;border-radius:16px;padding:10px 12px;font-size:13px;}}
    .job-grid{{display:grid;grid-template-columns:minmax(0,1fr) minmax(280px,.50fr);gap:18px;padding:0 18px 18px;}}
    .job-panel{{background:rgba(255,255,255,.86);border:1px solid rgba(255,255,255,.70);border-radius:24px;padding:20px;box-shadow:0 16px 42px rgba(15,23,42,.08);}}
    .job-panel h3{{font-size:18px;margin:0 0 14px;font-weight:1000;letter-spacing:-.02em;}}
    .job-row{{display:grid;grid-template-columns:132px minmax(0,1fr);gap:14px;padding:15px 0;border-top:1px solid rgba(15,23,42,.08);}}
    .job-row:first-child{{border-top:0;}}
    .job-row dt{{color:var(--job-primary);font-weight:1000;font-size:13px;letter-spacing:.03em;}}
    .job-row dd{{margin:0;color:var(--job-ink);line-height:1.85;font-size:14px;}}
    .job-empty{{padding:22px;border:1px dashed rgba(37,99,235,.28);border-radius:18px;color:#64748b;background:#f8fbff;}}
    .job-status-wrap{{display:flex;flex-wrap:wrap;gap:8px;margin-bottom:14px;}}
    .job-status{{font-size:12px;font-weight:900;border-radius:999px;padding:7px 9px;border:1px solid rgba(15,23,42,.12);}}
    .job-status.ok{{background:#ecfdf5;color:#047857;border-color:#a7f3d0;}}
    .job-status.warn{{background:#fff7ed;color:#c2410c;border-color:#fed7aa;}}
    .job-link-list{{display:grid;gap:8px;font-size:12px;line-height:1.55;color:#334155;}}
    .job-link-list div{{word-break:break-all;}}
    .job-sticky{{position:sticky;bottom:12px;z-index:9;display:flex;gap:10px;margin:0 18px 12px;padding:8px;border-radius:999px;background:rgba(255,255,255,.84);border:1px solid rgba(255,255,255,.70);box-shadow:0 18px 46px rgba(15,23,42,.15);backdrop-filter:blur(16px);}}
    .job-sticky .job-action{{flex:1 1 0;}}
    .job-footer{{padding:18px 28px;background:#0f172a;color:#e2e8f0;font-size:12px;}}
    .job-preview.is-mobile{{border-radius:24px;}}
    .job-preview.is-mobile .job-top{{padding:13px 14px;align-items:flex-start;}}
    .job-preview.is-mobile .job-badge{{font-size:11px;padding:8px 10px;}}
    .job-preview.is-mobile .job-hero{{display:block;padding:14px;}}
    .job-preview.is-mobile .job-hero-visual{{min-height:360px;border-radius:26px;}}
    .job-preview.is-mobile .job-hero-img,.job-preview.is-mobile .job-hero-placeholder{{min-height:360px;}}
    .job-preview.is-mobile .job-hero-copy{{margin:-78px 12px 0;padding:20px;position:relative;z-index:2;}}
    .job-preview.is-mobile .job-title{{font-size:clamp(28px,8.6vw,38px);line-height:1.13;}}
    .job-preview.is-mobile .job-lead{{font-size:14px;line-height:1.82;}}
    .job-preview.is-mobile .job-grid{{display:block;padding:0 14px 16px;}}
    .job-preview.is-mobile .job-panel{{padding:17px;margin-top:14px;border-radius:22px;}}
    .job-preview.is-mobile .job-row{{display:block;}}
    .job-preview.is-mobile .job-row dt{{margin-bottom:4px;}}
  </style>
  <header class="job-top">
    <div>
      <div class="job-brand">{_esc(company_name)}</div>
      <div class="job-page-path">{_esc(RECRUITMENT_PAGE_PATH)} / Google JobPosting / Indeed feed</div>
    </div>
    <div class="job-badge">{_esc(RECRUITMENT_BADGE_DEFAULT)}</div>
  </header>
  <section class="job-hero">
    <div class="job-hero-visual">{img_html}</div>
    <div class="job-hero-copy">
      <div class="job-kicker">RECRUIT PAGE</div>
      <h1 class="job-title">{_esc(title)}</h1>
      <p class="job-lead">{_nl(lead or "求人のひとこと説明を入力すると、ここに応募者向けの導入文が表示されます。")}</p>
      <div class="job-actions">
        <a class="job-action job-action-main" href="{_esc(apply_href)}">{_esc(apply_label)}</a>
        {indeed_button_html}
      </div>
      {disabled_note}
    </div>
  </section>
  <main class="job-grid">
    <section class="job-panel">
      <h3>募集内容</h3>
      <dl>{rows_html}</dl>
    </section>
    <aside class="job-panel">
        <h3>Google / Indeed 向けデータ確認</h3>
      <div class="job-status-wrap">{_status_badges(required_for_google)}</div>
      <div class="job-status-wrap">{_status_badges(required_for_indeed)}</div>
      <div class="job-link-list">
        <div>求人ページ: {_esc(recruitment_public_url)}</div>
        <div>JobPosting JSON: {_esc(jobposting_url)}</div>
        <div>Indeed feed: {_esc(indeed_feed_url)}</div>
      </div>
    </aside>
  </main>
  <nav class="job-sticky" aria-label="求人固定CTA">
    <a class="job-action job-action-main" href="{_esc(apply_href)}">{_esc(apply_label)}</a>
      <a class="job-action job-action-light" href="#">{'データ項目確認' if enabled else '表示OFF確認'}</a>
  </nav>
  <footer class="job-footer">{_esc(PRODUCT_NAME)} {_esc(APP_RELEASE_VERSION)} / dedicated recruitment page preview</footer>
</div>
"""
    )

def render_main(u: User) -> None:
    cleanup_user_storage()
    sync_builder_shell(True)

    render_header(u)

    p = get_current_project(u)

    # ---------------------------
    # [UI-STATE] 画面の「今どこを編集中か」を覚える
    # - たまに接続が切れてUIが再生成されると、ステップが初期値に戻ることがある
    # - 入力内容は残っているのに「作成ステップ1」に戻る、という現象の対策
    # ---------------------------
    UI_STEP_KEY = "cvhb_ui_step"
    UI_BLOCK_KEY = "cvhb_ui_block"
    UI_PV_MODE_KEY = "cvhb_ui_preview_mode"
    BUILDER_VIEW_STATE_KEY = "cvhb_builder_main"
    BUILDER_LEFT_COL_ID = "cvhb-builder-left-col"
    BUILDER_RIGHT_COL_ID = "cvhb-builder-right-col"
    BLOCK_PREVIEW_SECTION_IDS = {
        "hero": "pv-top",
        "philosophy": "pv-about",
        "news": "pv-news",
        "faq": "pv-faq",
        "access_contact": "pv-access-contact",
    }

    def _ui_get(key: str, default: str, allowed: list[str]) -> str:
        try:
            v = app.storage.user.get(key)
            if isinstance(v, str) and v in allowed:
                return v
        except Exception:
            pass
        try:
            app.storage.user[key] = default
        except Exception:
            pass
        return default

    def _ui_set(key: str, value: str, allowed: list[str]) -> None:
        try:
            if isinstance(value, str) and value in allowed:
                app.storage.user[key] = value
        except Exception:
            pass

    def _event_value(e) -> str:
        """NiceGUIのイベントから value を安全に取り出す（型ゆれ吸収）。

        1.5.4:
        - list / tuple / JSON文字列化された値を継続対応
        - dict で args / payload / detail / data に入る形も吸収
        - object 側も value / args / payload / detail / data を順に見る

        ねらい:
        - lazy mount 化後の step / block 切替を、イベント形の差で止めない
        - NiceGUI / Quasar 側の payload 揺れをここで閉じ込める
        """
        def _coerce(v) -> str:
            if isinstance(v, str):
                s = v.strip()
                if not s:
                    return ""
                try:
                    decoded = json.loads(s)
                except Exception:
                    decoded = None
                if isinstance(decoded, str):
                    return decoded.strip()
                if decoded is not None:
                    return _coerce(decoded)
                return s
            if isinstance(v, (list, tuple)):
                for item in v:
                    normalized = _coerce(item)
                    if normalized:
                        return normalized
                return ""
            if isinstance(v, dict):
                for key in ("value", "modelValue", "model_value", "args", "payload", "detail", "data"):
                    normalized = _coerce(v.get(key))
                    if normalized:
                        return normalized
            return ""

        try:
            for attr in ("value", "args", "payload", "detail", "data"):
                v = _coerce(getattr(e, attr, None))
                if v:
                    return v
        except Exception:
            pass
        try:
            v = _coerce(e)
            if v:
                return v
        except Exception:
            pass
        return ""

    preview_ref = {"refresh": (lambda: None)}

    editor_ref = {"refresh": (lambda: None)}

    approval_ref = {"refresh": (lambda: None)}
    publish_ref = {"refresh": (lambda: None)}

    # プレビューは更新が重くなりがちなので、入力中はデバウンスして負荷を下げる
    _preview_refresh_handle: Optional[asyncio.TimerHandle] = None
    _approval_refresh_handle: Optional[asyncio.TimerHandle] = None
    _publish_refresh_handle: Optional[asyncio.TimerHandle] = None

    def _current_step_value() -> str:
        try:
            v = str(app.storage.user.get(UI_STEP_KEY) or "").strip()
            if v:
                return v
        except Exception:
            pass
        return "s1"

    def _preview_debounce_sec() -> float:
        try:
            data_now = p.get("data") if isinstance(p, dict) else {}
            step1_now = data_now.get("step1") if isinstance(data_now, dict) else {}
            light_on = _normalize_preview_light_images(step1_now.get("preview_light_images", True)) if isinstance(step1_now, dict) else True
            return 0.45 if light_on else 0.65
        except Exception:
            return 0.55

    def refresh_preview(force: bool = False) -> None:
        """プレビュー更新（デバウンス対応）"""
        nonlocal _preview_refresh_handle

        def _do_refresh() -> None:
            nonlocal _preview_refresh_handle
            _preview_refresh_handle = None
            try:
                preview_ref["refresh"]()
            except Exception:
                pass
            restore_builder_view_state(70)

        if force:
            if _preview_refresh_handle is not None:
                try:
                    _preview_refresh_handle.cancel()
                except Exception:
                    pass
                _preview_refresh_handle = None
            _do_refresh()
            return

        try:
            loop = asyncio.get_running_loop()
        except Exception:
            _do_refresh()
            return

        if _preview_refresh_handle is not None:
            try:
                _preview_refresh_handle.cancel()
            except Exception:
                pass
        _preview_refresh_handle = loop.call_later(_preview_debounce_sec(), _do_refresh)

    def refresh_approval_panel(force: bool = False) -> None:
        nonlocal _approval_refresh_handle
        if not force and _current_step_value() != "s5":
            return

        def _do_refresh() -> None:
            nonlocal _approval_refresh_handle
            _approval_refresh_handle = None
            try:
                approval_ref["refresh"]()
            except Exception:
                pass
            restore_builder_view_state(60)

        if force:
            if _approval_refresh_handle is not None:
                try:
                    _approval_refresh_handle.cancel()
                except Exception:
                    pass
                _approval_refresh_handle = None
            _do_refresh()
            return

        try:
            loop = asyncio.get_running_loop()
        except Exception:
            _do_refresh()
            return

        if _approval_refresh_handle is not None:
            try:
                _approval_refresh_handle.cancel()
            except Exception:
                pass
        _approval_refresh_handle = loop.call_later(0.18, _do_refresh)

    def refresh_publish_panel(force: bool = False) -> None:
        nonlocal _publish_refresh_handle
        if not force and _current_step_value() != "s6":
            return

        def _do_refresh() -> None:
            nonlocal _publish_refresh_handle
            _publish_refresh_handle = None
            try:
                publish_ref["refresh"]()
            except Exception:
                pass
            restore_builder_view_state(60)

        if force:
            if _publish_refresh_handle is not None:
                try:
                    _publish_refresh_handle.cancel()
                except Exception:
                    pass
                _publish_refresh_handle = None
            _do_refresh()
            return

        try:
            loop = asyncio.get_running_loop()
        except Exception:
            _do_refresh()
            return

        if _publish_refresh_handle is not None:
            try:
                _publish_refresh_handle.cancel()
            except Exception:
                pass
        _publish_refresh_handle = loop.call_later(0.18, _do_refresh)

    def capture_builder_view_state(*, include_focus: bool = True) -> None:
        focus_flag = "true" if include_focus else "false"
        try:
            ui.run_javascript(
                f"window.cvhbBuilderCaptureView && window.cvhbBuilderCaptureView('{BUILDER_VIEW_STATE_KEY}','{BUILDER_LEFT_COL_ID}','pv-root',{focus_flag});"
            )
        except Exception:
            pass

    def restore_builder_view_state(delay_ms: int = 60) -> None:
        delay = max(0, int(delay_ms or 0))
        try:
            ui.run_javascript(
                f"setTimeout(function(){{ window.cvhbBuilderRestoreView && window.cvhbBuilderRestoreView('{BUILDER_VIEW_STATE_KEY}','{BUILDER_LEFT_COL_ID}','pv-root'); }}, {delay});"
            )
        except Exception:
            pass

    def scroll_preview_to_block(block_key: str, *, delay_ms: int = 0) -> None:
        target_id = BLOCK_PREVIEW_SECTION_IDS.get(str(block_key or "").strip())
        if not target_id:
            return
        delay = max(0, int(delay_ms or 0))
        try:
            ui.run_javascript(
                "setTimeout(function(){"
                f"window.cvhbPreviewScrollTo && window.cvhbPreviewScrollTo('pv-root','{target_id}');"
                f"}}, {delay});"
            )
        except Exception:
            pass

    save_state = {"busy": False}

    async def save_now() -> None:
        nonlocal p
        if not p:
            ui.notify("案件が選択されていません", type="warning")
            return
        if save_state["busy"]:
            return
        save_state["busy"] = True
        try:
            ui.notify("保存しています...", type="info")

            def _save_work(project_obj: dict, user_obj: User) -> None:
                save_project_to_sftp(_clone_json_data(project_obj), user_obj)

            await asyncio.wait_for(asyncio.to_thread(_save_work, p, u), timeout=15.0)
            set_current_project(p, u)
            ui.notify("保存しました（project.json）", type="positive")
        except asyncio.TimeoutError:
            ui.notify("保存がタイムアウトしました。通信状況を確認して再試行してください。", type="warning")
        except Exception as e:
            ui.notify(f"保存に失敗しました: {sanitize_error_text(e)}", type="negative")
        finally:
            save_state["busy"] = False

    with ui.element("div").classes("cvhb-page"):
        with ui.element("div").classes("cvhb-container"):
            with ui.element("div").classes("cvhb-split"):

                # -----------------
                # LEFT (cards)
                # -----------------
                with ui.element("div").classes("cvhb-left-col").props(f'id="{BUILDER_LEFT_COL_ID}"'):
                    with ui.element("div").classes("cvhb-left-stack"):

                        # Card 1: current project
                        with ui.card().classes("q-pa-md rounded-borders cvhb-surface-card").props("bordered"):
                            with ui.row().classes("items-center justify-between"):
                                ui.label("現在の案件").classes("cvhb-card-title")
                                ui.button("案件一覧", on_click=lambda: navigate_to("/projects")).props("flat")

                            if not p:
                                ui.label("案件が未選択です。まずは「案件一覧」から開いてください。").classes("q-mt-sm")
                                ui.button("案件一覧へ", on_click=lambda: navigate_to("/projects")).props("color=primary unelevated").classes("q-mt-sm")
                            else:
                                ui.separator().classes("q-my-sm")
                                ui.label(p.get("project_name", "")).classes("text-subtitle1")
                                ui.label(f"ID：{p.get('project_id','')}").classes("cvhb-muted")

                                ui.separator().classes("q-my-sm")
                                ui.label(f"案件開始日：{fmt_jst(p.get('created_at'))}").classes("cvhb-muted")
                                ui.label(f"最新更新日：{fmt_jst(p.get('updated_at'))}").classes("cvhb-muted")
                                ui.label(f"更新担当者：{p.get('updated_by') or u.username}").classes("cvhb-muted")

                                ui.button("保存（PROJECT.JSON）", on_click=save_now).props("color=primary unelevated").classes("q-mt-sm")

                        # Card 2: step nav
                        with ui.card().classes("q-pa-md rounded-borders cvhb-surface-card").props("bordered"):
                            ui.label("作成ステップ").classes("cvhb-card-title")
                            ui.label("ステップを選ぶと、下の入力画面が切り替わります。").classes("cvhb-muted q-mb-sm")

                            # UIの「今のステップ」を覚える（接続が切れても戻らないように）
                            allowed_steps = ["s1", "s2", "s3", "s4", "s5"] + ([] if HELP_MODE else ["s6"])
                            step_initial = _ui_get(UI_STEP_KEY, "s1", allowed_steps)

                            with ui.tabs(value=step_initial).props("vertical dense").classes("w-full cvhb-step-tabs") as step_tabs:
                                ui.tab("s1", label=f"1. {ASSIST_LABEL}")
                                ui.tab("s2", label="2. 基本情報設定")
                                ui.tab("s3", label="3. ページ内容詳細設定（ブロックごと）")
                                ui.tab("s4", label="4. 求人ページ")
                                ui.tab("s5", label="5. 承認・最終チェック")
                                if not HELP_MODE:
                                    ui.tab("s6", label=f"6. {PUBLISH_LABEL}")

                            step_content_ref = {"refresh": (lambda: None)}

                            def _on_step_tab_change(e):
                                v = _event_value(e)
                                if not v:
                                    return
                                _ui_set(UI_STEP_KEY, v, allowed_steps)
                                try:
                                    step_content_ref["refresh"]()
                                except Exception:
                                    pass
                                if v == "s4":
                                    refresh_preview(force=True)
                                elif v == "s5":
                                    refresh_approval_panel(force=True)
                                elif v == "s6":
                                    refresh_publish_panel(force=True)

                            try:
                                step_tabs.on("update:model-value", _on_step_tab_change)
                            except Exception:
                                pass

                        # Card 3: step contents
                        with ui.card().classes("q-pa-md rounded-borders cvhb-surface-card").props("bordered"):
                            if not p:
                                ui.label("案件を選択すると、ここに入力項目が表示されます。").classes("text-body2")
                            else:
                                # local shortcuts
                                data = p["data"]
                                step1 = data["step1"]
                                step2 = data["step2"]
                                blocks = data["blocks"]

                                def sync_project_state_only() -> bool:
                                    # Step1の分岐（テンプレID）を常に同期
                                    before_tpl = step1.get("_applied_template_id") or step1.get("template_id") or ""
                                    step1["template_id"] = resolve_template_id(step1)
                                    set_current_project(p, u)
                                    after_tpl = step1.get("_applied_template_id") or step1.get("template_id") or ""
                                    return after_tpl != before_tpl

                                def refresh_block_editor_if_structure_changed(structure_changed: bool) -> None:
                                    if not structure_changed:
                                        return
                                    try:
                                        editor_ref["refresh"]()
                                    except Exception:
                                        pass
                                    restore_builder_view_state(50)

                                def schedule_preview_refresh(*, force: bool = False) -> None:
                                    refresh_preview(force=force)

                                def schedule_visible_side_panels_refresh(*, force: bool = False) -> None:
                                    refresh_approval_panel(force=force)
                                    refresh_publish_panel(force=force)

                                def update_and_refresh(*, structure_changed: bool = False, force_preview: bool = False, delta_preview_key: str = "") -> None:
                                    template_changed = sync_project_state_only()
                                    structure_now = bool(structure_changed or template_changed)
                                    capture_builder_view_state(include_focus=not structure_now)
                                    refresh_block_editor_if_structure_changed(structure_now)
                                    preview_updated = False
                                    if (not structure_now) and (not force_preview) and delta_preview_key == "theme":
                                        preview_updated = apply_preview_theme_delta()
                                    if not preview_updated:
                                        schedule_preview_refresh(force=force_preview)
                                    schedule_visible_side_panels_refresh(force=force_preview)

                                async def force_preview_refresh_and_save() -> None:
                                    update_and_refresh(force_preview=True)
                                    await save_now()

                                def bind_step2_input(label: str, key: str, hint: str = "") -> None:
                                    val = step2.get(key, "")
                                    def _on_change(e):
                                        next_value = e.value or ""
                                        if str(step2.get(key) or "") == str(next_value):
                                            return
                                        step2[key] = next_value
                                        update_and_refresh()
                                    inp = ui.input(label, value=val, on_change=_on_change).props("outlined dense").classes("w-full q-mb-sm")
                                    if hint:
                                        inp.props(f"hint={hint}")

                                def update_block(block_key: str, field: str, value) -> None:
                                    b = blocks.setdefault(block_key, {})
                                    if b.get(field) == value:
                                        return
                                    b[field] = value
                                    update_and_refresh()

                                def bind_block_input(block_key: str, label: str, field: str, *, textarea: bool = False, hint: str = "") -> None:
                                    b = blocks.setdefault(block_key, {})
                                    val = b.get(field, "")
                                    def _on_change(e):
                                        next_value = e.value or ""
                                        if b.get(field, "") == next_value:
                                            return
                                        update_block(block_key, field, next_value)
                                    props = "outlined"
                                    if textarea:
                                        props += " type=textarea autogrow"
                                    inp = ui.input(label, value=val, on_change=_on_change).props(props).classes("w-full q-mb-sm")
                                    if hint:
                                        inp.props(f"hint={hint}")

                                def bind_dict_input(target: dict, label: str, field: str, *, textarea: bool = False, hint: str = "") -> None:
                                    """Bind ui.input directly to a dict field (used for nested blocks like philosophy/services)."""
                                    if not isinstance(target, dict):
                                        return
                                    val = target.get(field, "")

                                    def _on_change(e):
                                        next_value = e.value or ""
                                        try:
                                            if target.get(field, "") == next_value:
                                                return
                                            target[field] = next_value
                                        except Exception:
                                            pass
                                        update_and_refresh()

                                    props = "outlined"
                                    if textarea:
                                        props += " type=textarea autogrow"
                                    inp = ui.input(label, value=val, on_change=_on_change).props(props).classes("w-full q-mb-sm")
                                    if hint:
                                        inp.props(f"hint={hint}")

