def render_loading_visual(*, compact: bool = False) -> None:
    """ローディング中に小さなビルダーが組み上がるような見た目を出す。"""
    size_class = "is-compact" if compact else ""
    icon = html.escape(PAGEFLOW_BUILDER_ICON_DATA_URL, quote=True)
    ui.html(
        f"""
<div class="cvhb-loader-scene {size_class}" aria-hidden="true">
  <div class="cvhb-loader-glow"></div>
  <div class="cvhb-loader-orbit"></div>
  <div class="cvhb-loader-orbit cvhb-loader-orbit-secondary"></div>
  <div class="cvhb-loader-stage">
    <span class="cvhb-loader-card-mini cvhb-loader-card-a"></span>
    <span class="cvhb-loader-card-mini cvhb-loader-card-b"></span>
    <span class="cvhb-loader-card-mini cvhb-loader-card-c"></span>
    <span class="cvhb-loader-core"><img class="cvhb-loader-logo" src="{icon}" alt=""></span>
  </div>
  <div class="cvhb-loader-dots"><span></span><span></span><span></span></div>
  <div class="cvhb-loader-bar"><span></span></div>
</div>
"""
    )




def render_startup_shell_skeleton(*, title: str, detail: str) -> None:
    """cold open 時の初期表示を軽くするための最小 skeleton。"""
    with ui.column().classes("w-full items-center justify-center text-center q-pa-lg").style("min-height: 72vh;"):
        with ui.card().classes("q-pa-lg rounded-borders cvhb-surface-card").style("width:min(980px, 96vw);").props("bordered"):
            with ui.column().classes("w-full q-gutter-md"):
                ui.html(_startup_brand_panel_html("""必要なデータだけ先に読み込みます。
Builder 本体は shell を先に出し、重い描画は後ろへ回します。"""))
                with ui.row().classes("w-full items-stretch").style("gap:14px; flex-wrap:wrap;"):
                    with ui.element("div").style("flex:1 1 320px; min-width:280px; display:grid; gap:12px;"):
                        for h in ("48px", "180px", "160px"):
                            ui.element("div").style(
                                f"height:{h}; border-radius:16px; border:1px solid rgba(15,23,42,0.08);"
                                "background:linear-gradient(180deg, rgba(248,250,252,0.96), rgba(241,245,249,0.92));"
                            )
                    with ui.element("div").style("flex:1.4 1 420px; min-width:320px; display:grid; gap:12px;"):
                        ui.element("div").style(
                            "height:48px; border-radius:16px; border:1px solid rgba(15,23,42,0.08);"
                            "background:linear-gradient(180deg, rgba(248,250,252,0.96), rgba(241,245,249,0.92));"
                        )
                        ui.element("div").style(
                            "height:420px; border-radius:22px; border:1px solid rgba(15,23,42,0.08);"
                            "background:linear-gradient(180deg, rgba(255,255,255,0.98), rgba(241,245,249,0.92));"
                        )
                ui.label(title).classes("w-full text-subtitle1 text-center")
                ui.label(detail).classes("w-full cvhb-muted text-center")

@ui.page("/help")
def help_page():
    """HELP_MODE専用: ローカルでヘルプ（手順書）を作るためのページ。"""
    inject_global_styles()
    cleanup_user_storage()
    sync_builder_shell(False)
    ui.page_title(f"HELP MODE | {PRODUCT_NAME}")

    if not HELP_MODE:
        navigate_to("/")
        return

    u = current_user() or User(id=0, username="help_admin", role="admin")
    render_header(u)

    # サンプル案件を確実に用意
    try:
        _help_seed_sample_projects(u)
    except Exception:
        pass

    with ui.element("div").classes("cvhb-container"):
        with ui.card().classes("q-pa-md rounded-borders cvhb-empty-card cvhb-surface-card").props("bordered"):
            ui.label("HELP MODE（ローカル専用）").classes("text-h5")
            ui.label("DB/SFTPに触らず、画面のスクショを撮ってヘルプを作るためのモードです。").classes("cvhb-muted q-mt-sm")

            ui.separator().classes("q-my-md")

            ui.label("まずやること（超ざっくり）").classes("text-subtitle1")
            ui.markdown(
                """- **案件** → サンプル案件を開く（企業/福祉/飲食）  
- 左で編集 → 右でプレビュー確認  
- 必要な画面をスクショして、手順書に貼る  
"""
            )

            ui.separator().classes("q-my-md")

            ui.label("サンプル案件を開く").classes("text-subtitle1")
            items = []
            try:
                items = list_projects_from_sftp()
            except Exception:
                items = []

            async def _open(pid: str) -> None:
                try:
                    p = await asyncio.to_thread(load_project_from_sftp, pid, u)
                    set_current_project(p, u)
                    ui.notify("サンプル案件を開きました", type="positive")
                    navigate_to("/")
                except Exception as e:
                    ui.notify(f"開けませんでした: {sanitize_error_text(e)}", type="negative")

            if not items:
                ui.label("サンプル案件が見つかりません").classes("text-negative")
            else:
                for it in items:
                    pid = str(it.get("project_id") or "")
                    name = str(it.get("project_name") or "")
                    async def _open_one(project_id=pid):
                        await _open(project_id)

                    with ui.row().classes("items-center justify-between w-full q-mb-xs"):
                        ui.label(name).classes("text-body1")
                        ui.button("開く", on_click=_open_one).props("color=primary unelevated")

            ui.separator().classes("q-my-md")

            ui.label("提案メモの型（コピペ用）").classes("text-subtitle1")
            ui.markdown(
                """**迷ったらこの順番で書く**（短くてOK）  
1) 目的：誰に、何が伝わればOK？  
2) 変更：どこを、どう変える？  
3) 理由：なぜ良くなる？（1行でOK）  
4) 確認：お客様に確認が必要なこと（写真・住所・公開可否など）  
"""
            )

            with ui.row().classes("q-gutter-sm q-mt-md"):
                ui.button("案件一覧へ", on_click=lambda: navigate_to("/projects")).props("flat")
                ui.button(f"{BUILDER_NAME}へ", on_click=lambda: navigate_to("/")).props("color=primary flat")



