def assign_project_company(project_id: str, company_id: int, actor: User) -> dict:
    if not is_platform_admin(actor):
        raise PermissionError("A管理者のみ会社の割当を変更できます")
    cid = _normalize_int_optional(company_id)
    if not cid:
        raise ValueError("会社を選択してください")
    company_row = get_company_by_id(cid)
    if not company_row:
        raise ValueError("会社が見つかりません")
    project_obj = _load_project_from_sftp_v173(project_id, None)
    old_company_id = _project_owner_company_id(project_obj)
    project_obj = _bind_project_to_company(project_obj, company_row, clear_assignments=(old_company_id != cid))
    save_project_to_sftp(project_obj, actor)
    safe_log_action(actor, "project_company_bind", json.dumps({"project_id": project_id, "company_id": cid}, ensure_ascii=False))
    return project_obj


def set_project_assigned_users(project_id: str, user_ids: list[int], actor: User) -> dict:
    project_obj = load_project_from_sftp(project_id, actor)
    if not _project_assignment_change_allowed(actor, project_obj):
        raise PermissionError("担当者の紐づけ変更は管理者のみです")
    company_id = _project_owner_company_id(project_obj)
    if not company_id:
        raise ValueError("先に案件の所属会社を設定してください")
    valid_rows = []
    for uid in _normalize_int_list(user_ids):
        row = get_user_row_by_id(uid)
        if not row:
            continue
        if _normalize_int_optional(row.get("company_id")) != company_id:
            continue
        if str(row.get("role") or "") != "user":
            continue
        if not bool(row.get("is_active", True)):
            continue
        valid_rows.append(row)
    project_obj["assigned_user_ids"] = [int(r.get("id") or 0) for r in valid_rows]
    project_obj["assigned_usernames"] = [str(r.get("username") or "") for r in valid_rows]
    project_obj["assigned_user_display_names"] = [_user_display_name_from_row(r) for r in valid_rows]
    save_project_to_sftp(project_obj, actor)
    safe_log_action(actor, "project_assignment_update", json.dumps({"project_id": project_id, "assigned_user_ids": project_obj.get("assigned_user_ids", [])}, ensure_ascii=False))
    return project_obj


def save_project_management_settings(
    project_id: str,
    *,
    actor: User,
    owner_company_id: Optional[int] = None,
    assigned_user_ids: Optional[list[int]] = None,
    client_name: str = "",
    delivery_mode: str = DELIVERY_MODE_ZIP,
    maintenance_included: Optional[bool] = None,
) -> dict:
    pid = str(project_id or "").strip()
    if not pid:
        raise ValueError("案件を選択してください")
    project_obj = _load_project_from_sftp_v173(pid, None if is_platform_admin(actor) else actor)
    project_obj = normalize_project(project_obj)
    if not user_can_manage_project_settings(actor, project_obj):
        raise PermissionError("案件設定を変更できるのはA管理者または所属B会社の管理者のみです")

    if is_platform_admin(actor):
        cid = _normalize_int_optional(owner_company_id) or _project_owner_company_id(project_obj)
        if not cid:
            raise ValueError("所属会社を選択してください")
    else:
        cid = _normalize_int_optional(getattr(actor, "company_id", None))
        if not cid:
            raise PermissionError("所属会社が設定されていません")

    company_row = get_company_by_id(cid)
    if not company_row:
        raise ValueError("所属会社が見つかりません")
    if str(company_row.get("status") or COMPANY_STATUS_ACTIVE).strip().lower() != COMPANY_STATUS_ACTIVE:
        raise ValueError("停止中の会社には案件を紐づけできません")

    old_company_id = _project_owner_company_id(project_obj)
    project_obj = _bind_project_to_company(project_obj, company_row, clear_assignments=(old_company_id != cid))

    if assigned_user_ids is not None:
        valid_rows = []
        for uid in _normalize_int_list(assigned_user_ids):
            row = get_user_row_by_id(uid)
            if not row:
                continue
            if _normalize_int_optional(row.get("company_id")) != cid:
                continue
            if str(row.get("role") or "") != "user":
                continue
            if not bool(row.get("is_active", True)):
                continue
            valid_rows.append(row)
        project_obj["assigned_user_ids"] = [int(r.get("id") or 0) for r in valid_rows]
        project_obj["assigned_usernames"] = [str(r.get("username") or "") for r in valid_rows]
        project_obj["assigned_user_display_names"] = [_user_display_name_from_row(r) for r in valid_rows]
    else:
        _sync_project_scope_from_db(project_obj)

    project_obj["client_name"] = str(client_name or "").strip()
    dm = str(delivery_mode or DELIVERY_MODE_ZIP).strip().lower()
    if dm not in {DELIVERY_MODE_ZIP, DELIVERY_MODE_MANAGED_UPDATE}:
        dm = DELIVERY_MODE_ZIP
    project_obj["delivery_mode"] = dm
    maint = bool(maintenance_included) if maintenance_included is not None else bool(project_obj.get("maintenance_included"))
    if dm == DELIVERY_MODE_MANAGED_UPDATE:
        maint = True
    project_obj["maintenance_included"] = maint
    project_obj = normalize_project(project_obj)
    save_project_to_sftp(project_obj, actor)
    safe_log_action(
        actor,
        "project_settings_update",
        json.dumps(
            {
                "project_id": pid,
                "owner_company_id": _project_owner_company_id(project_obj),
                "assigned_user_ids": _project_assigned_user_ids(project_obj),
                "client_name": project_obj.get("client_name") or "",
                "delivery_mode": project_obj.get("delivery_mode") or DELIVERY_MODE_ZIP,
                "maintenance_included": bool(project_obj.get("maintenance_included")),
            },
            ensure_ascii=False,
        ),
    )
    return project_obj


def company_summary_rows(actor: User) -> list[dict]:
    try:
        companies = list_companies(include_stopped=True) if is_platform_admin(actor) else ([get_company_by_id(actor.company_id)] if actor.company_id else [])
    except Exception:
        companies = []
    try:
        users_all = db_fetchall(_user_lookup_sql_base() + " ORDER BY u.id ASC", None) if is_platform_admin(actor) else list_company_users(actor.company_id or 0, include_inactive=True)
    except Exception:
        users_all = []
    try:
        projects_all = list_projects_from_sftp(actor)
    except Exception:
        projects_all = []
    out: list[dict] = []
    for company in companies:
        if not isinstance(company, dict):
            continue
        cid = _normalize_int_optional(company.get("id"))
        company_users = [row for row in users_all if _normalize_int_optional(row.get("company_id")) == cid]
        admin_rows = [row for row in company_users if str(row.get("role") or "").strip() == "admin"]
        subadmin_rows = [row for row in company_users if str(row.get("role") or "").strip() == "subadmin"]
        member_rows = [row for row in company_users if str(row.get("role") or "").strip() == "user"]
        project_count = 0
        for item in projects_all:
            if _normalize_int_optional(item.get("owner_company_id")) == cid:
                project_count += 1
        primary_admin = admin_rows[0] if admin_rows else None
        out.append({
            "company_id": cid,
            "company_name": str(company.get("company_name") or ""),
            "company_code": str(company.get("company_code") or ""),
            "status": str(company.get("status") or COMPANY_STATUS_ACTIVE),
            "user_count": len(company_users),
            "subadmin_count": len(subadmin_rows),
            "member_count": len(member_rows),
            "project_count": project_count,
            "primary_admin_display": _user_display_name_from_row(primary_admin) if primary_admin else "未発行",
            "primary_admin_username": str(primary_admin.get("username") or "") if isinstance(primary_admin, dict) else "",
        })
    return out


def _tenant_scope_company_options(actor: User) -> dict:
    if HELP_MODE or not _tenant_admin_db_ready():
        return {}
    cached = _tenant_scope_company_options_cache_get(actor)
    if isinstance(cached, dict):
        return cached
    if is_platform_admin(actor):
        try:
            rows = list_companies(include_stopped=True)
        except Exception:
            rows = []
        admin_map: dict[int, str] = {}
        try:
            admin_rows = db_fetchall(_user_lookup_sql_base() + " WHERE u.role = 'admin' ORDER BY u.company_id ASC, u.id ASC", None)
        except Exception:
            admin_rows = []
        for row in admin_rows:
            cid = _normalize_int_optional(row.get("company_id"))
            if cid and cid not in admin_map:
                admin_map[cid] = _user_display_name_from_row(row) or str(row.get("username") or "")
        options = {
            str(r.get("id")): f"{r.get('company_name')} ({r.get('company_code')}) / B管理者:{admin_map.get(_normalize_int_optional(r.get('id')) or 0, '未発行')} / {_company_status_label(r.get('status'))}"
            for r in rows if isinstance(r, dict)
        }
        _tenant_scope_company_options_cache_put(actor, options)
        return options
    if _normalize_int_optional(actor.company_id):
        options = {str(actor.company_id): str(actor.company_name or "")}
        _tenant_scope_company_options_cache_put(actor, options)
        return options
    return {}


def _tenant_scope_project_options(actor: User, company_id: Optional[int] = None) -> dict:
    company_id = _normalize_int_optional(company_id)
    try:
        items = list_projects_from_sftp(actor)
    except Exception:
        items = []
    if is_platform_admin(actor):
        if company_id:
            filtered = []
            for it in items:
                owner_company_id = _normalize_int_optional(it.get("owner_company_id"))
                if owner_company_id == company_id or (not owner_company_id):
                    filtered.append(it)
            items = filtered
    options = {}
    for it in items:
        pid = str(it.get("project_id") or "")
        if not pid:
            continue
        company_label = str(it.get("owner_company_name") or "未設定")
        client_label = str(it.get("client_name") or "").strip()
        assigned = _normalize_str_list(it.get("assigned_user_display_names") or it.get("assigned_usernames"))
        assignee_text = ", ".join(assigned[:3]) + ("…" if len(assigned) > 3 else "") if assigned else "未割当"
        label = f"{it.get('project_name') or pid} / 所属:{company_label}"
        if client_label:
            label += f" / C:{client_label}"
        label += f" / 担当:{assignee_text}"
        options[pid] = label
    return options


def render_header(u: Optional[User]) -> None:
    with ui.element("div").classes("w-full cvhb-appbar"):
        with ui.row().classes("w-full items-center justify-between cvhb-appbar-inner"):
            with ui.row().classes("items-center no-wrap cvhb-brand-lockup"):
                ui.html(_header_brand_html())

            with ui.row().classes("items-center cvhb-chip-row"):
                ui.badge(APP_ENV.upper()).props("outline")
                if stg_auto_admin_enabled():
                    ui.badge("STG自動admin（ログインなし）").props("outline")
                if HELP_MODE:
                    ui.badge("HELP_MODE（オフライン）").props("outline")
                else:
                    ui.badge(f"SFTP_BASE_DIR: {SFTP_BASE_DIR}").props("outline")

                if u:
                    company_badge = _company_badge_text(u)
                    if company_badge:
                        ui.badge(company_badge).props("outline")

                pname = app.storage.user.get("current_project_name")
                if pname:
                    ui.badge(f"案件: {str(pname)[:18]}").props("outline")

                if u:
                    display_name = _user_to_display_name(u)
                    ui.badge(f"{display_name} ({user_role_scope_label(u)})").props("outline")
                    ui.button("案件", on_click=lambda: navigate_to("/projects")).props("flat no-caps").classes("cvhb-header-btn")
                    if user_requires_password_change(u):
                        ui.badge("初回PW変更").props("outline color=negative")
                    if (not HELP_MODE) and can_manage_users(u):
                        ui.button("組織・担当者管理", on_click=lambda: navigate_to(TENANT_ADMIN_PAGE_PATH)).props("flat no-caps").classes("cvhb-header-btn")
                    if not HELP_MODE:
                        ui.button("アカウント / パスワード", on_click=lambda: navigate_to(ACCOUNT_PAGE_PATH)).props("flat no-caps").classes("cvhb-header-btn")

                    help_dialog = create_inapp_help_dialog()
                    ui.button("ヘルプ", icon="help_outline", on_click=help_dialog.open).props("flat no-caps").classes("cvhb-header-btn")

                    if HELP_MODE:
                        ui.button("ヘルプ（ページ）", on_click=lambda: navigate_to("/help")).props("flat no-caps").classes("cvhb-header-btn")
                    if can_view_audit_logs(u):
                        ui.button("操作ログ", on_click=lambda: navigate_to("/audit")).props("flat no-caps").classes("cvhb-header-btn")
                    ui.button("ログアウト", on_click=logout).props("color=negative flat no-caps").classes("cvhb-header-btn")


